/* AUTO-GENERATED — North Dakota Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["ND"] = {"code":"ND","name":"North Dakota","agency":"North Dakota NDDOT","agencyShort":"NDDOT","handbook":"https://www.dot.nd.gov/driver/commercial/commercial-driver-license-manual","links":{},"en":[{"q":"On North Dakota highways, what is the maximum legal total outside width of a vehicle and its load?","options":["8 feet 6 inches","8 feet","9 feet","10 feet"],"answer":0,"explanation":"North Dakota limits total outside vehicle width, including load, to 8 feet 6 inches on all highways (NDCC 39-12-04; NDHP Motor Carrier Operations Legal Size and Weight Guide, Ref 9-1, Sec. A). A load wider than this requires a permit.","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle, loaded or unloaded, on North Dakota highways?","options":["13 feet 6 inches","14 feet","13 feet","15 feet"],"answer":1,"explanation":"North Dakota sets the maximum legal vehicle height at 14 feet, whether loaded or unloaded, but the driver must still ensure clearance under bridges and underpasses lower than 14 feet (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. B).","handbook":"","hbref":""},{"q":"In North Dakota, what is the maximum length of a trailer or semitrailer, including its load (for units registered after July 1, 1987)?","options":["48 feet","53 feet","57 feet","60 feet"],"answer":1,"explanation":"A trailer or semitrailer, including the load, may not exceed 53 feet in North Dakota; trailers/semitrailers titled and registered in the state before July 1, 1987, and towed vehicles may reach 60 feet (NDCC 39-12-04; NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.4).","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight allowed on the Interstate highway system in North Dakota?","options":["85,500 pounds","90,000 pounds","80,000 pounds","105,500 pounds"],"answer":2,"explanation":"The maximum gross vehicle weight on the Interstate highway system in North Dakota is 80,000 pounds (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.b), consistent with the federal Interstate limit.","handbook":"","hbref":""},{"q":"In North Dakota, no single axle may carry a gross weight in excess of how many pounds?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"answer":1,"explanation":"North Dakota limits a single axle to a maximum gross weight of 20,000 pounds (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.b). Axles spaced 40 inches or less apart count as one axle.","handbook":"","hbref":""},{"q":"What is the maximum gross weight North Dakota allows on a tandem axle?","options":["32,000 pounds","36,000 pounds","40,000 pounds","34,000 pounds"],"answer":3,"explanation":"In North Dakota the gross weight of a tandem axle may not exceed 34,000 pounds (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.c), matching the federal tandem-axle limit.","handbook":"","hbref":""},{"q":"What is the maximum length of a single-unit vehicle with two or more axles, including its load, in North Dakota?","options":["40 feet","45 feet","50 feet","53 feet"],"answer":2,"explanation":"A single-unit vehicle with two or more axles, including the load, may not exceed 50 feet in North Dakota (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.1).","handbook":"","hbref":""},{"q":"On North Dakota highways OTHER than the Interstate system, what is the maximum gross weight permitted for two individual axles spaced 8 feet or more apart?","options":["34,000 pounds","36,000 pounds","40,000 pounds","44,000 pounds"],"answer":2,"explanation":"On highways other than the Interstate system, the combined gross weight of two individual axles spaced 8 feet or more apart may not exceed 40,000 pounds in North Dakota (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.b).","handbook":"","hbref":""},{"q":"On non-designated highways in North Dakota, what is the maximum length of a combination of two, three, or four units, including the load?","options":["65 feet","70 feet","75 feet","85 feet"],"answer":2,"explanation":"A combination of two, three, or four units, including the load, may not exceed 75 feet on non-designated North Dakota highways; on NDDOT-designated four-lane divided highways such combinations may reach 95 or 110 feet (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.2 and C.3).","handbook":"","hbref":""},{"q":"On North Dakota state highways (other than the Interstate), the maximum gross vehicle weight is generally 80,000 pounds unless the route is designated for more, not to exceed what ceiling?","options":["100,000 pounds","105,500 pounds","110,000 pounds","129,000 pounds"],"answer":1,"explanation":"On non-Interstate North Dakota highways the maximum gross vehicle weight is 80,000 pounds unless the highway is designated for more, in which case it may not exceed 105,500 pounds (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.2.a).","handbook":"","hbref":""},{"q":"Under the federal bridge formula as applied in North Dakota, two consecutive sets of tandem axles may each carry 34,000 pounds provided the distance between the first and last axles of those tandem sets is at least how many feet?","options":["30 feet","34 feet","36 feet","40 feet"],"answer":2,"explanation":"North Dakota applies the bridge formula W = 500(LN/(N-1) + 12N + 36), but two consecutive sets of tandem axles may carry 34,000 pounds each if the overall distance between the first and last axles of those sets is at least 36 feet (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.a).","handbook":"","hbref":""},{"q":"In North Dakota's bridge formula W = 500(LN/(N-1) + 12N + 36), what does the letter N represent?","options":["The number of axles in the group","The distance between axle extremes","The net weight of the load","The maximum weight in pounds"],"answer":0,"explanation":"In North Dakota's bridge formula, W is the maximum weight on a group of axles, L is the distance in feet between the extremes of the group, and N is the number of axles in the group (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.a).","handbook":"","hbref":""},{"q":"On highways other than the Interstate system in North Dakota, what is the maximum gross weight allowed on a grouping of three or more axles?","options":["42,000 pounds","51,000 pounds","54,000 pounds","48,000 pounds"],"answer":3,"explanation":"On North Dakota highways other than the Interstate system, the gross weight of a grouping of three or more axles may not exceed 48,000 pounds; on the Interstate the group is governed by the bridge formula (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.c).","handbook":"","hbref":""},{"q":"When is a single-trip oversize/overweight permit required in North Dakota?","options":["For any commercial vehicle carrying hazardous materials","Only for loads traveling on the Interstate after dark","For a non-reducible load that exceeds North Dakota legal size and/or weight limits","For any vehicle weighing more than 26,001 pounds"],"answer":2,"explanation":"North Dakota requires a single-trip oversize/overweight permit for a non-reducible oversize and/or overweight load movement that exceeds the state's legal vehicle size and weight limits (NDHP Oversize/Overweight Permit, e-permits).","handbook":"","hbref":""},{"q":"How long is a North Dakota single-trip oversize/overweight permit valid for one load movement?","options":["Up to 24 hours","Up to 3 days","Up to 5 days","Up to 7 days"],"answer":2,"explanation":"A North Dakota single-trip oversize/overweight permit is valid for one load movement for up to 5 days (NDHP Oversize/Overweight Permit, e-permits system at nd.gov/ndhp).","handbook":"","hbref":""},{"q":"North Dakota's harvest weight exemption permit allows a vehicle hauling a harvested farm product from the field to the first point of storage or sale to carry how much additional weight?","options":["5 percent more weight","10 percent more weight","15 percent more weight","20 percent more weight"],"answer":1,"explanation":"North Dakota's harvest weight exemption permit allows 10% more weight when hauling a harvested product from the field to the initial point of storage or first point of sale, valid July 15 through November 30, and gross weight may not exceed 105,500 pounds (NDHP e-permits, Harvest Weight Exemption Permit).","handbook":"","hbref":""},{"q":"During what date range is North Dakota's harvest weight exemption permit valid?","options":["May 1 - September 30","June 1 - October 31","July 15 - November 30","August 1 - December 31"],"answer":2,"explanation":"North Dakota's harvest weight exemption permit is valid between July 15 and November 30 for hauling harvested products from the field to the initial point of storage or first sale (NDHP e-permits, Harvest Weight Exemption Permit).","handbook":"","hbref":""},{"q":"In North Dakota, an implement of husbandry being moved by a resident farmer between sunrise and sunset (not on the Interstate) may exceed the normal 14-foot height limit up to what maximum height?","options":["14 feet 6 inches","15 feet","15 feet 6 inches","16 feet"],"answer":2,"explanation":"North Dakota allows implements of husbandry to reach 15 feet 6 inches in height when moved by resident farmers, ranchers, dealers, or manufacturers between sunrise and sunset, for a distance not exceeding 60 miles and not on the Interstate (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. B.2.a).","handbook":"","hbref":""},{"q":"A North Dakota vehicle powered primarily by natural gas may exceed the gross weight limit by how much, up to what maximum?","options":["Up to 1,000 pounds, max 81,000 pounds","Up to 2,000 pounds, max 82,000 pounds","Up to 2,500 pounds, max 82,500 pounds","Up to 4,000 pounds, max 84,000 pounds"],"answer":1,"explanation":"A North Dakota vehicle operated by an engine fueled primarily by natural gas may exceed the weight limit by up to 2,000 pounds, to a maximum gross weight of 82,000 pounds, to account for the heavier fuel system (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.8).","handbook":"","hbref":""},{"q":"In North Dakota, the steering axle weight is set by the manufacturer's axle rating but may not exceed how many pounds when traveling on the Interstate system?","options":["12,000 pounds","18,000 pounds","20,000 pounds","24,000 pounds"],"answer":2,"explanation":"North Dakota limits the steering axle to the manufacturer's axle rating, not to exceed 20,000 pounds on the Interstate system, and no tire may exceed 550 pounds per inch of tire width (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.a).","handbook":"","hbref":""},{"q":"In North Dakota, which CDL class is required to operate any combination of vehicles with a gross combination weight rating (GCWR) of 26,001 pounds or more, provided the vehicle(s) being towed have a GVWR over 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"North Dakota's CDL Class A (combination vehicle) covers any combination of vehicles with a GCWR of 26,001 lbs or more when the towed unit's GVWR exceeds 10,000 lbs. Source: NDDOT Commercial Driver License page and ND CDL Manual; 49 CFR 383.91.","handbook":"","hbref":""},{"q":"Under North Dakota rules, a Class B CDL authorizes a driver to operate which of the following?","options":["Any single vehicle with a GVWR of 26,001 lbs or more, towing a unit not over 10,000 lbs GVWR","Any combination of vehicles over 26,001 lbs GCWR with a towed unit over 10,000 lbs","Only vehicles designed to carry 16 or more passengers","Only vehicles under 26,001 lbs GVWR carrying placarded hazardous materials"],"answer":0,"explanation":"ND Class B (heavy straight vehicle) covers any single vehicle with a GVWR of 26,001 lbs or more, or such a vehicle towing a unit not exceeding 10,000 lbs GVWR. Source: NDDOT Commercial Driver License page and ND CDL Manual; 49 CFR 383.91.","handbook":"","hbref":""},{"q":"A North Dakota driver operates a single vehicle rated under 26,001 lbs GVWR that is designed to transport 16 or more passengers (including the driver). Which CDL class applies?","options":["Class C","Class A","Class B","No CDL is required"],"answer":0,"explanation":"ND Class C (small vehicle) applies to single vehicles under 26,001 lbs GVWR that are designed to carry 16 or more passengers (including the driver) or that carry hazardous materials requiring placards. Source: NDDOT Commercial Driver License page and ND CDL Manual; 49 CFR 383.91.","handbook":"","hbref":""},{"q":"Which North Dakota CDL endorsement is required to operate a tank vehicle used to haul a liquid or gas in a permanently mounted tank with an individual rated capacity of more than 119 gallons (and an aggregate of 1,000 gallons or more)?","options":["N (Tank Vehicles)","H (Hazardous Materials)","T (Doubles/Triples)","P (Passenger)"],"answer":0,"explanation":"The N endorsement is required in ND to haul liquids or gases in a tank rated over 119 gallons individually or 1,000 gallons or more in aggregate. Source: NDDOT Commercial Driver License page; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"In North Dakota, which endorsement must a CDL holder obtain to pull double or triple trailers?","options":["T (Doubles/Triples)","N (Tank Vehicles)","X (Tank/HazMat combination)","P (Passenger)"],"answer":0,"explanation":"The T endorsement authorizes towing double or triple trailers in North Dakota and is obtained by passing the doubles/triples knowledge test. Source: NDDOT Commercial Driver License page and ND CDL Manual; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a North Dakota CDL valid only for INTRASTATE driving (within North Dakota)?","options":["18 years old","16 years old","19 years old","21 years old"],"answer":0,"explanation":"North Dakota allows a CDL for intrastate-only driving at age 18. Drivers must be 21 to operate in interstate commerce. Source: NDDOT CDL requirements; NDCC Title 39; 49 CFR 383.","handbook":"","hbref":""},{"q":"A North Dakota CDL applicant who wants to drive in interstate commerce, transport hazardous materials, or transport passengers for hire must be at least what age?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"North Dakota requires a driver to be at least 21 to operate across state lines (interstate), to carry hazardous materials, or to transport passengers for hire. Source: NDDOT CDL requirements; 49 CFR 383.","handbook":"","hbref":""},{"q":"After being issued a North Dakota Commercial Learner's Permit (CLP), how long must an applicant wait before being eligible to take the CDL skills (road) test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"North Dakota follows the federal rule requiring a CLP to be held for at least 14 days before the applicant may take the CDL skills test. Source: NDDOT CDL application page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Before obtaining a Hazardous Materials (H) endorsement in North Dakota, an applicant must pass which federally required background screening?","options":["A TSA security threat assessment, including fingerprinting","An FBI-only criminal history check with no fingerprints","A state-administered polygraph examination","An employer-conducted reference check only"],"answer":0,"explanation":"ND H-endorsement applicants must complete the TSA security threat assessment, which includes submitting fingerprints, before the endorsement can be added. Source: NDDOT Hazardous Material Requirements page; 49 CFR 1572 / TSA.","handbook":"","hbref":""},{"q":"Which entry-level training step is now required before a North Dakota applicant can take the knowledge test for a NEW Hazardous Materials (H) endorsement?","options":["Federal ELDT hazmat theory training from a provider on the FMCSA Training Provider Registry","A 40-hour in-cab tanker apprenticeship","A North Dakota state-run hazmat academy course","No training is required, only the knowledge test"],"answer":0,"explanation":"Initial H-endorsement applicants in ND must complete the federally required hazmat theory Entry-Level Driver Training (ELDT) from a provider listed on the FMCSA Training Provider Registry before the knowledge test. Source: NDDOT Hazardous Material Requirements page; 49 CFR 380.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) required before getting a first North Dakota Class A CDL must be completed through which system?","options":["A provider listed on the FMCSA Training Provider Registry","Any North Dakota community college, with no federal listing","The NDDOT's internal driver academy","Any out-of-state trucking employer of the driver's choice"],"answer":0,"explanation":"ND requires ELDT to be completed through a school or entity listed on the FMCSA Training Provider Registry before the skills test for an initial Class A CDL. Source: NDDOT How to Apply for a CDL page; 49 CFR 380 Subpart F.","handbook":"","hbref":""},{"q":"Which endorsement does a North Dakota driver need to operate a vehicle (other than a school bus) designed to transport 16 or more people including the driver?","options":["P (Passenger)","S (School Bus)","N (Tank)","T (Doubles/Triples)"],"answer":0,"explanation":"The P (Passenger) endorsement is required to operate a bus or other vehicle designed to carry 16 or more people including the driver. A school bus also requires the separate S endorsement. Source: ND CDL Manual; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"To add a School Bus (S) endorsement to a North Dakota CDL, which endorsement must the driver ALSO hold?","options":["P (Passenger)","N (Tank)","H (Hazardous Materials)","T (Doubles/Triples)"],"answer":0,"explanation":"In North Dakota the S (School Bus) endorsement requires the driver to first hold the P (Passenger) endorsement, plus pass the school bus knowledge and skills tests. Source: ND CDL Manual; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"When applying for a North Dakota CDL, an applicant must provide proof of a Social Security number. Which of these is an acceptable document?","options":["The original Social Security card","A photocopy of the Social Security card","A handwritten note listing the SSN","A library card showing the number"],"answer":0,"explanation":"ND requires proof of the Social Security number, such as the original Social Security card; photocopies are not accepted and documents must be original or certified. Source: NDDOT Driver License Requirements / REAL ID checklist.","handbook":"","hbref":""},{"q":"How many proof-of-residence documents does North Dakota require an applicant to present to establish their North Dakota residential address?","options":["Two documents","One document","Three documents","No residency proof is required"],"answer":0,"explanation":"North Dakota requires two documents proving the applicant's North Dakota residence address (e.g., utility/financial statements, tax records). Source: NDDOT Driver License Requirements / REAL ID checklist.","handbook":"","hbref":""},{"q":"Besides identity, Social Security number, and residency, what additional proof must a North Dakota CDL applicant provide?","options":["Proof of U.S. citizenship, lawful permanent residence, or legal/temporary presence","A notarized letter from a current employer","Proof of vehicle ownership","A high school diploma"],"answer":0,"explanation":"ND requires proof of citizenship, lawful permanent residence, or legal presence in the United States in addition to identity, SSN, and residency. Source: NDDOT Driver License Requirements page.","handbook":"","hbref":""},{"q":"A North Dakota CDL applicant who drives in interstate commerce and must carry a Medical Examiner's Certificate would self-certify under which category?","options":["Interstate, non-excepted (NI)","Interstate, excepted (EI)","Intrastate, non-excepted (NA)","Intrastate, excepted (EA)"],"answer":0,"explanation":"Drivers in interstate commerce who must meet federal physical-qualification standards self-certify as Interstate Non-Excepted and must keep a valid Medical Examiner's Certificate on file with ND. Source: NDDOT CDL self-certification; 49 CFR 383.71 / 391.","handbook":"","hbref":""},{"q":"How many medical self-certification categories must a North Dakota CDL holder choose from when certifying the type of commerce they operate in?","options":["Four (interstate non-excepted, interstate excepted, intrastate non-excepted, intrastate excepted)","Two (interstate and intrastate only)","Three (interstate, intrastate, and exempt)","Five (one per CDL endorsement)"],"answer":0,"explanation":"Federal rules adopted by ND require selecting one of four self-certification categories: interstate non-excepted, interstate excepted, intrastate non-excepted, or intrastate excepted. Source: NDDOT CDL self-certification; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Under the federal standard North Dakota follows, what is the maximum period a Commercial Learner's Permit (CLP) may be valid before it must be renewed (without retaking the knowledge tests)?","options":["180 days","30 days","12 months","5 years"],"answer":0,"explanation":"A CLP is valid for up to 180 days and may be renewed once for another 180 days within a one-year window without retesting; ND issues CLPs under this federal standard. Source: ND CDL Manual; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"A North Dakota CDL applicant must take the skills (road) test in what kind of vehicle?","options":["A representative vehicle of the class and type the applicant intends to drive","Any passenger car owned by the applicant","A vehicle provided by the NDDOT examiner","Only a Class A combination, regardless of license sought"],"answer":0,"explanation":"ND requires the skills test to be taken in a vehicle representative of the class and configuration (including endorsements such as school bus or tank) the applicant intends to operate. Source: NDDOT CDL application page; 49 CFR 383.71/383.113.","handbook":"","hbref":""},{"q":"In North Dakota, at what blood alcohol concentration (BAC) is a driver considered to be operating a commercial motor vehicle (CMV) under the influence and subject to disqualification?","options":["0.04 or higher","0.08 or higher","0.02 or higher","0.10 or higher"],"answer":0,"explanation":"North Dakota follows the federal standard: operating a CMV with a BAC of 0.04 or greater is an alcohol offense that disqualifies a CDL holder. This is half the 0.08 limit that applies to non-commercial driving. Source: NDDOT Commercial Driver License Manual (Disqualification); NDCC 39-06.2-10.1.","handbook":"","hbref":""},{"q":"Under North Dakota's implied-consent law, what happens to a CDL holder who refuses to submit to a chemical test for alcohol while operating a CMV?","options":["It is treated the same as a DUI conviction and disqualifies the driver","It results only in a warning for a first refusal","It carries a smaller penalty than a DUI conviction","It results in a 30-day suspension only"],"answer":0,"explanation":"Refusal to submit to chemical testing is treated, for CDL purposes, the same as an alcohol/DUI conviction. A first refusal disqualifies the driver for at least one year, the same as a first major offense. Source: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.1.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification period in North Dakota for a first major offense, such as a DUI in a CMV, when NOT transporting hazardous materials?","options":["1 year","60 days","6 months","3 years"],"answer":0,"explanation":"A first major offense (for example, operating a CMV with a BAC of 0.04 or more, DUI, or test refusal) disqualifies the driver for at least one year. Source: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In North Dakota, what is the minimum CDL disqualification for a first major offense committed while the CMV is transporting placarded hazardous materials?","options":["3 years","1 year","5 years","120 days"],"answer":0,"explanation":"If a first major offense is committed while operating a CMV that is placarded for hazardous materials, the disqualification increases from one year to at least three years. Source: NDDOT CDL Manual (Disqualification); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period in North Dakota for a second major offense (for example, a second DUI in a CMV)?","options":["Lifetime","10 years","3 years","5 years"],"answer":0,"explanation":"A second conviction for any major offense, in any combination, results in a lifetime CDL disqualification. Source: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A North Dakota CDL holder is convicted of using a vehicle to commit a felony involving the manufacturing or distribution of a controlled substance. What disqualification applies?","options":["Lifetime disqualification with no reinstatement","1-year disqualification","3-year disqualification","60-day disqualification"],"answer":0,"explanation":"Using a CMV to commit a felony involving manufacturing, distributing, or dispensing a controlled substance results in a lifetime disqualification that is not subject to reinstatement. Source: NDDOT CDL Manual (Disqualification); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period trigger a 60-day CDL disqualification in North Dakota?","options":["2 (the second within 3 years)","1 (the first violation)","3 (the third within 3 years)","4 (the fourth within 3 years)"],"answer":0,"explanation":"A second serious traffic violation within a 3-year period, arising from separate incidents, results in a disqualification of at least 60 days. Source: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.5; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In North Dakota, three serious traffic violations within a 3-year period result in a CDL disqualification of at least how long?","options":["120 days","60 days","1 year","180 days"],"answer":0,"explanation":"A third serious traffic violation within a 3-year period (from separate incidents) results in a disqualification of at least 120 days. Source: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.5; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation for CDL disqualification purposes in North Dakota?","options":["Speeding 15 mph or more over the posted speed limit","Operating a CMV with a BAC of 0.04 or more","Refusing a chemical test under implied consent","Leaving the scene of an accident"],"answer":0,"explanation":"Excessive speeding (15 mph or more over the limit) is a serious traffic violation. The other listed offenses are major offenses, which carry much longer disqualifications. Source: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.5; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Driving a CMV while texting, in violation of state or local law, is classified in North Dakota as which type of disqualifying offense?","options":["A serious traffic violation","A major offense","An out-of-service order violation","A railroad-crossing violation"],"answer":0,"explanation":"Texting while driving a CMV is a serious traffic violation; two within 3 years cause a 60-day disqualification and three within 3 years a 120-day disqualification. Source: NDDOT CDL Manual (Disqualification); 49 CFR 383.51; 49 CFR 392.80.","handbook":"","hbref":""},{"q":"Using a hand-held mobile telephone while driving a CMV, in violation of the rule, is treated in North Dakota as:","options":["A serious traffic violation","A minor equipment violation","A major offense disqualifying for 1 year","An out-of-service order violation"],"answer":0,"explanation":"Driving a CMV while using a hand-held mobile telephone is a serious traffic violation. Accumulating two or three within 3 years results in 60- or 120-day disqualifications, respectively. Source: NDDOT CDL Manual (Disqualification); 49 CFR 383.51; 49 CFR 392.82.","handbook":"","hbref":""},{"q":"Under the federal rule that applies in North Dakota, what is the maximum civil penalty a CMV driver can face for texting or using a hand-held phone while driving?","options":["$2,750","$500","$1,000","$5,000"],"answer":0,"explanation":"A driver may be subject to a civil penalty of up to $2,750 for texting or using a hand-held mobile phone while driving a CMV, in addition to disqualification for repeat serious violations. Source: FMCSA distracted-driving rule (49 CFR 392.80/392.82), applicable in North Dakota.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification in North Dakota for a FIRST conviction of violating an out-of-service (OOS) order while driving a non-HazMat, non-passenger CMV?","options":["180 days","60 days","1 year","90 days"],"answer":0,"explanation":"A first violation of an out-of-service order results in a disqualification of at least 180 days. Source: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.9; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In North Dakota, a SECOND out-of-service order violation within 10 years (non-HazMat, non-passenger) results in a disqualification of at least:","options":["2 years","180 days","1 year","3 years"],"answer":0,"explanation":"A second out-of-service order violation within a 10-year period disqualifies the driver for at least 2 years. Source: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.9; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A North Dakota CDL holder commits a THIRD out-of-service order violation within 10 years. What is the minimum disqualification?","options":["3 years","2 years","1 year","5 years"],"answer":0,"explanation":"A third or subsequent out-of-service order violation within a 10-year period results in a disqualification of at least 3 years. Source: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.9; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification for a FIRST out-of-service order violation while transporting placarded hazardous materials or while driving a vehicle designed to carry 16 or more passengers?","options":["180 days","90 days","1 year","60 days"],"answer":0,"explanation":"A first OOS-order violation while hauling placarded HazMat or operating a vehicle designed for 16+ passengers carries a minimum disqualification of 180 days (the same first-offense minimum as other CMVs, but second and third offenses are longer). Source: NDDOT CDL Manual (Disqualification); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification in North Dakota for a FIRST railroad-highway grade crossing violation?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A first conviction for a railroad-highway grade crossing violation results in a disqualification of at least 60 days. Source: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.6; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A North Dakota CDL holder commits a SECOND railroad-highway grade crossing violation within 3 years. What is the minimum disqualification?","options":["120 days","60 days","180 days","1 year"],"answer":0,"explanation":"A second railroad-grade crossing violation within a 3-year period results in a disqualification of at least 120 days. Source: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.6; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the minimum disqualification for a THIRD railroad-highway grade crossing violation within 3 years in North Dakota?","options":["1 year","120 days","180 days","60 days"],"answer":0,"explanation":"A third or subsequent railroad-grade crossing violation within a 3-year period results in a disqualification of at least 1 year (at least 180 days up to 1 year under the rule, with the maximum applied). Source: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.6; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A CMV driver in North Dakota is found with a measurable or detectable amount of alcohol below 0.04 BAC. What is the immediate consequence?","options":["Placed out of service for 24 hours","Permanently disqualified","Charged with a major offense","Given a 60-day disqualification"],"answer":0,"explanation":"A driver with any measurable alcohol concentration under 0.04 must be placed out of service for 24 hours; a BAC of 0.04 or more is a disqualifying major offense. Source: NDDOT CDL Manual (Alcohol/Out-of-Service); 49 CFR 392.5.","handbook":"","hbref":""},{"q":"On a North Dakota interstate highway outside a city, you approach a tow truck stopped on the right shoulder with its amber flashing lights on. Under North Dakota's Move Over law, what must the driver of an approaching commercial vehicle do?","options":["Continue at the posted speed since only police vehicles are covered","Come to a complete stop and wait until the vehicle leaves","Move to the left shoulder and stop","Move into a lane not adjacent to the stopped vehicle if it can be done safely, or otherwise slow down and pass with caution"],"answer":3,"explanation":"North Dakota Century Code 39-10-26 requires drivers on the interstate or a multilane highway outside a city to move to a lane not adjacent to a stopped emergency or highway-maintenance vehicle displaying amber/blue/white/red lights if it can be done safely; if not, the driver must slow down and proceed with caution at a safe speed. A 2023 amendment extended this to any stopped vehicle displaying hazard flashers. Source: NDCC 39-10-26; ND Highway Patrol Move Over Law.","handbook":"","hbref":""},{"q":"In 2023 North Dakota expanded its Move Over law. Besides authorized emergency and highway-maintenance vehicles, the duty to move over or slow down now also applies when approaching which stopped vehicle?","options":["Any vehicle displaying its flashing hazard warning signals","Only mail-delivery vehicles","Only vehicles displaying a blue light","Any vehicle parked within city limits"],"answer":0,"explanation":"North Dakota's 2023 expansion of the Move Over law (NDCC 39-10-26) added any stopped motor vehicle displaying flashing hazard warning signals on the interstate or a multilane highway outside a city. Source: NDCC 39-10-26; ND Highway Patrol / NDDOT Move Over Law materials.","handbook":"","hbref":""},{"q":"As of August 1, 2025, what is the maximum statutory speed limit on access-controlled, paved, divided multilane interstate highways in rural North Dakota (where posted), and does it differ for trucks?","options":["75 mph for cars but 65 mph for trucks","80 mph, applying to all vehicles including trucks","70 mph for all vehicles","80 mph for cars but 70 mph for trucks"],"answer":1,"explanation":"Under NDCC 39-09-02 (as amended by HB 1298, effective August 1, 2025), the maximum is 80 mph on rural access-controlled divided interstate highways. North Dakota does not set a separate lower truck speed limit by statute, so the limit applies to all vehicles. Source: NDCC 39-09-02; NDDOT / ND Highway Patrol speed limit guidance.","handbook":"","hbref":""},{"q":"Under North Dakota law, what is the maximum speed limit on a paved and divided multilane highway that is NOT an access-controlled interstate?","options":["55 mph","65 mph","70 mph","80 mph"],"answer":2,"explanation":"NDCC 39-09-02 sets 70 mph as the presumptive lawful maximum on paved and divided multilane highways (other than interstates, which are 80 mph). Source: NDCC 39-09-02.","handbook":"","hbref":""},{"q":"In North Dakota, on gravel, dirt, or loose-surface highways (and paved two-lane county and township highways) with no posted limit, what is the presumptive maximum lawful speed?","options":["45 mph","50 mph","55 mph","65 mph"],"answer":2,"explanation":"NDCC 39-09-02 sets 55 mph as the presumptive lawful maximum on gravel, dirt, or loose-surface highways and on paved two-lane county and township highways where no limit is posted. Source: NDCC 39-09-02.","handbook":"","hbref":""},{"q":"A driver operating a placarded hazardous-materials commercial vehicle in North Dakota approaches a railroad grade crossing required to be stopped at. Where must the vehicle stop?","options":["Within 75 feet but not less than 25 feet from the nearest rail","Within 100 feet but not less than 50 feet from the nearest rail","Within 50 feet but not less than 15 feet from the nearest rail","Anywhere within 10 feet of the nearest rail"],"answer":2,"explanation":"NDCC 39-10-43 requires the driver of a placarded HazMat vehicle (and certain tank/chlorine vehicles) to stop within 50 feet but not less than 15 feet from the nearest rail, then look and listen before proceeding. Source: NDCC 39-10-43; ND CDL Manual.","handbook":"","hbref":""},{"q":"In North Dakota, which vehicle is required by statute to stop at all railroad grade crossings (not just dangerous ones)?","options":["Any vehicle towing a trailer","A bus carrying passengers or a school bus","Any pickup truck used for farming","Any vehicle with a gross weight over 26,000 pounds"],"answer":1,"explanation":"NDCC 39-10-43 requires the driver of a bus carrying passengers, a school bus, and placarded HazMat/certain tank vehicles to stop at all railroad grade crossings within 50 feet but not less than 15 feet from the nearest rail. Source: NDCC 39-10-43.","handbook":"","hbref":""},{"q":"After stopping at a railroad crossing as required in North Dakota, what additional restriction does the statute place on a bus or HazMat driver while crossing the tracks?","options":["The driver must sound the horn continuously while crossing","The driver must not manually shift gears while crossing the track","The driver must put on the four-way flashers while crossing","The driver must cross in the highest available gear"],"answer":1,"explanation":"NDCC 39-10-43 directs the driver to cross only in a gear that avoids the need to change gears while on the crossing, and the driver may not shift gears manually while crossing the track. Source: NDCC 39-10-43; ND CDL Manual.","handbook":"","hbref":""},{"q":"Under North Dakota's stop-required rule for buses and HazMat vehicles at railroad crossings, when is a stop NOT required?","options":["When the vehicle is empty","When traffic is controlled by a police officer, or at a crossing marked 'Exempt' or 'Tracks out of service'","When the driver has more than one year of experience","When the crossing is in a business district"],"answer":1,"explanation":"NDCC 39-10-43 waives the stop when traffic is controlled by a police officer, and at crossings the director has designated and clearly marked 'Exempt' or 'Tracks out of service.' Source: NDCC 39-10-43.","handbook":"","hbref":""},{"q":"A North Dakota school bus is stopped with its flashing red lights and stop arm activated to load children. A commercial driver is approaching from the opposite direction on a two-lane road. What must the driver do?","options":["Slow to 20 mph and pass with caution","Pass only on the left at reduced speed","Continue, because opposing traffic is never required to stop","Stop before reaching the bus and not proceed until the lights and stop arm are no longer actuated"],"answer":3,"explanation":"NDCC 39-10-46 requires a driver meeting or overtaking a school bus from either direction to stop before reaching it when the flashing red lights or stop arm are actuated, and not proceed until the bus moves, the driver is signaled to proceed, or the lights and arm are no longer actuated. Source: NDCC 39-10-46.","handbook":"","hbref":""},{"q":"North Dakota's school-bus stopping law contains a divided-highway exception. Under NDCC 39-10-46, a driver need NOT stop for a stopped school bus only when:","options":["There are two or more lanes in the driver's direction","The bus is on a different roadway of a highway with separate roadways, or the driver is on a controlled-access highway and the bus is in a loading zone where pedestrians may not cross","There is a center two-way left-turn lane between the driver and the bus","The road has a painted center line"],"answer":1,"explanation":"Under NDCC 39-10-46(5), the exception applies only when the bus is on a DIFFERENT roadway of a highway with separate (physically divided) roadways, or on a controlled-access highway where the bus is in a loading zone and pedestrians may not cross. A mere center turn lane or painted line does not qualify. Source: NDCC 39-10-46.","handbook":"","hbref":""},{"q":"On an undivided four-lane North Dakota road (two lanes each way, separated only by a painted center line), a school bus going the opposite direction stops with red lights flashing. Must oncoming traffic stop?","options":["No, because there are multiple lanes","No, oncoming traffic never stops on a four-lane road","Only the lane nearest the bus must stop","Yes, because the roadway is not physically divided into separate roadways"],"answer":3,"explanation":"NDCC 39-10-46's exception applies only on highways with separate (physically divided) roadways. On an undivided multilane road with only a painted center line, oncoming traffic must still stop for a school bus showing flashing red lights and stop arm. Source: NDCC 39-10-46.","handbook":"","hbref":""},{"q":"Per North Dakota law, a school bus driver may activate the amber caution (warning) lights at what distance before the point where children will be received or discharged?","options":["Not less than 100 feet nor more than 300 feet","Not less than 200 feet nor more than 400 feet","Not less than 300 feet nor more than 500 feet","Exactly 250 feet"],"answer":2,"explanation":"NDCC 39-10-46(3) allows the amber caution lights to be activated not less than 300 feet nor more than 500 feet from the point where children are received or discharged. Source: NDCC 39-10-46.","handbook":"","hbref":""},{"q":"North Dakota law requires every school bus to bear a particular sign on its rear relating to railroad crossings. What does it say?","options":["\"DO NOT PASS ON TRACKS\"","\"THIS SCHOOLBUS STOPS AT ALL RAILROAD CROSSINGS\"","\"CAUTION: RAILROAD AHEAD\"","\"SCHOOLBUS YIELDS AT CROSSINGS\""],"answer":1,"explanation":"NDCC 39-10-46(6) requires every school bus to bear on its rear a plainly visible sign reading \"THIS SCHOOLBUS STOPS AT ALL RAILROAD CROSSINGS.\" Source: NDCC 39-10-46.","handbook":"","hbref":""},{"q":"Under North Dakota's rules of the road, a commercial vehicle proceeding at less than the normal speed of traffic on a multilane highway must:","options":["Use the left lane to stay out of merging traffic","Stay in whatever lane the driver prefers","Be driven in the right-hand lane or as close as practicable to the right edge, except when passing or preparing for a left turn","Use the center lane on a three-lane road"],"answer":2,"explanation":"NDCC 39-10-08(2) requires any vehicle moving slower than the normal speed of traffic to keep to the right-hand lane (or as close as practicable to the right edge), except when passing or preparing for a left turn. Source: NDCC 39-10-08.","handbook":"","hbref":""},{"q":"A North Dakota CDL driver's truck breaks down on a level, straight, undivided two-lane highway in daylight. Following the warning-device rules North Dakota applies, where should the three warning triangles be placed?","options":["All three within 10 feet of the rear of the truck","About 50 feet, 150 feet, and 250 feet behind the vehicle","One on the roof and two on the shoulder","About 10 feet behind, 100 feet behind, and 100 feet ahead of the vehicle"],"answer":3,"explanation":"North Dakota follows the federal placement standard (49 CFR 392.22): on a two-lane road, place triangles about 10 feet behind the vehicle on the traffic side, about 100 feet behind, and about 100 feet ahead. Source: ND CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"When a North Dakota CDL driver is stopped on a one-way or divided highway, how should the three warning triangles be placed toward approaching traffic?","options":["At about 10 feet, 100 feet, and 200 feet toward the approaching traffic","At about 25 feet, 75 feet, and 125 feet toward the approaching traffic","All three at 100 feet toward the approaching traffic","At about 50 feet, 100 feet, and 150 feet toward the approaching traffic"],"answer":0,"explanation":"On a one-way or divided highway, the federal standard North Dakota applies (49 CFR 392.22) calls for triangles at about 10 feet, 100 feet, and 200 feet toward the approaching traffic. Source: ND CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"A North Dakota CDL driver hauling a placarded load of explosives or flammable liquid must stop and set out warning devices. Which warning device is PROHIBITED on such a vehicle?","options":["Reflective warning triangles","Three portable red emergency reflectors","Flares or fusees (any flame-producing signal)","Red electric lanterns"],"answer":2,"explanation":"Flares, fusees, or any flame-producing signal may not be used on vehicles carrying explosives, flammable gas/liquid, or using compressed gas as fuel; reflective triangles, red reflectors, or red electric lanterns must be used instead. Source: ND CDL Manual; 49 CFR 392.22 / 393.95.","handbook":"","hbref":""},{"q":"Outside the spring thaw period, North Dakota's posture toward overweight permits for divisible loads during posted spring load restrictions is that:","options":["Overweight permits will NOT be issued for any divisible load during spring road restrictions","Divisible loads may always exceed limits with a standard permit year-round","Spring restrictions only apply to the interstate system","Divisible loads are exempt from all axle-weight limits in spring"],"answer":0,"explanation":"NDDOT and the ND Highway Patrol do not issue overweight permits for divisible loads during posted spring road (thaw) restrictions, which typically run from roughly mid-February into May depending on conditions. Source: NDDOT North Dakota Load Restrictions; ND Highway Patrol Oversize/Overweight Permit information.","handbook":"","hbref":""},{"q":"North Dakota statute sets a special low maximum speed for one specific equipment type. A vehicle equipped with solid rubber tires may not be driven faster than:","options":["5 mph","10 mph","20 mph","25 mph"],"answer":1,"explanation":"NDCC 39-09-04.1 prohibits driving any vehicle equipped with solid rubber tires at more than 10 mph. Source: NDCC 39-09-04.1.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver Licenses in North Dakota?","options":["The North Dakota Department of Transportation (NDDOT) Driver License Division","The Federal Motor Carrier Safety Administration (FMCSA)","The North Dakota Highway Patrol","The county sheriff's office where the driver resides"],"answer":0,"explanation":"In North Dakota, CDLs are issued by the North Dakota Department of Transportation (NDDOT) through its Driver License Division; FMCSA sets federal standards but does not issue state licenses. Source: NDDOT Commercial Driver License pages.","handbook":"","hbref":""},{"q":"Under North Dakota's medical self-certification, how many self-certification categories must a CDL applicant choose from?","options":["Four","Two","Three","Six"],"answer":0,"explanation":"North Dakota uses the four federal self-certification categories: non-excepted interstate, excepted interstate, non-excepted intrastate, and excepted intrastate. Source: NDDOT CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"A North Dakota driver self-certifies as 'non-excepted interstate.' What does this require regarding medical qualification?","options":["The driver must obtain and maintain a current DOT medical examiner's certificate","The driver is exempt from all medical certification requirements","The driver only needs a vision waiver","The driver must pass a state physical fitness test instead of a DOT exam"],"answer":0,"explanation":"Non-excepted interstate drivers are subject to 49 CFR Part 391 and must obtain and keep a current DOT medical examiner's certificate. Source: NDDOT CDL Medical Certification Requirements; 49 CFR 391.45.","handbook":"","hbref":""},{"q":"Which self-certification category in North Dakota does NOT require a DOT medical examiner's certificate?","options":["Excepted interstate","Non-excepted interstate","Non-excepted intrastate","Interstate hazmat hauler"],"answer":0,"explanation":"Drivers certifying as 'excepted' (interstate or intrastate) operate exclusively in excepted operations and are not required to hold a medical examiner's certificate; non-excepted drivers must. Source: NDDOT CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"As of April 21, 2025, how is a North Dakota CDL holder's DOT medical examiner's certificate submitted to the state?","options":["The certified medical examiner uploads it electronically; NDDOT no longer accepts paper certificates","The driver mails a paper copy to NDDOT","The driver faxes a copy to the Driver License Division","The employer files it with the county clerk"],"answer":0,"explanation":"Effective April 21, 2025, North Dakota no longer accepts medical certificates directly; nationally certified medical examiners must upload the certificate electronically to the registry/state. Source: NDDOT CDL medical certificate notice.","handbook":"","hbref":""},{"q":"Before taking the CDL skills test in North Dakota for a first Class A or B license, what training must a new applicant complete?","options":["Entry-Level Driver Training (ELDT) from a provider on the Training Provider Registry","A defensive driving classroom course at the county","A four-year apprenticeship with a licensed carrier","An employer-only orientation with no registry requirement"],"answer":0,"explanation":"Since February 7, 2022, federal ELDT rules adopted by North Dakota require new CDL applicants to complete training from an FMCSA Training Provider Registry-listed provider before the skills test. Source: NDDOT 'How to Apply'; FMCSA ELDT.","handbook":"","hbref":""},{"q":"The North Dakota CDL skills test consists of which three parts, in order?","options":["Pre-trip inspection, basic vehicle control, and on-road driving","Written knowledge test, eye exam, and on-road driving","Parallel parking, hazmat written test, and air brake test","Pre-trip inspection, hazmat endorsement test, and night driving"],"answer":0,"explanation":"North Dakota's CDL skills test follows the federal three-part format: pre-trip vehicle inspection, basic vehicle (control) skills, and on-road driving. Source: ND CDL Manual; NDDOT CDL pages.","handbook":"","hbref":""},{"q":"In North Dakota, what must an applicant obtain before being allowed to take the CDL skills (road) test?","options":["A Commercial Learner Permit (CLP) after passing the required knowledge test(s)","A full CDL issued provisionally","A hazardous materials endorsement","A federal operating authority number"],"answer":0,"explanation":"Applicants must first pass the knowledge test(s) and obtain a Commercial Learner Permit (CLP) before scheduling the skills test. Source: NDDOT 'How to Apply for a Commercial Driver License.'","handbook":"","hbref":""},{"q":"How long must a North Dakota CLP be held before the holder may take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"North Dakota enforces the federal 14-day hold: a CLP must be held for at least 14 days before the applicant may take the CDL skills test. Source: NDDOT CDL pages; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"In North Dakota, a Commercial Learner Permit is valid for up to how many consecutive days from its issue date?","options":["180 days","90 days","365 days","60 days"],"answer":0,"explanation":"A North Dakota CLP is valid for up to 180 consecutive days from the date of issue; if the road test is not passed in time, the permit must be renewed. Source: NDDOT CDL pages.","handbook":"","hbref":""},{"q":"When practicing with a North Dakota CLP, who must be in the vehicle with the permit holder?","options":["A CDL holder with the same or higher class/endorsements, seated next to the driver","Any licensed driver age 21 or older","A North Dakota Highway Patrol officer","No one is required if practicing off public roads"],"answer":0,"explanation":"A CLP holder may only drive a commercial vehicle when accompanied by a qualified CDL holder (with the proper class and endorsements) seated beside them. Source: NDDOT CDL pages; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"What is the standard renewal cycle for a North Dakota CDL?","options":["Four years","Five years","Two years","Eight years"],"answer":0,"explanation":"North Dakota CDLs are issued for a four-year term and expire at midnight on the driver's birthday at the end of that cycle. Source: NDDOT 'How to Renew a Commercial Driver License.'","handbook":"","hbref":""},{"q":"A North Dakota CDL expires at midnight on which date of the renewal year?","options":["The driver's birthday","December 31","The anniversary of the original issue date","The last day of the issuing month"],"answer":0,"explanation":"North Dakota CDLs expire at midnight on the driver's birthday in the renewal year. Source: NDDOT renewal information.","handbook":"","hbref":""},{"q":"Which documents must a North Dakota CDL applicant typically present when applying?","options":["A current driver license, proof of legal presence, and proof of residence address","Only a Social Security card","A passport and a vehicle registration only","A birth certificate and a hunting license"],"answer":0,"explanation":"NDDOT requires applicants to present a current driver license, proof of legal presence/identity, and proof of North Dakota residence address. Source: NDDOT 'How to Apply for a Commercial Driver License.'","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an intrastate-only (within North Dakota) CDL?","options":["18 years old","16 years old","21 years old","19 years old"],"answer":0,"explanation":"North Dakota allows an intrastate CDL at age 18; interstate operation (and hazmat) generally requires age 21. Source: NDDOT 'How to Apply'; 49 CFR 383/391.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a CDL valid for interstate driving (or for a hazmat endorsement) in North Dakota?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"Interstate CDL operation, and the hazardous materials endorsement, require the driver to be at least 21 years old. Source: NDDOT CDL requirements; federal CDL rules.","handbook":"","hbref":""},{"q":"To obtain a North Dakota CLP, in addition to passing the knowledge test, what examination is required?","options":["A vision (eye) examination","A hearing test administered by NDDOT","A drug and alcohol screening at the DOT office","A psychological evaluation"],"answer":0,"explanation":"North Dakota requires a vision/eye examination to issue a CLP, along with passing the required knowledge test(s). Source: NDDOT 'How to Apply for a Commercial Driver License.'","handbook":"","hbref":""},{"q":"If a North Dakota CDL applicant fails the knowledge test, what is the NDDOT policy on retaking it?","options":["Generally one attempt is allowed per day; the applicant returns another day to retest","The applicant must wait 30 days before any retake","The applicant is permanently barred after one failure","Unlimited same-day retakes are allowed"],"answer":0,"explanation":"NDDOT generally limits knowledge testing to one attempt per day, so a failing applicant must return on a later day to retest. Source: NDDOT CDL test/fee information. (Exact fees can change.)","handbook":"","hbref":""},{"q":"A driver wants to add a school bus (S) endorsement to a North Dakota CDL for the first time. What process step is required before the skills/endorsement test?","options":["Complete the required Entry-Level Driver Training (ELDT) for the S endorsement","Only pass a vision test","Hold the base CDL for at least five years","Obtain a separate intrastate-only permit"],"answer":0,"explanation":"Adding a passenger (P), school bus (S), or hazmat (H) endorsement for the first time triggers the ELDT requirement, which must be completed before testing. Source: NDDOT CDL pages; FMCSA ELDT rule effective Feb 7, 2022.","handbook":"","hbref":""},{"q":"On the North Dakota CDL skills test, the basic vehicle control portion primarily tests which abilities?","options":["Maneuvers such as straight-line backing, parking/docking, and controlled turning","Reading road signs from memory","Calculating bridge weight limits","Answering oral hazmat questions"],"answer":0,"explanation":"The basic vehicle control portion tests low-speed control maneuvers such as straight-line backing, alley docking, parallel parking, and precise turning. Source: ND CDL Manual; NDDOT skills test format.","handbook":"","hbref":""}],"ru":{"0":{"q":"На автомагистралях Северной Дакоты какова максимальная допустимая общая наружная ширина транспортного средства вместе с грузом?","options":["8 футов 6 дюймов","8 футов","9 футов","10 футов"],"explanation":"Северная Дакота ограничивает общую наружную ширину транспортного средства, включая груз, до 8 футов 6 дюймов на всех автомагистралях (NDCC 39-12-04; NDHP Motor Carrier Operations Legal Size and Weight Guide, Ref 9-1, Sec. A). Груз шире этого требует разрешения."},"1":{"q":"Какова максимальная допустимая высота транспортного средства, гружёного или негружёного, на автомагистралях Северной Дакоты?","options":["13 футов 6 дюймов","14 футов","13 футов","15 футов"],"explanation":"Северная Дакота устанавливает максимальную допустимую высоту транспортного средства в 14 футов, как для гружёного, так и для негружёного, однако водитель всё равно обязан убедиться в наличии зазора под мостами и путепроводами высотой менее 14 футов (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. B)."},"2":{"q":"В Северной Дакоте какова максимальная длина прицепа или полуприцепа, включая груз (для единиц техники, зарегистрированных после 1 июля 1987 года)?","options":["48 футов","53 фута","57 футов","60 футов"],"explanation":"Прицеп или полуприцеп, включая груз, не может превышать 53 фута в Северной Дакоте; прицепы/полуприцепы, оформленные и зарегистрированные в штате до 1 июля 1987 года, и буксируемые транспортные средства могут достигать 60 футов (NDCC 39-12-04; NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.4)."},"3":{"q":"Какова максимальная полная масса транспортного средства, разрешённая на системе межштатных автомагистралей (Interstate) в Северной Дакоте?","options":["85 500 фунтов","90 000 фунтов","80 000 фунтов","105 500 фунтов"],"explanation":"Максимальная полная масса транспортного средства на системе межштатных автомагистралей (Interstate) в Северной Дакоте составляет 80 000 фунтов (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.b), что соответствует федеральному лимиту для Interstate."},"4":{"q":"В Северной Дакоте ни одна одиночная ось не может нести полную массу, превышающую сколько фунтов?","options":["18 000 фунтов","20 000 фунтов","22 000 фунтов","24 000 фунтов"],"explanation":"Северная Дакота ограничивает одиночную ось максимальной полной массой в 20 000 фунтов (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.b). Оси, расположенные на расстоянии 40 дюймов или менее друг от друга, считаются одной осью."},"5":{"q":"Какую максимальную полную массу Северная Дакота разрешает для сдвоенной оси (tandem axle)?","options":["32 000 фунтов","36 000 фунтов","40 000 фунтов","34 000 фунтов"],"explanation":"В Северной Дакоте полная масса сдвоенной оси (tandem axle) не может превышать 34 000 фунтов (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.c), что соответствует федеральному лимиту для сдвоенной оси."},"6":{"q":"Какова максимальная длина одиночного транспортного средства с двумя или более осями, включая груз, в Северной Дакоте?","options":["40 футов","45 футов","50 футов","53 фута"],"explanation":"Одиночное транспортное средство с двумя или более осями, включая груз, не может превышать 50 футов в Северной Дакоте (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.1)."},"7":{"q":"На автомагистралях Северной Дакоты, ОТЛИЧНЫХ от системы межштатных автомагистралей (Interstate), какова максимальная полная масса, разрешённая для двух отдельных осей, расположенных на расстоянии 8 футов или более друг от друга?","options":["34 000 фунтов","36 000 фунтов","40 000 фунтов","44 000 фунтов"],"explanation":"На автомагистралях, отличных от системы межштатных автомагистралей (Interstate), суммарная полная масса двух отдельных осей, расположенных на расстоянии 8 футов или более друг от друга, не может превышать 40 000 фунтов в Северной Дакоте (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.b)."},"8":{"q":"На неустановленных (non-designated) автомагистралях Северной Дакоты какова максимальная длина состава из двух, трёх или четырёх единиц, включая груз?","options":["65 футов","70 футов","75 футов","85 футов"],"explanation":"Состав из двух, трёх или четырёх единиц, включая груз, не может превышать 75 футов на неустановленных автомагистралях Северной Дакоты; на установленных NDDOT четырёхполосных автомагистралях с разделительной полосой такие составы могут достигать 95 или 110 футов (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.2 and C.3)."},"9":{"q":"На автомагистралях штата Северная Дакота (отличных от Interstate) максимальная полная масса транспортного средства обычно составляет 80 000 фунтов, если только маршрут не установлен для большей массы, не превышающей какой предел?","options":["100 000 фунтов","105 500 фунтов","110 000 фунтов","129 000 фунтов"],"explanation":"На автомагистралях Северной Дакоты, отличных от Interstate, максимальная полная масса транспортного средства составляет 80 000 фунтов, если только автомагистраль не установлена для большей массы, в этом случае она не может превышать 105 500 фунтов (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.2.a)."},"10":{"q":"Согласно федеральной мостовой формуле (bridge formula), применяемой в Северной Дакоте, два последовательных набора сдвоенных осей могут нести по 34 000 фунтов каждый при условии, что расстояние между первой и последней осями этих наборов сдвоенных осей составляет не менее скольких футов?","options":["30 футов","34 фута","36 футов","40 футов"],"explanation":"Северная Дакота применяет мостовую формулу W = 500(LN/(N-1) + 12N + 36), но два последовательных набора сдвоенных осей могут нести по 34 000 фунтов каждый, если общее расстояние между первой и последней осями этих наборов составляет не менее 36 футов (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.a)."},"11":{"q":"В мостовой формуле Северной Дакоты W = 500(LN/(N-1) + 12N + 36) что обозначает буква N?","options":["Число осей в группе","Расстояние между крайними осями","Чистую массу груза","Максимальную массу в фунтах"],"explanation":"В мостовой формуле Северной Дакоты W — это максимальная масса на группе осей, L — расстояние в футах между крайними осями группы, а N — число осей в группе (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.a)."},"12":{"q":"На автомагистралях, отличных от системы межштатных автомагистралей (Interstate), в Северной Дакоте какова максимальная полная масса, разрешённая для группы из трёх или более осей?","options":["42 000 фунтов","51 000 фунтов","54 000 фунтов","48 000 фунтов"],"explanation":"На автомагистралях Северной Дакоты, отличных от системы межштатных автомагистралей (Interstate), полная масса группы из трёх или более осей не может превышать 48 000 фунтов; на Interstate группа регулируется мостовой формулой (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.c)."},"13":{"q":"Когда в Северной Дакоте требуется разрешение на однократную перевозку негабаритного/сверхтяжёлого груза (single-trip oversize/overweight permit)?","options":["Для любого коммерческого транспортного средства, перевозящего опасные материалы","Только для грузов, движущихся по Interstate после наступления темноты","Для неделимого груза, превышающего допустимые в Северной Дакоте лимиты по габаритам и/или массе","Для любого транспортного средства массой более 26 001 фунта"],"explanation":"Северная Дакота требует разрешение на однократную перевозку негабаритного/сверхтяжёлого груза для перемещения неделимого негабаритного и/или сверхтяжёлого груза, превышающего установленные в штате допустимые лимиты по габаритам и массе транспортного средства (NDHP Oversize/Overweight Permit, e-permits)."},"14":{"q":"В течение какого срока действует разрешение Северной Дакоты на однократную перевозку негабаритного/сверхтяжёлого груза для одного перемещения груза?","options":["До 24 часов","До 3 дней","До 5 дней","До 7 дней"],"explanation":"Разрешение Северной Дакоты на однократную перевозку негабаритного/сверхтяжёлого груза действует для одного перемещения груза до 5 дней (NDHP Oversize/Overweight Permit, e-permits system at nd.gov/ndhp)."},"15":{"q":"Разрешение Северной Дакоты на освобождение от ограничений по массе на время уборки урожая (harvest weight exemption permit) позволяет транспортному средству, перевозящему убранную сельскохозяйственную продукцию с поля до первого пункта хранения или продажи, нести сколько дополнительной массы?","options":["На 5 процентов больше массы","На 10 процентов больше массы","На 15 процентов больше массы","На 20 процентов больше массы"],"explanation":"Разрешение Северной Дакоты на освобождение от ограничений по массе на время уборки урожая позволяет перевозить на 10% больше массы при транспортировке убранной продукции с поля до первоначального пункта хранения или первого пункта продажи, действует с 15 июля по 30 ноября, при этом полная масса не может превышать 105 500 фунтов (NDHP e-permits, Harvest Weight Exemption Permit)."},"16":{"q":"В течение какого диапазона дат действует разрешение Северной Дакоты на освобождение от ограничений по массе на время уборки урожая?","options":["1 мая - 30 сентября","1 июня - 31 октября","15 июля - 30 ноября","1 августа - 31 декабря"],"explanation":"Разрешение Северной Дакоты на освобождение от ограничений по массе на время уборки урожая действует с 15 июля по 30 ноября для перевозки убранной продукции с поля до первоначального пункта хранения или первой продажи (NDHP e-permits, Harvest Weight Exemption Permit)."},"17":{"q":"В Северной Дакоте сельскохозяйственное орудие (implement of husbandry), перемещаемое фермером-резидентом между восходом и заходом солнца (не по Interstate), может превышать обычный лимит высоты в 14 футов до какой максимальной высоты?","options":["14 футов 6 дюймов","15 футов","15 футов 6 дюймов","16 футов"],"explanation":"Северная Дакота позволяет сельскохозяйственным орудиям достигать высоты 15 футов 6 дюймов при перемещении фермерами-резидентами, ранчерами, дилерами или производителями между восходом и заходом солнца на расстояние, не превышающее 60 миль, и не по Interstate (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. B.2.a)."},"18":{"q":"Транспортное средство в Северной Дакоте, работающее преимущественно на природном газе, может превышать лимит полной массы на сколько и до какого максимума?","options":["До 1 000 фунтов, максимум 81 000 фунтов","До 2 000 фунтов, максимум 82 000 фунтов","До 2 500 фунтов, максимум 82 500 фунтов","До 4 000 фунтов, максимум 84 000 фунтов"],"explanation":"Транспортное средство в Северной Дакоте, приводимое в движение двигателем, работающим преимущественно на природном газе, может превышать лимит массы до 2 000 фунтов, до максимальной полной массы в 82 000 фунтов, чтобы учесть более тяжёлую топливную систему (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.8)."},"19":{"q":"В Северной Дакоте масса рулевой оси (steering axle) определяется номинальной нагрузкой оси по данным производителя, но не может превышать сколько фунтов при движении по системе межштатных автомагистралей (Interstate)?","options":["12 000 фунтов","18 000 фунтов","20 000 фунтов","24 000 фунтов"],"explanation":"Северная Дакота ограничивает рулевую ось номинальной нагрузкой оси по данным производителя, не превышающей 20 000 фунтов на системе межштатных автомагистралей (Interstate), при этом ни одна шина не может превышать 550 фунтов на дюйм ширины шины (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.a)."},"20":{"q":"В Северной Дакоте какой класс CDL требуется для управления любым составом транспортных средств с полной массой автопоезда (GCWR) 26 001 фунт или более при условии, что буксируемое(ые) транспортное(ые) средство(а) имеет(ют) GVWR более 10 000 фунтов?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"CDL класса A Северной Дакоты (составное транспортное средство) распространяется на любой состав транспортных средств с GCWR 26 001 фунт или более, когда GVWR буксируемой единицы превышает 10 000 фунтов. Источник: страница NDDOT Commercial Driver License и ND CDL Manual; 49 CFR 383.91."},"21":{"q":"Согласно правилам Северной Дакоты, CDL класса B даёт водителю право управлять чем из перечисленного?","options":["Любым одиночным транспортным средством с GVWR 26 001 фунт или более, буксирующим единицу с GVWR не более 10 000 фунтов","Любым составом транспортных средств с GCWR более 26 001 фунта с буксируемой единицей более 10 000 фунтов","Только транспортными средствами, рассчитанными на перевозку 16 или более пассажиров","Только транспортными средствами с GVWR менее 26 001 фунта, перевозящими опасные материалы, требующие табличек (placards)"],"explanation":"Класс B Северной Дакоты (тяжёлое одиночное транспортное средство) распространяется на любое одиночное транспортное средство с GVWR 26 001 фунт или более, или на такое транспортное средство, буксирующее единицу с GVWR не более 10 000 фунтов. Источник: страница NDDOT Commercial Driver License и ND CDL Manual; 49 CFR 383.91."},"22":{"q":"Водитель в Северной Дакоте управляет одиночным транспортным средством с GVWR менее 26 001 фунта, рассчитанным на перевозку 16 или более пассажиров (включая водителя). Какой класс CDL применяется?","options":["Класс C","Класс A","Класс B","CDL не требуется"],"explanation":"Класс C Северной Дакоты (малое транспортное средство) применяется к одиночным транспортным средствам с GVWR менее 26 001 фунта, рассчитанным на перевозку 16 или более пассажиров (включая водителя) или перевозящим опасные материалы, требующие табличек (placards). Источник: страница NDDOT Commercial Driver License и ND CDL Manual; 49 CFR 383.91."},"23":{"q":"Какая отметка (endorsement) CDL Северной Дакоты требуется для управления цистерной (tank vehicle), используемой для перевозки жидкости или газа в стационарно установленной цистерне с индивидуальной номинальной ёмкостью более 119 галлонов (и суммарной ёмкостью 1 000 галлонов или более)?","options":["N (Цистерны)","H (Опасные материалы)","T (Двойные/тройные прицепы)","P (Пассажиры)"],"explanation":"Отметка N требуется в Северной Дакоте для перевозки жидкостей или газов в цистерне с номинальной ёмкостью более 119 галлонов индивидуально или 1 000 галлонов или более суммарно. Источник: страница NDDOT Commercial Driver License; 49 CFR 383.93."},"24":{"q":"В Северной Дакоте какую отметку (endorsement) должен получить владелец CDL для буксировки двойных или тройных прицепов?","options":["T (Двойные/тройные прицепы)","N (Цистерны)","X (Комбинация Цистерна/HazMat)","P (Пассажиры)"],"explanation":"Отметка T даёт право буксировать двойные или тройные прицепы в Северной Дакоте и получается путём сдачи теоретического теста на двойные/тройные прицепы. Источник: страница NDDOT Commercial Driver License и ND CDL Manual; 49 CFR 383.93."},"25":{"q":"Каков минимальный возраст для получения CDL Северной Дакоты, действительного только для ВНУТРИШТАТНОГО вождения (в пределах Северной Дакоты)?","options":["18 лет","16 лет","19 лет","21 год"],"explanation":"Северная Дакота допускает выдачу CDL для вождения только в пределах штата с 18 лет. Для работы в межштатной торговле (interstate commerce) водителям должно быть 21 год. Источник: требования NDDOT к CDL; NDCC Title 39; 49 CFR 383."},"26":{"q":"Заявитель на CDL Северной Дакоты, желающий водить в межштатной торговле (interstate commerce), перевозить опасные материалы или перевозить пассажиров за плату, должен быть не моложе какого возраста?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Северная Дакота требует, чтобы водителю было не менее 21 года для работы за пределами штата (межштатная торговля), перевозки опасных материалов или перевозки пассажиров за плату. Источник: требования NDDOT к CDL; 49 CFR 383."},"27":{"q":"После выдачи коммерческого ученического разрешения (CLP) Северной Дакоты сколько времени должен ждать заявитель, прежде чем получит право сдавать практический (дорожный) тест CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 7 дней","Не менее 60 дней"],"explanation":"Северная Дакота следует федеральному правилу, требующему, чтобы CLP удерживалось не менее 14 дней, прежде чем заявитель сможет сдавать практический тест CDL. Источник: страница подачи заявления на CDL NDDOT; 49 CFR 383.25."},"28":{"q":"Прежде чем получить отметку об опасных материалах (H) в Северной Дакоте, заявитель должен пройти какую федерально требуемую проверку благонадёжности?","options":["Оценку угрозы безопасности TSA (security threat assessment), включая снятие отпечатков пальцев","Проверку криминальной истории только через FBI без отпечатков пальцев","Полиграфическое обследование, проводимое штатом","Только проверку рекомендаций, проводимую работодателем"],"explanation":"Заявители на отметку H в Северной Дакоте должны пройти оценку угрозы безопасности TSA, которая включает сдачу отпечатков пальцев, прежде чем отметка может быть добавлена. Источник: страница NDDOT Hazardous Material Requirements; 49 CFR 1572 / TSA."},"29":{"q":"Какой этап подготовки начального уровня теперь требуется, прежде чем заявитель в Северной Дакоте сможет сдавать теоретический тест на НОВУЮ отметку об опасных материалах (H)?","options":["Федеральная теоретическая подготовка ELDT по hazmat от поставщика из реестра поставщиков обучения FMCSA (FMCSA Training Provider Registry)","40-часовая стажировка в кабине цистерны","Курс академии hazmat, проводимый штатом Северная Дакота","Обучение не требуется, только теоретический тест"],"explanation":"Первичные заявители на отметку H в Северной Дакоте должны пройти федерально требуемую теоретическую подготовку начального уровня (ELDT) по hazmat от поставщика, указанного в реестре поставщиков обучения FMCSA, перед теоретическим тестом. Источник: страница NDDOT Hazardous Material Requirements; 49 CFR 380."},"30":{"q":"Подготовка водителей начального уровня (ELDT), требуемая перед получением первого CDL класса A в Северной Дакоте, должна быть пройдена через какую систему?","options":["Поставщика, указанного в реестре поставщиков обучения FMCSA (FMCSA Training Provider Registry)","Любой общинный колледж Северной Дакоты, без федерального внесения в реестр","Внутреннюю автошколу NDDOT","Любого работодателя-перевозчика из другого штата по выбору водителя"],"explanation":"Северная Дакота требует, чтобы ELDT была пройдена через школу или организацию, указанную в реестре поставщиков обучения FMCSA, перед практическим тестом на первичный CDL класса A. Источник: страница NDDOT How to Apply for a CDL; 49 CFR 380 Subpart F."},"31":{"q":"Какая отметка (endorsement) нужна водителю в Северной Дакоте для управления транспортным средством (кроме школьного автобуса), рассчитанным на перевозку 16 или более человек, включая водителя?","options":["P (Пассажиры)","S (Школьный автобус)","N (Цистерна)","T (Двойные/тройные прицепы)"],"explanation":"Отметка P (Пассажиры) требуется для управления автобусом или другим транспортным средством, рассчитанным на перевозку 16 или более человек, включая водителя. Школьный автобус также требует отдельной отметки S. Источник: ND CDL Manual; 49 CFR 383.93."},"32":{"q":"Чтобы добавить отметку «Школьный автобус» (S) к CDL Северной Дакоты, какую отметку водитель должен ТАКЖЕ иметь?","options":["P (Пассажиры)","N (Цистерна)","H (Опасные материалы)","T (Двойные/тройные прицепы)"],"explanation":"В Северной Дакоте отметка S (Школьный автобус) требует, чтобы водитель сначала имел отметку P (Пассажиры), а также сдал теоретический и практический тесты на школьный автобус. Источник: ND CDL Manual; 49 CFR 383.93."},"33":{"q":"При подаче заявления на CDL Северной Дакоты заявитель должен предоставить подтверждение номера социального страхования (Social Security number). Какой из этих документов является приемлемым?","options":["Оригинал карты социального страхования (Social Security card)","Фотокопия карты социального страхования","Рукописная записка с указанием номера SSN","Библиотечная карта с указанием номера"],"explanation":"Северная Дакота требует подтверждения номера социального страхования, например оригинала карты социального страхования; фотокопии не принимаются, а документы должны быть оригинальными или заверенными. Источник: NDDOT Driver License Requirements / чек-лист REAL ID."},"34":{"q":"Сколько документов, подтверждающих место жительства, требует Северная Дакота от заявителя для установления его места жительства в Северной Дакоте?","options":["Два документа","Один документ","Три документа","Подтверждение места жительства не требуется"],"explanation":"Северная Дакота требует два документа, подтверждающих адрес места жительства заявителя в Северной Дакоте (например, счета за коммунальные услуги/финансовые выписки, налоговые записи). Источник: NDDOT Driver License Requirements / чек-лист REAL ID."},"35":{"q":"Помимо личности, номера социального страхования и места жительства, какое дополнительное подтверждение должен предоставить заявитель на CDL Северной Дакоты?","options":["Подтверждение гражданства США, законного постоянного проживания или законного/временного пребывания","Нотариально заверенное письмо от текущего работодателя","Подтверждение права собственности на транспортное средство","Аттестат об окончании средней школы"],"explanation":"Северная Дакота требует подтверждения гражданства, законного постоянного проживания или законного пребывания в Соединённых Штатах в дополнение к личности, SSN и месту жительства. Источник: страница NDDOT Driver License Requirements."},"36":{"q":"Заявитель на CDL Северной Дакоты, который водит в межштатной торговле (interstate commerce) и должен иметь при себе медицинскую справку (Medical Examiner's Certificate), будет самостоятельно сертифицироваться по какой категории?","options":["Межштатная, неисключённая (Interstate, non-excepted, NI)","Межштатная, исключённая (Interstate, excepted, EI)","Внутриштатная, неисключённая (Intrastate, non-excepted, NA)","Внутриштатная, исключённая (Intrastate, excepted, EA)"],"explanation":"Водители в межштатной торговле, которые должны соответствовать федеральным стандартам физической пригодности, самостоятельно сертифицируются как «Межштатная неисключённая» (Interstate Non-Excepted) и должны иметь действующую медицинскую справку (Medical Examiner's Certificate) в досье в Северной Дакоте. Источник: NDDOT CDL self-certification; 49 CFR 383.71 / 391."},"37":{"q":"Из скольких категорий медицинской самосертификации должен выбрать владелец CDL Северной Дакоты при сертификации типа торговли, в которой он работает?","options":["Из четырёх (межштатная неисключённая, межштатная исключённая, внутриштатная неисключённая, внутриштатная исключённая)","Из двух (только межштатная и внутриштатная)","Из трёх (межштатная, внутриштатная и освобождённая)","Из пяти (по одной на каждую отметку CDL)"],"explanation":"Федеральные правила, принятые Северной Дакотой, требуют выбора одной из четырёх категорий самосертификации: межштатная неисключённая, межштатная исключённая, внутриштатная неисключённая или внутриштатная исключённая. Источник: NDDOT CDL self-certification; 49 CFR 383.71."},"38":{"q":"Согласно федеральному стандарту, которому следует Северная Дакота, каков максимальный срок действия коммерческого ученического разрешения (CLP) до того, как оно должно быть продлено (без повторной сдачи теоретических тестов)?","options":["180 дней","30 дней","12 месяцев","5 лет"],"explanation":"CLP действует до 180 дней и может быть продлено один раз ещё на 180 дней в течение одногодичного окна без пересдачи; Северная Дакота выдаёт CLP по этому федеральному стандарту. Источник: ND CDL Manual; 49 CFR 383.25."},"39":{"q":"Заявитель на CDL Северной Дакоты должен сдавать практический (дорожный) тест на каком виде транспортного средства?","options":["На репрезентативном транспортном средстве того класса и типа, которым заявитель намерен управлять","На любом легковом автомобиле, принадлежащем заявителю","На транспортном средстве, предоставленном экзаменатором NDDOT","Только на составном транспортном средстве класса A, независимо от запрашиваемой категории"],"explanation":"Северная Дакота требует, чтобы практический тест сдавался на транспортном средстве, репрезентативном для класса и конфигурации (включая отметки, такие как школьный автобус или цистерна), которыми заявитель намерен управлять. Источник: страница подачи заявления на CDL NDDOT; 49 CFR 383.71/383.113."},"40":{"q":"В Северной Дакоте при какой концентрации алкоголя в крови (BAC) водитель считается управляющим коммерческим транспортным средством (CMV) в состоянии опьянения и подлежит дисквалификации?","options":["0.04 или выше","0.08 или выше","0.02 или выше","0.10 или выше"],"explanation":"Северная Дакота следует федеральному стандарту: управление CMV с BAC 0.04 или выше является алкогольным правонарушением, которое дисквалифицирует владельца CDL. Это половина лимита 0.08, применяемого к некоммерческому вождению. Источник: NDDOT Commercial Driver License Manual (Disqualification); NDCC 39-06.2-10.1."},"41":{"q":"Согласно закону Северной Дакоты о подразумеваемом согласии (implied-consent law), что происходит с владельцем CDL, который отказывается пройти химический тест на алкоголь во время управления CMV?","options":["Это приравнивается к осуждению за DUI и дисквалифицирует водителя","При первом отказе это влечёт только предупреждение","Это влечёт меньшее наказание, чем осуждение за DUI","Это влечёт только 30-дневное приостановление"],"explanation":"Отказ пройти химическое тестирование для целей CDL приравнивается к осуждению за алкогольное правонарушение/DUI. Первый отказ дисквалифицирует водителя не менее чем на один год, так же как и первое серьёзное правонарушение (major offense). Источник: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.1."},"42":{"q":"Каков минимальный срок дисквалификации CDL в Северной Дакоте за первое серьёзное правонарушение (major offense), например DUI на CMV, когда НЕ перевозятся опасные материалы?","options":["1 год","60 дней","6 месяцев","3 года"],"explanation":"Первое серьёзное правонарушение (например, управление CMV с BAC 0.04 или выше, DUI или отказ от теста) дисквалифицирует водителя не менее чем на один год. Источник: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10; 49 CFR 383.51."},"43":{"q":"В Северной Дакоте какова минимальная дисквалификация CDL за первое серьёзное правонарушение (major offense), совершённое во время перевозки CMV опасных материалов, маркированных табличками (placarded)?","options":["3 года","1 год","5 лет","120 дней"],"explanation":"Если первое серьёзное правонарушение совершено во время управления CMV, маркированным табличками для опасных материалов, дисквалификация увеличивается с одного года до не менее чем трёх лет. Источник: NDDOT CDL Manual (Disqualification); 49 CFR 383.51."},"44":{"q":"Каков срок дисквалификации CDL в Северной Дакоте за второе серьёзное правонарушение (major offense) (например, второй DUI на CMV)?","options":["Пожизненно","10 лет","3 года","5 лет"],"explanation":"Второе осуждение за любое серьёзное правонарушение, в любом сочетании, влечёт пожизненную дисквалификацию CDL. Источник: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10; 49 CFR 383.51."},"45":{"q":"Владелец CDL Северной Дакоты осуждён за использование транспортного средства для совершения тяжкого преступления (felony), связанного с производством или распространением контролируемого вещества. Какая дисквалификация применяется?","options":["Пожизненная дисквалификация без права восстановления","Дисквалификация на 1 год","Дисквалификация на 3 года","Дисквалификация на 60 дней"],"explanation":"Использование CMV для совершения тяжкого преступления, связанного с производством, распространением или сбытом контролируемого вещества, влечёт пожизненную дисквалификацию, не подлежащую восстановлению. Источник: NDDOT CDL Manual (Disqualification); 49 CFR 383.51."},"46":{"q":"Сколько серьёзных нарушений ПДД (serious traffic violations) в течение 3-летнего периода влекут 60-дневную дисквалификацию CDL в Северной Дакоте?","options":["2 (второе в течение 3 лет)","1 (первое нарушение)","3 (третье в течение 3 лет)","4 (четвёртое в течение 3 лет)"],"explanation":"Второе серьёзное нарушение ПДД в течение 3-летнего периода, возникшее из отдельных инцидентов, влечёт дисквалификацию не менее чем на 60 дней. Источник: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.5; 49 CFR 383.51."},"47":{"q":"В Северной Дакоте три серьёзных нарушения ПДД (serious traffic violations) в течение 3-летнего периода влекут дисквалификацию CDL не менее чем на какой срок?","options":["120 дней","60 дней","1 год","180 дней"],"explanation":"Третье серьёзное нарушение ПДД в течение 3-летнего периода (из отдельных инцидентов) влечёт дисквалификацию не менее чем на 120 дней. Источник: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.5; 49 CFR 383.51."},"48":{"q":"Что из перечисленного классифицируется как СЕРЬЁЗНОЕ нарушение ПДД (serious traffic violation) для целей дисквалификации CDL в Северной Дакоте?","options":["Превышение скорости на 15 миль/ч или более сверх установленного ограничения скорости","Управление CMV с BAC 0.04 или выше","Отказ от химического теста в рамках подразумеваемого согласия","Оставление места ДТП"],"explanation":"Чрезмерное превышение скорости (на 15 миль/ч или более сверх ограничения) является серьёзным нарушением ПДД. Остальные перечисленные правонарушения являются серьёзными правонарушениями (major offenses), которые влекут гораздо более длительные дисквалификации. Источник: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.5; 49 CFR 383.51."},"49":{"q":"Управление CMV во время отправки текстовых сообщений (texting) в нарушение закона штата или местного закона классифицируется в Северной Дакоте как какой тип дисквалифицирующего правонарушения?","options":["Серьёзное нарушение ПДД (serious traffic violation)","Серьёзное правонарушение (major offense)","Нарушение предписания о выводе из эксплуатации (out-of-service order)","Нарушение на железнодорожном переезде"],"explanation":"Отправка текстовых сообщений во время управления CMV является серьёзным нарушением ПДД; два таких нарушения в течение 3 лет влекут 60-дневную дисквалификацию, а три в течение 3 лет — 120-дневную дисквалификацию. Источник: NDDOT CDL Manual (Disqualification); 49 CFR 383.51; 49 CFR 392.80."},"50":{"q":"Использование ручного мобильного телефона во время управления CMV в нарушение правила рассматривается в Северной Дакоте как:","options":["Серьёзное нарушение ПДД (serious traffic violation)","Незначительное нарушение, связанное с оборудованием","Серьёзное правонарушение (major offense), дисквалифицирующее на 1 год","Нарушение предписания о выводе из эксплуатации (out-of-service order)"],"explanation":"Управление CMV с использованием ручного мобильного телефона является серьёзным нарушением ПДД. Накопление двух или трёх таких нарушений в течение 3 лет влечёт 60- или 120-дневную дисквалификацию соответственно. Источник: NDDOT CDL Manual (Disqualification); 49 CFR 383.51; 49 CFR 392.82."},"51":{"q":"Согласно федеральному правилу, применяемому в Северной Дакоте, каков максимальный гражданско-правовой штраф, с которым может столкнуться водитель CMV за отправку текстовых сообщений или использование ручного телефона во время вождения?","options":["$2 750","$500","$1 000","$5 000"],"explanation":"Водитель может быть подвергнут гражданско-правовому штрафу до $2 750 за отправку текстовых сообщений или использование ручного мобильного телефона во время управления CMV, в дополнение к дисквалификации за повторные серьёзные нарушения. Источник: правило FMCSA о вождении, отвлекающем внимание (49 CFR 392.80/392.82), применимое в Северной Дакоте."},"52":{"q":"Какова минимальная дисквалификация CDL в Северной Дакоте за ПЕРВОЕ осуждение за нарушение предписания о выводе из эксплуатации (out-of-service, OOS) во время управления CMV без HazMat и без пассажиров?","options":["180 дней","60 дней","1 год","90 дней"],"explanation":"Первое нарушение предписания о выводе из эксплуатации влечёт дисквалификацию не менее чем на 180 дней. Источник: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.9; 49 CFR 383.51."},"53":{"q":"В Северной Дакоте ВТОРОЕ нарушение предписания о выводе из эксплуатации (out-of-service) в течение 10 лет (без HazMat, без пассажиров) влечёт дисквалификацию не менее чем на:","options":["2 года","180 дней","1 год","3 года"],"explanation":"Второе нарушение предписания о выводе из эксплуатации в течение 10-летнего периода дисквалифицирует водителя не менее чем на 2 года. Источник: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.9; 49 CFR 383.51."},"54":{"q":"Владелец CDL Северной Дакоты совершает ТРЕТЬЕ нарушение предписания о выводе из эксплуатации (out-of-service) в течение 10 лет. Какова минимальная дисквалификация?","options":["3 года","2 года","1 год","5 лет"],"explanation":"Третье или последующее нарушение предписания о выводе из эксплуатации в течение 10-летнего периода влечёт дисквалификацию не менее чем на 3 года. Источник: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.9; 49 CFR 383.51."},"55":{"q":"Какова минимальная дисквалификация CDL за ПЕРВОЕ нарушение предписания о выводе из эксплуатации (out-of-service) во время перевозки опасных материалов, маркированных табличками (placarded), или во время управления транспортным средством, рассчитанным на перевозку 16 или более пассажиров?","options":["180 дней","90 дней","1 год","60 дней"],"explanation":"Первое нарушение предписания OOS во время перевозки маркированного табличками HazMat или управления транспортным средством, рассчитанным на 16+ пассажиров, влечёт минимальную дисквалификацию в 180 дней (тот же минимум за первое нарушение, что и для других CMV, но второе и третье нарушения длиннее). Источник: NDDOT CDL Manual (Disqualification); 49 CFR 383.51."},"56":{"q":"Какова минимальная дисквалификация CDL в Северной Дакоте за ПЕРВОЕ нарушение на железнодорожно-автомобильном переезде (railroad-highway grade crossing)?","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Первое осуждение за нарушение на железнодорожно-автомобильном переезде влечёт дисквалификацию не менее чем на 60 дней. Источник: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.6; 49 CFR 383.51."},"57":{"q":"Владелец CDL Северной Дакоты совершает ВТОРОЕ нарушение на железнодорожно-автомобильном переезде (railroad-highway grade crossing) в течение 3 лет. Какова минимальная дисквалификация?","options":["120 дней","60 дней","180 дней","1 год"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3-летнего периода влечёт дисквалификацию не менее чем на 120 дней. Источник: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.6; 49 CFR 383.51."},"58":{"q":"Какова минимальная дисквалификация за ТРЕТЬЕ нарушение на железнодорожно-автомобильном переезде (railroad-highway grade crossing) в течение 3 лет в Северной Дакоте?","options":["1 год","120 дней","180 дней","60 дней"],"explanation":"Третье или последующее нарушение на железнодорожном переезде в течение 3-летнего периода влечёт дисквалификацию не менее чем на 1 год (не менее 180 дней до 1 года согласно правилу, с применением максимума). Источник: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.6; 49 CFR 383.51."},"59":{"q":"У водителя CMV в Северной Дакоте обнаружено измеримое или определяемое количество алкоголя ниже 0.04 BAC. Каково немедленное последствие?","options":["Выведение из эксплуатации (out of service) на 24 часа","Постоянная дисквалификация","Обвинение в серьёзном правонарушении (major offense)","60-дневная дисквалификация"],"explanation":"Водитель с любой измеримой концентрацией алкоголя ниже 0.04 должен быть выведен из эксплуатации на 24 часа; BAC 0.04 или выше является дисквалифицирующим серьёзным правонарушением (major offense). Источник: NDDOT CDL Manual (Alcohol/Out-of-Service); 49 CFR 392.5."},"60":{"q":"На автомагистрали между штатами в Северной Дакоте за пределами города вы приближаетесь к эвакуатору, стоящему на правой обочине с включёнными мигающими жёлтыми огнями. Согласно закону Северной Дакоты «Уступи дорогу» (Move Over), что обязан сделать водитель приближающегося коммерческого транспортного средства?","options":["Продолжать движение с установленной скоростью, поскольку закон распространяется только на полицейские автомобили","Полностью остановиться и ждать, пока автомобиль не уедет","Перестроиться на левую обочину и остановиться","Перестроиться в полосу, не примыкающую к остановившемуся автомобилю, если это можно сделать безопасно, либо иначе снизить скорость и проехать с осторожностью"],"explanation":"North Dakota Century Code 39-10-26 требует, чтобы водители на автомагистрали между штатами или многополосной автодороге за пределами города перестроились в полосу, не примыкающую к остановившемуся аварийному транспортному средству или машине дорожной службы с включёнными жёлтыми/синими/белыми/красными огнями, если это можно сделать безопасно; если нет, водитель должен снизить скорость и продолжить движение с осторожностью на безопасной скорости. Поправка 2023 года распространила это правило на любое остановившееся транспортное средство с включённой аварийной сигнализацией. Источник: NDCC 39-10-26; ND Highway Patrol Move Over Law."},"61":{"q":"В 2023 году Северная Дакота расширила свой закон «Уступи дорогу» (Move Over). Помимо уполномоченных аварийных транспортных средств и машин дорожной службы, обязанность перестроиться или снизить скорость теперь также распространяется при приближении к какому остановившемуся транспортному средству?","options":["К любому транспортному средству с включённой аварийной световой сигнализацией","Только к автомобилям доставки почты","Только к транспортным средствам с включённым синим огнём","К любому транспортному средству, припаркованному в черте города"],"explanation":"Расширение закона «Уступи дорогу» в Северной Дакоте в 2023 году (NDCC 39-10-26) добавило любое остановившееся механическое транспортное средство с включённой аварийной световой сигнализацией на автомагистрали между штатами или многополосной автодороге за пределами города. Источник: NDCC 39-10-26; материалы ND Highway Patrol / NDDOT Move Over Law."},"62":{"q":"По состоянию на 1 августа 2025 года, какой максимальный установленный законом предел скорости действует на закрытых для въезда, мощёных, разделённых многополосных автомагистралях между штатами в сельской местности Северной Дакоты (где это обозначено знаками), и отличается ли он для грузовиков?","options":["75 mph для легковых автомобилей, но 65 mph для грузовиков","80 mph, применяется ко всем транспортным средствам, включая грузовики","70 mph для всех транспортных средств","80 mph для легковых автомобилей, но 70 mph для грузовиков"],"explanation":"Согласно NDCC 39-09-02 (с изменениями, внесёнными HB 1298, вступившими в силу 1 августа 2025 года), максимум составляет 80 mph на сельских закрытых для въезда разделённых автомагистралях между штатами. Северная Дакота не устанавливает отдельный пониженный предел скорости для грузовиков законом, поэтому ограничение применяется ко всем транспортным средствам. Источник: NDCC 39-09-02; руководство NDDOT / ND Highway Patrol по ограничениям скорости."},"63":{"q":"Согласно законодательству Северной Дакоты, каков максимальный предел скорости на мощёной и разделённой многополосной автодороге, которая НЕ является закрытой для въезда автомагистралью между штатами?","options":["55 mph","65 mph","70 mph","80 mph"],"explanation":"NDCC 39-09-02 устанавливает 70 mph в качестве предполагаемого законного максимума на мощёных и разделённых многополосных автодорогах (кроме автомагистралей между штатами, где предел составляет 80 mph). Источник: NDCC 39-09-02."},"64":{"q":"В Северной Дакоте на гравийных, грунтовых дорогах или дорогах с рыхлым покрытием (а также на мощёных двухполосных дорогах округов и тауншипов) при отсутствии обозначенного знаками ограничения, каков предполагаемый максимальный законный предел скорости?","options":["45 mph","50 mph","55 mph","65 mph"],"explanation":"NDCC 39-09-02 устанавливает 55 mph в качестве предполагаемого законного максимума на гравийных, грунтовых дорогах или дорогах с рыхлым покрытием, а также на мощёных двухполосных дорогах округов и тауншипов, где ограничение не обозначено знаками. Источник: NDCC 39-09-02."},"65":{"q":"Водитель, управляющий коммерческим транспортным средством с табличками опасных грузов в Северной Дакоте, приближается к железнодорожному переезду, на котором требуется остановка. Где транспортное средство должно остановиться?","options":["В пределах 75 футов, но не ближе 25 футов от ближайшего рельса","В пределах 100 футов, но не ближе 50 футов от ближайшего рельса","В пределах 50 футов, но не ближе 15 футов от ближайшего рельса","В любом месте в пределах 10 футов от ближайшего рельса"],"explanation":"NDCC 39-10-43 требует, чтобы водитель транспортного средства с табличками HazMat (а также определённых цистерн/транспортных средств с хлором) остановился в пределах 50 футов, но не ближе 15 футов от ближайшего рельса, затем посмотрел и прислушался, прежде чем продолжить движение. Источник: NDCC 39-10-43; ND CDL Manual."},"66":{"q":"В Северной Дакоте какое транспортное средство по закону обязано останавливаться на всех железнодорожных переездах (а не только на опасных)?","options":["Любое транспортное средство, буксирующее прицеп","Автобус с пассажирами или школьный автобус","Любой пикап, используемый в сельском хозяйстве","Любое транспортное средство с полной массой более 26,000 фунтов"],"explanation":"NDCC 39-10-43 требует, чтобы водитель автобуса с пассажирами, школьного автобуса и транспортных средств с табличками HazMat/определённых цистерн останавливался на всех железнодорожных переездах в пределах 50 футов, но не ближе 15 футов от ближайшего рельса. Источник: NDCC 39-10-43."},"67":{"q":"После остановки на железнодорожном переезде, как того требует закон в Северной Дакоте, какое дополнительное ограничение закон налагает на водителя автобуса или транспортного средства с HazMat при пересечении путей?","options":["Водитель должен непрерывно подавать звуковой сигнал во время пересечения","Водитель не должен вручную переключать передачи во время пересечения путей","Водитель должен включить аварийную сигнализацию во время пересечения","Водитель должен пересекать переезд на наивысшей доступной передаче"],"explanation":"NDCC 39-10-43 предписывает водителю пересекать переезд только на той передаче, которая позволяет избежать необходимости переключения передач во время нахождения на переезде, и водитель не вправе вручную переключать передачи во время пересечения путей. Источник: NDCC 39-10-43; ND CDL Manual."},"68":{"q":"Согласно правилу обязательной остановки для автобусов и транспортных средств с HazMat на железнодорожных переездах в Северной Дакоте, в каком случае остановка НЕ требуется?","options":["Когда транспортное средство пустое","Когда движением управляет сотрудник полиции, или на переезде, обозначенном как «Exempt» (освобождён) или «Tracks out of service» (пути выведены из эксплуатации)","Когда у водителя более одного года опыта","Когда переезд находится в деловом районе"],"explanation":"NDCC 39-10-43 отменяет остановку, когда движением управляет сотрудник полиции, а также на переездах, которые директор обозначил и чётко промаркировал как «Exempt» или «Tracks out of service». Источник: NDCC 39-10-43."},"69":{"q":"Школьный автобус в Северной Дакоте остановился с включёнными мигающими красными огнями и выдвинутым знаком «Stop» для посадки детей. Водитель коммерческого транспортного средства приближается со встречного направления по двухполосной дороге. Что должен сделать водитель?","options":["Снизить скорость до 20 mph и проехать с осторожностью","Объехать только слева на пониженной скорости","Продолжать движение, поскольку встречный транспорт никогда не обязан останавливаться","Остановиться, не доезжая до автобуса, и не продолжать движение, пока огни и знак «Stop» не будут отключены"],"explanation":"NDCC 39-10-46 требует, чтобы водитель, который встречает или обгоняет школьный автобус с любого направления, остановился, не доезжая до него, когда включены мигающие красные огни или выдвинут знак «Stop», и не продолжал движение, пока автобус не тронется, водителю не подадут сигнал продолжить движение, либо огни и знак не будут отключены. Источник: NDCC 39-10-46."},"70":{"q":"Закон Северной Дакоты об остановке перед школьным автобусом содержит исключение для разделённых автодорог. Согласно NDCC 39-10-46, водитель НЕ обязан останавливаться перед остановившимся школьным автобусом только в случае, когда:","options":["В направлении движения водителя имеется две или более полос","Автобус находится на другой проезжей части автодороги с раздельными проезжими частями, или водитель движется по автодороге с ограниченным доступом, а автобус находится в зоне посадки, где пешеходам нельзя переходить","Между водителем и автобусом имеется центральная полоса для левого поворота в обоих направлениях","На дороге нанесена осевая разметка"],"explanation":"Согласно NDCC 39-10-46(5), исключение применяется только когда автобус находится на ДРУГОЙ проезжей части автодороги с раздельными (физически разделёнными) проезжими частями, либо на автодороге с ограниченным доступом, где автобус находится в зоне посадки и пешеходам нельзя переходить. Простая центральная полоса для поворота или нанесённая разметка под исключение не подпадают. Источник: NDCC 39-10-46."},"71":{"q":"На неразделённой четырёхполосной дороге в Северной Дакоте (по две полосы в каждом направлении, разделённые только нанесённой осевой разметкой) школьный автобус, едущий во встречном направлении, останавливается с мигающими красными огнями. Должен ли встречный транспорт останавливаться?","options":["Нет, потому что имеется несколько полос","Нет, встречный транспорт никогда не останавливается на четырёхполосной дороге","Должна остановиться только полоса, ближайшая к автобусу","Да, потому что проезжая часть не разделена физически на раздельные проезжие части"],"explanation":"Исключение NDCC 39-10-46 применяется только на автодорогах с раздельными (физически разделёнными) проезжими частями. На неразделённой многополосной дороге, имеющей лишь нанесённую осевую разметку, встречный транспорт всё равно обязан останавливаться перед школьным автобусом с мигающими красными огнями и выдвинутым знаком «Stop». Источник: NDCC 39-10-46."},"72":{"q":"Согласно законодательству Северной Дакоты, водитель школьного автобуса может включить жёлтые предупреждающие (предостерегающие) огни на каком расстоянии до места, где будет производиться посадка или высадка детей?","options":["Не менее 100 футов и не более 300 футов","Не менее 200 футов и не более 400 футов","Не менее 300 футов и не более 500 футов","Ровно 250 футов"],"explanation":"NDCC 39-10-46(3) разрешает включать жёлтые предупреждающие огни не менее чем за 300 футов и не более чем за 500 футов до места, где производится посадка или высадка детей. Источник: NDCC 39-10-46."},"73":{"q":"Закон Северной Дакоты требует, чтобы каждый школьный автобус имел сзади определённую табличку, касающуюся железнодорожных переездов. Что на ней написано?","options":["«DO NOT PASS ON TRACKS»","«THIS SCHOOLBUS STOPS AT ALL RAILROAD CROSSINGS»","«CAUTION: RAILROAD AHEAD»","«SCHOOLBUS YIELDS AT CROSSINGS»"],"explanation":"NDCC 39-10-46(6) требует, чтобы каждый школьный автобус имел сзади хорошо видимую табличку с надписью «THIS SCHOOLBUS STOPS AT ALL RAILROAD CROSSINGS». Источник: NDCC 39-10-46."},"74":{"q":"Согласно правилам дорожного движения Северной Дакоты, коммерческое транспортное средство, движущееся со скоростью ниже обычной скорости потока на многополосной автодороге, должно:","options":["Использовать левую полосу, чтобы не мешать вливающемуся транспорту","Оставаться в любой полосе, какую предпочитает водитель","Двигаться по правой полосе или как можно ближе к правому краю, за исключением случаев обгона или подготовки к левому повороту","Использовать центральную полосу на трёхполосной дороге"],"explanation":"NDCC 39-10-08(2) требует, чтобы любое транспортное средство, движущееся медленнее обычной скорости потока, держалось правой полосы (или как можно ближе к правому краю), за исключением случаев обгона или подготовки к левому повороту. Источник: NDCC 39-10-08."},"75":{"q":"Грузовик водителя с CDL в Северной Дакоте сломался на ровном, прямом, неразделённом двухполосном участке дороги в светлое время суток. Согласно правилам размещения предупреждающих устройств, применяемым в Северной Дакоте, где следует расположить три предупреждающих треугольника?","options":["Все три в пределах 10 футов позади грузовика","Примерно 50 футов, 150 футов и 250 футов позади транспортного средства","Один на крыше и два на обочине","Примерно 10 футов позади, 100 футов позади и 100 футов впереди транспортного средства"],"explanation":"Северная Дакота следует федеральному стандарту размещения (49 CFR 392.22): на двухполосной дороге треугольники размещаются примерно в 10 футах позади транспортного средства со стороны движения, примерно в 100 футах позади и примерно в 100 футах впереди. Источник: ND CDL Manual; 49 CFR 392.22."},"76":{"q":"Когда водитель с CDL в Северной Дакоте остановился на дороге с односторонним движением или на разделённой автодороге, как следует расположить три предупреждающих треугольника в сторону приближающегося транспорта?","options":["Примерно в 10 футах, 100 футах и 200 футах в сторону приближающегося транспорта","Примерно в 25 футах, 75 футах и 125 футах в сторону приближающегося транспорта","Все три в 100 футах в сторону приближающегося транспорта","Примерно в 50 футах, 100 футах и 150 футах в сторону приближающегося транспорта"],"explanation":"На дороге с односторонним движением или разделённой автодороге федеральный стандарт, применяемый в Северной Дакоте (49 CFR 392.22), предписывает размещать треугольники примерно в 10 футах, 100 футах и 200 футах в сторону приближающегося транспорта. Источник: ND CDL Manual; 49 CFR 392.22."},"77":{"q":"Водитель с CDL в Северной Дакоте, перевозящий груз взрывчатых веществ или легковоспламеняющейся жидкости с табличками, должен остановиться и выставить предупреждающие устройства. Какое предупреждающее устройство ЗАПРЕЩЕНО на таком транспортном средстве?","options":["Светоотражающие предупреждающие треугольники","Три портативных красных аварийных отражателя","Сигнальные огни или фальшфейеры (любой сигнал, образующий пламя)","Красные электрические фонари"],"explanation":"Сигнальные огни, фальшфейеры или любой образующий пламя сигнал не могут использоваться на транспортных средствах, перевозящих взрывчатые вещества, легковоспламеняющийся газ/жидкость или использующих сжатый газ в качестве топлива; вместо них необходимо использовать светоотражающие треугольники, красные отражатели или красные электрические фонари. Источник: ND CDL Manual; 49 CFR 392.22 / 393.95."},"78":{"q":"Вне периода весеннего оттаивания позиция Северной Дакоты в отношении разрешений на перевес для делимых грузов во время действия обозначенных весенних ограничений нагрузки заключается в том, что:","options":["Разрешения на перевес НЕ выдаются ни для каких делимых грузов во время весенних дорожных ограничений","Делимые грузы всегда могут превышать пределы при наличии стандартного разрешения круглый год","Весенние ограничения применяются только к системе автомагистралей между штатами","Делимые грузы освобождены от всех ограничений по осевой нагрузке весной"],"explanation":"NDDOT и ND Highway Patrol не выдают разрешения на перевес для делимых грузов во время действия обозначенных весенних дорожных ограничений (по оттаиванию), которые обычно действуют примерно с середины февраля до мая в зависимости от условий. Источник: NDDOT North Dakota Load Restrictions; информация ND Highway Patrol о разрешениях на негабарит/перевес."},"79":{"q":"Закон Северной Дакоты устанавливает особый низкий максимальный предел скорости для одного конкретного типа оборудования. Транспортное средство, оснащённое цельнорезиновыми шинами, не может двигаться быстрее, чем:","options":["5 mph","10 mph","20 mph","25 mph"],"explanation":"NDCC 39-09-04.1 запрещает управлять любым транспортным средством, оснащённым цельнорезиновыми шинами, со скоростью более 10 mph. Источник: NDCC 39-09-04.1."},"80":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) в Северной Дакоте?","options":["Отдел водительских удостоверений Департамента транспорта Северной Дакоты (NDDOT)","Федеральное управление безопасности автомобильных перевозчиков (FMCSA)","Дорожный патруль Северной Дакоты (North Dakota Highway Patrol)","Управление шерифа округа, где проживает водитель"],"explanation":"В Северной Дакоте CDL выдаёт Департамент транспорта Северной Дакоты (NDDOT) через свой Отдел водительских удостоверений; FMCSA устанавливает федеральные стандарты, но не выдаёт лицензии штатов. Источник: страницы NDDOT Commercial Driver License."},"81":{"q":"Согласно медицинской самосертификации Северной Дакоты, из скольких категорий самосертификации должен выбирать кандидат на получение CDL?","options":["Четырёх","Двух","Трёх","Шести"],"explanation":"Северная Дакота использует четыре федеральные категории самосертификации: non-excepted interstate (междуштатные перевозки без исключений), excepted interstate (междуштатные перевозки с исключениями), non-excepted intrastate (внутриштатные перевозки без исключений) и excepted intrastate (внутриштатные перевозки с исключениями). Источник: NDDOT CDL Medical Certification Requirements."},"82":{"q":"Водитель в Северной Дакоте самосертифицируется как «non-excepted interstate». Что это требует в отношении медицинской квалификации?","options":["Водитель должен получить и поддерживать действующий медицинский сертификат эксперта DOT (DOT medical examiner's certificate)","Водитель освобождён от всех требований медицинской сертификации","Водителю нужен только отказ по зрению (vision waiver)","Водитель должен пройти физический тест на пригодность штата вместо осмотра DOT"],"explanation":"Водители категории non-excepted interstate подпадают под действие 49 CFR Part 391 и должны получить и поддерживать действующий медицинский сертификат эксперта DOT. Источник: NDDOT CDL Medical Certification Requirements; 49 CFR 391.45."},"83":{"q":"Какая категория самосертификации в Северной Дакоте НЕ требует медицинского сертификата эксперта DOT?","options":["Excepted interstate","Non-excepted interstate","Non-excepted intrastate","Перевозчик опасных грузов в междуштатном сообщении (interstate hazmat hauler)"],"explanation":"Водители, сертифицирующиеся как «excepted» (с исключениями, в междуштатном или внутриштатном сообщении), работают исключительно в операциях с исключениями и не обязаны иметь медицинский сертификат эксперта; водители без исключений (non-excepted) обязаны. Источник: NDDOT CDL Medical Certification Requirements."},"84":{"q":"По состоянию на 21 апреля 2025 года, как медицинский сертификат эксперта DOT владельца CDL в Северной Дакоте подаётся в штат?","options":["Сертифицированный медицинский эксперт загружает его в электронном виде; NDDOT больше не принимает бумажные сертификаты","Водитель отправляет бумажную копию по почте в NDDOT","Водитель отправляет копию по факсу в Отдел водительских удостоверений","Работодатель подаёт его секретарю округа"],"explanation":"С 21 апреля 2025 года Северная Дакота больше не принимает медицинские сертификаты напрямую; медицинские эксперты, сертифицированные на национальном уровне, должны загружать сертификат в электронном виде в реестр/штат. Источник: уведомление NDDOT о медицинском сертификате CDL."},"85":{"q":"Прежде чем сдавать практический экзамен на CDL в Северной Дакоте для первого получения лицензии класса A или B, какое обучение должен пройти новый кандидат?","options":["Обучение водителей начального уровня (ELDT) у поставщика из Реестра поставщиков обучения (Training Provider Registry)","Аудиторный курс безопасного вождения в округе","Четырёхлетнее ученичество у лицензированного перевозчика","Ориентационный курс только от работодателя без требования о реестре"],"explanation":"С 7 февраля 2022 года федеральные правила ELDT, принятые Северной Дакотой, требуют, чтобы новые кандидаты на CDL прошли обучение у поставщика, внесённого в Реестр поставщиков обучения FMCSA (Training Provider Registry), перед практическим экзаменом. Источник: NDDOT «How to Apply»; FMCSA ELDT."},"86":{"q":"Из каких трёх частей состоит практический экзамен на CDL в Северной Дакоте, в каком порядке?","options":["Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Письменный теоретический тест, проверка зрения и вождение по дороге","Параллельная парковка, письменный тест по hazmat и тест на воздушные тормоза","Предрейсовый осмотр, тест на эндорсмент по hazmat и вождение в ночное время"],"explanation":"Практический экзамен на CDL в Северной Дакоте следует федеральному трёхчастному формату: предрейсовый осмотр транспортного средства, базовые навыки управления транспортным средством и вождение по дороге. Источник: ND CDL Manual; страницы NDDOT CDL."},"87":{"q":"В Северной Дакоте что должен получить кандидат, прежде чем ему будет разрешено сдавать практический экзамен на CDL (вождение по дороге)?","options":["Коммерческое ученическое разрешение (Commercial Learner Permit, CLP) после сдачи требуемого теоретического теста(ов)","Полное CDL, выданное условно","Эндорсмент на перевозку опасных материалов","Федеральный номер операционных полномочий"],"explanation":"Кандидаты должны сначала сдать теоретический тест(ы) и получить коммерческое ученическое разрешение (CLP), прежде чем назначать практический экзамен. Источник: NDDOT «How to Apply for a Commercial Driver License»."},"88":{"q":"Сколько времени необходимо владеть CLP в Северной Дакоте, прежде чем владелец сможет сдавать практический экзамен на CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 7 дней","Не менее 60 дней"],"explanation":"Северная Дакота применяет федеральный срок выжидания в 14 дней: CLP должно находиться у владельца не менее 14 дней, прежде чем кандидат сможет сдавать практический экзамен на CDL. Источник: страницы NDDOT CDL; 49 CFR 383.25."},"89":{"q":"В Северной Дакоте коммерческое ученическое разрешение действительно в течение скольких последовательных дней с даты его выдачи?","options":["180 дней","90 дней","365 дней","60 дней"],"explanation":"CLP в Северной Дакоте действительно в течение до 180 последовательных дней с даты выдачи; если практический экзамен не сдан в срок, разрешение необходимо продлить. Источник: страницы NDDOT CDL."},"90":{"q":"При тренировке с CLP в Северной Дакоте кто должен находиться в транспортном средстве вместе с владельцем разрешения?","options":["Владелец CDL такого же или более высокого класса/с такими же или более высокими эндорсментами, сидящий рядом с водителем","Любой лицензированный водитель в возрасте 21 года или старше","Сотрудник Дорожного патруля Северной Дакоты","Никто не требуется, если тренировка проходит вне дорог общего пользования"],"explanation":"Владелец CLP может управлять коммерческим транспортным средством только в сопровождении квалифицированного владельца CDL (с надлежащим классом и эндорсментами), сидящего рядом с ним. Источник: страницы NDDOT CDL; 49 CFR 383.25."},"91":{"q":"Каков стандартный цикл продления CDL в Северной Дакоте?","options":["Четыре года","Пять лет","Два года","Восемь лет"],"explanation":"CDL в Северной Дакоте выдаются сроком на четыре года и истекают в полночь в день рождения водителя в конце этого цикла. Источник: NDDOT «How to Renew a Commercial Driver License»."},"92":{"q":"CDL в Северной Дакоте истекает в полночь в какую дату года продления?","options":["В день рождения водителя","31 декабря","В годовщину первоначальной даты выдачи","В последний день месяца выдачи"],"explanation":"CDL в Северной Дакоте истекают в полночь в день рождения водителя в год продления. Источник: информация NDDOT о продлении."},"93":{"q":"Какие документы обычно должен предъявить кандидат на CDL в Северной Дакоте при подаче заявления?","options":["Действующее водительское удостоверение, подтверждение законного пребывания и подтверждение адреса проживания","Только карту социального страхования","Только паспорт и регистрацию транспортного средства","Свидетельство о рождении и охотничью лицензию"],"explanation":"NDDOT требует, чтобы кандидаты предъявили действующее водительское удостоверение, подтверждение законного пребывания/личности и подтверждение адреса проживания в Северной Дакоте. Источник: NDDOT «How to Apply for a Commercial Driver License»."},"94":{"q":"Каков минимальный возраст для получения CDL только для внутриштатных перевозок (в пределах Северной Дакоты)?","options":["18 лет","16 лет","21 год","19 лет"],"explanation":"Северная Дакота допускает внутриштатное CDL с 18 лет; для междуштатных перевозок (и hazmat), как правило, требуется возраст 21 год. Источник: NDDOT «How to Apply»; 49 CFR 383/391."},"95":{"q":"Каков минимальный возраст для получения CDL, действительного для междуштатных перевозок (или для эндорсмента hazmat) в Северной Дакоте?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Для междуштатных перевозок по CDL, а также для эндорсмента на перевозку опасных материалов, водитель должен быть не моложе 21 года. Источник: требования NDDOT CDL; федеральные правила CDL."},"96":{"q":"Для получения CLP в Северной Дакоте, помимо сдачи теоретического теста, какое обследование требуется?","options":["Обследование зрения (проверка глаз)","Проверка слуха, проводимая NDDOT","Тестирование на наркотики и алкоголь в офисе DOT","Психологическое обследование"],"explanation":"Северная Дакота требует обследования зрения/глаз для выдачи CLP, наряду со сдачей требуемого теоретического теста(ов). Источник: NDDOT «How to Apply for a Commercial Driver License»."},"97":{"q":"Если кандидат на CDL в Северной Дакоте не сдал теоретический тест, какова политика NDDOT в отношении его пересдачи?","options":["Как правило, разрешается одна попытка в день; кандидат возвращается в другой день для пересдачи","Кандидат должен подождать 30 дней перед любой пересдачей","Кандидат пожизненно отстраняется после одной неудачи","Разрешается неограниченное количество пересдач в тот же день"],"explanation":"NDDOT, как правило, ограничивает теоретическое тестирование одной попыткой в день, поэтому кандидат, не сдавший экзамен, должен вернуться в более поздний день для пересдачи. Источник: информация NDDOT о тестах/сборах за CDL. (Точные сборы могут меняться.)"},"98":{"q":"Водитель хочет впервые добавить эндорсмент на школьный автобус (S) к CDL в Северной Дакоте. Какой шаг процесса требуется перед практическим экзаменом/экзаменом на эндорсмент?","options":["Пройти требуемое обучение водителей начального уровня (ELDT) для эндорсмента S","Только сдать проверку зрения","Владеть базовым CDL не менее пяти лет","Получить отдельное разрешение только для внутриштатных перевозок"],"explanation":"Добавление эндорсмента на пассажирские перевозки (P), школьный автобус (S) или hazmat (H) впервые влечёт за собой требование ELDT, которое должно быть выполнено перед сдачей экзамена. Источник: страницы NDDOT CDL; правило FMCSA ELDT, вступившее в силу 7 февраля 2022 года."},"99":{"q":"На практическом экзамене на CDL в Северной Дакоте часть, посвящённая базовому управлению транспортным средством, в первую очередь проверяет какие навыки?","options":["Манёвры, такие как движение задним ходом по прямой, парковка/стыковка и контролируемый поворот","Чтение дорожных знаков по памяти","Расчёт ограничений нагрузки на мосты","Ответы на устные вопросы по hazmat"],"explanation":"Часть, посвящённая базовому управлению транспортным средством, проверяет манёвры управления на низкой скорости, такие как движение задним ходом по прямой, стыковка в нишу, параллельная парковка и точный поворот. Источник: ND CDL Manual; формат практического экзамена NDDOT."}},"tr":{"0":{"q":"Kuzey Dakota karayollarında, bir aracın ve yükünün izin verilen yasal toplam dış genişliği en fazla ne kadardır?","options":["8 feet 6 inches","8 feet","9 feet","10 feet"],"explanation":"Kuzey Dakota, yük dahil toplam dış araç genişliğini tüm karayollarında 8 feet 6 inches ile sınırlandırır (NDCC 39-12-04; NDHP Motor Carrier Operations Legal Size and Weight Guide, Ref 9-1, Sec. A). Bundan daha geniş bir yük izin (permit) gerektirir."},"1":{"q":"Kuzey Dakota karayollarında, yüklü ya da yüksüz bir aracın izin verilen yasal yüksekliği en fazla ne kadardır?","options":["13 feet 6 inches","14 feet","13 feet","15 feet"],"explanation":"Kuzey Dakota, yüklü ya da yüksüz olmasına bakılmaksızın izin verilen azami araç yüksekliğini 14 feet olarak belirler; ancak sürücü, 14 feet'ten alçak köprü ve alt geçitlerin altından geçiş açıklığını yine de sağlamak zorundadır (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. B)."},"2":{"q":"Kuzey Dakota'da, yükü dahil bir treyler veya yarı treylerin azami uzunluğu nedir (1 Temmuz 1987'den sonra tescil edilen üniteler için)?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"Yükü dahil bir treyler veya yarı treyler, Kuzey Dakota'da 53 feet'i aşamaz; eyalette 1 Temmuz 1987'den önce tescil edilen ve ruhsatlandırılan treylerler/yarı treylerler ve çekilen araçlar 60 feet'e ulaşabilir (NDCC 39-12-04; NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.4)."},"3":{"q":"Kuzey Dakota'daki Interstate karayolu sisteminde izin verilen azami brüt araç ağırlığı nedir?","options":["85,500 pounds","90,000 pounds","80,000 pounds","105,500 pounds"],"explanation":"Kuzey Dakota'daki Interstate karayolu sisteminde azami brüt araç ağırlığı, federal Interstate sınırıyla uyumlu olarak 80,000 pounds'tur (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.b)."},"4":{"q":"Kuzey Dakota'da, tek bir aks en fazla kaç pound brüt ağırlık taşıyabilir?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"explanation":"Kuzey Dakota, tek bir aksı azami 20,000 pounds brüt ağırlıkla sınırlandırır (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.b). Aralarındaki mesafe 40 inches veya daha az olan akslar tek aks olarak sayılır."},"5":{"q":"Kuzey Dakota'nın bir tandem aks için izin verdiği azami brüt ağırlık nedir?","options":["32,000 pounds","36,000 pounds","40,000 pounds","34,000 pounds"],"explanation":"Kuzey Dakota'da bir tandem aksın brüt ağırlığı, federal tandem aks sınırıyla aynı olarak 34,000 pounds'u aşamaz (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.c)."},"6":{"q":"Kuzey Dakota'da, yükü dahil iki veya daha fazla akslı tek üniteli bir aracın azami uzunluğu nedir?","options":["40 feet","45 feet","50 feet","53 feet"],"explanation":"Yükü dahil iki veya daha fazla akslı tek üniteli bir araç, Kuzey Dakota'da 50 feet'i aşamaz (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.1)."},"7":{"q":"Kuzey Dakota'da Interstate sistemi DIŞINDAKİ karayollarında, aralarında 8 feet veya daha fazla mesafe bulunan iki bağımsız aks için izin verilen azami brüt ağırlık nedir?","options":["34,000 pounds","36,000 pounds","40,000 pounds","44,000 pounds"],"explanation":"Interstate sistemi dışındaki karayollarında, aralarında 8 feet veya daha fazla mesafe bulunan iki bağımsız aksın toplam brüt ağırlığı Kuzey Dakota'da 40,000 pounds'u aşamaz (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.b)."},"8":{"q":"Kuzey Dakota'da belirlenmiş (designated) olmayan karayollarında, yük dahil iki, üç veya dört üniteli bir kombinasyonun azami uzunluğu nedir?","options":["65 feet","70 feet","75 feet","85 feet"],"explanation":"Yük dahil iki, üç veya dört üniteli bir kombinasyon, Kuzey Dakota'nın belirlenmemiş karayollarında 75 feet'i aşamaz; NDDOT tarafından belirlenmiş dört şeritli bölünmüş karayollarında bu tür kombinasyonlar 95 veya 110 feet'e ulaşabilir (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.2 ve C.3)."},"9":{"q":"Kuzey Dakota eyalet karayollarında (Interstate dışında), azami brüt araç ağırlığı genellikle 80,000 pounds'tur; ancak güzergah daha fazlası için belirlenmişse, aşılamayacak üst sınır nedir?","options":["100,000 pounds","105,500 pounds","110,000 pounds","129,000 pounds"],"explanation":"Interstate dışındaki Kuzey Dakota karayollarında azami brüt araç ağırlığı 80,000 pounds'tur; ancak karayolu daha fazlası için belirlenmişse, bu durumda 105,500 pounds'u aşamaz (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.2.a)."},"10":{"q":"Kuzey Dakota'da uygulanan federal köprü formülüne göre, iki ardışık tandem aks takımının her biri 34,000 pounds taşıyabilir; bunun için o tandem takımlarının ilk ve son aksları arasındaki mesafenin en az kaç feet olması gerekir?","options":["30 feet","34 feet","36 feet","40 feet"],"explanation":"Kuzey Dakota, W = 500(LN/(N-1) + 12N + 36) köprü formülünü uygular; ancak iki ardışık tandem aks takımının ilk ve son aksları arasındaki toplam mesafe en az 36 feet ise her biri 34,000 pounds taşıyabilir (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.a)."},"11":{"q":"Kuzey Dakota'nın W = 500(LN/(N-1) + 12N + 36) köprü formülünde N harfi neyi temsil eder?","options":["Gruptaki aks sayısını","Aks uçları arasındaki mesafeyi","Yükün net ağırlığını","Pound cinsinden azami ağırlığı"],"explanation":"Kuzey Dakota'nın köprü formülünde W bir aks grubuna uygulanan azami ağırlık, L grubun uçları arasındaki feet cinsinden mesafe ve N gruptaki aks sayısıdır (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.a)."},"12":{"q":"Kuzey Dakota'da Interstate sistemi dışındaki karayollarında, üç veya daha fazla aksdan oluşan bir grup için izin verilen azami brüt ağırlık nedir?","options":["42,000 pounds","51,000 pounds","54,000 pounds","48,000 pounds"],"explanation":"Kuzey Dakota'da Interstate sistemi dışındaki karayollarında, üç veya daha fazla aksdan oluşan bir grubun brüt ağırlığı 48,000 pounds'u aşamaz; Interstate üzerinde ise grup, köprü formülüne tabidir (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.c)."},"13":{"q":"Kuzey Dakota'da tek seferlik aşırı boyut/aşırı ağırlık (oversize/overweight) izni ne zaman gereklidir?","options":["Tehlikeli madde taşıyan herhangi bir ticari araç için","Yalnızca hava karardıktan sonra Interstate üzerinde seyahat eden yükler için","Kuzey Dakota'nın yasal boyut ve/veya ağırlık sınırlarını aşan, bölünemeyen bir yük için","26,001 pounds'tan ağır herhangi bir araç için"],"explanation":"Kuzey Dakota, eyaletin yasal araç boyut ve ağırlık sınırlarını aşan, bölünemeyen aşırı boyutlu ve/veya aşırı ağırlıklı bir yük hareketi için tek seferlik aşırı boyut/aşırı ağırlık izni gerektirir (NDHP Oversize/Overweight Permit, e-permits)."},"14":{"q":"Kuzey Dakota'da tek seferlik aşırı boyut/aşırı ağırlık izni, tek bir yük hareketi için ne kadar süre geçerlidir?","options":["24 saate kadar","3 güne kadar","5 güne kadar","7 güne kadar"],"explanation":"Kuzey Dakota tek seferlik aşırı boyut/aşırı ağırlık izni, tek bir yük hareketi için 5 güne kadar geçerlidir (NDHP Oversize/Overweight Permit, nd.gov/ndhp adresindeki e-permits sistemi)."},"15":{"q":"Kuzey Dakota'nın hasat ağırlık muafiyeti izni, tarladan ilk depolama veya ilk satış noktasına hasat edilmiş bir tarım ürünü taşıyan bir aracın ne kadar ek ağırlık taşımasına izin verir?","options":["yüzde 5 daha fazla ağırlık","yüzde 10 daha fazla ağırlık","yüzde 15 daha fazla ağırlık","yüzde 20 daha fazla ağırlık"],"explanation":"Kuzey Dakota'nın hasat ağırlık muafiyeti izni, hasat edilmiş bir ürünü tarladan ilk depolama veya ilk satış noktasına taşırken %10 daha fazla ağırlığa izin verir; 15 Temmuz ile 30 Kasım arasında geçerlidir ve brüt ağırlık 105,500 pounds'u aşamaz (NDHP e-permits, Harvest Weight Exemption Permit)."},"16":{"q":"Kuzey Dakota'nın hasat ağırlık muafiyeti izni hangi tarih aralığında geçerlidir?","options":["1 Mayıs - 30 Eylül","1 Haziran - 31 Ekim","15 Temmuz - 30 Kasım","1 Ağustos - 31 Aralık"],"explanation":"Kuzey Dakota'nın hasat ağırlık muafiyeti izni, hasat edilmiş ürünleri tarladan ilk depolama veya ilk satış noktasına taşımak için 15 Temmuz ile 30 Kasım arasında geçerlidir (NDHP e-permits, Harvest Weight Exemption Permit)."},"17":{"q":"Kuzey Dakota'da, gün doğumu ile gün batımı arasında yerleşik bir çiftçi tarafından taşınan bir tarım aracı (implement of husbandry) (Interstate üzerinde olmamak kaydıyla) normal 14 feet'lik yükseklik sınırını en fazla hangi yüksekliğe kadar aşabilir?","options":["14 feet 6 inches","15 feet","15 feet 6 inches","16 feet"],"explanation":"Kuzey Dakota, yerleşik çiftçiler, çiftlik sahipleri, bayiler veya üreticiler tarafından gün doğumu ile gün batımı arasında, 60 mil'i aşmayan bir mesafe boyunca ve Interstate üzerinde olmamak kaydıyla taşınan tarım araçlarının (implements of husbandry) 15 feet 6 inches yüksekliğe ulaşmasına izin verir (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. B.2.a)."},"18":{"q":"Esas olarak doğal gazla çalışan bir Kuzey Dakota aracı, brüt ağırlık sınırını ne kadar ve hangi azami değere kadar aşabilir?","options":["1,000 pounds'a kadar, azami 81,000 pounds","2,000 pounds'a kadar, azami 82,000 pounds","2,500 pounds'a kadar, azami 82,500 pounds","4,000 pounds'a kadar, azami 84,000 pounds"],"explanation":"Esas olarak doğal gazla çalışan bir motorla işletilen bir Kuzey Dakota aracı, daha ağır yakıt sistemini telafi etmek amacıyla ağırlık sınırını 2,000 pounds'a kadar, azami 82,000 pounds brüt ağırlığa kadar aşabilir (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.8)."},"19":{"q":"Kuzey Dakota'da, direksiyon aksı (steering axle) ağırlığı üreticinin aks değerine göre belirlenir; ancak Interstate sisteminde seyahat ederken kaç pound'u aşamaz?","options":["12,000 pounds","18,000 pounds","20,000 pounds","24,000 pounds"],"explanation":"Kuzey Dakota, direksiyon aksını üreticinin aks değeriyle sınırlandırır; Interstate sisteminde bu değer 20,000 pounds'u aşamaz ve hiçbir lastik, lastik genişliğinin her inch'i başına 550 pounds'u geçemez (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.a)."},"20":{"q":"Kuzey Dakota'da, çekilen araç(lar)ın GVWR'si 10,000 pounds'tan fazla olmak kaydıyla, brüt kombinasyon ağırlık değeri (GCWR) 26,001 pounds veya daha fazla olan herhangi bir araç kombinasyonunu kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Kuzey Dakota'nın CDL Class A'sı (kombinasyon aracı), çekilen ünitenin GVWR'si 10,000 lbs'yi aştığında GCWR'si 26,001 lbs veya daha fazla olan herhangi bir araç kombinasyonunu kapsar. Kaynak: NDDOT Commercial Driver License sayfası ve ND CDL Manual; 49 CFR 383.91."},"21":{"q":"Kuzey Dakota kurallarına göre, Class B CDL bir sürücüye aşağıdakilerden hangisini kullanma yetkisi verir?","options":["GVWR'si 26,001 lbs veya daha fazla olan ve GVWR'si 10,000 lbs'yi aşmayan bir ünite çeken herhangi bir tek araç","Çekilen ünitesi 10,000 lbs'yi aşan, 26,001 lbs GCWR'nin üzerindeki herhangi bir araç kombinasyonu","Yalnızca 16 veya daha fazla yolcu taşımak için tasarlanmış araçlar","Yalnızca plakart gerektiren tehlikeli madde taşıyan, 26,001 lbs GVWR'nin altındaki araçlar"],"explanation":"ND Class B (ağır düz araç), GVWR'si 26,001 lbs veya daha fazla olan herhangi bir tek aracı ya da GVWR'si 10,000 lbs'yi aşmayan bir ünite çeken böyle bir aracı kapsar. Kaynak: NDDOT Commercial Driver License sayfası ve ND CDL Manual; 49 CFR 383.91."},"22":{"q":"Bir Kuzey Dakota sürücüsü, GVWR'si 26,001 lbs'nin altında olan ve 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış tek bir aracı kullanır. Hangi CDL sınıfı geçerlidir?","options":["Class C","Class A","Class B","CDL gerekli değildir"],"explanation":"ND Class C (küçük araç), GVWR'si 26,001 lbs'nin altında olan ve 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış ya da plakart gerektiren tehlikeli madde taşıyan tek araçlar için geçerlidir. Kaynak: NDDOT Commercial Driver License sayfası ve ND CDL Manual; 49 CFR 383.91."},"23":{"q":"Kalıcı olarak monte edilmiş bir tankta, bireysel kapasitesi 119 gallon'dan fazla (ve toplamda 1,000 gallon veya daha fazla) olan sıvı veya gaz taşımak için kullanılan bir tank aracını kullanmak için hangi Kuzey Dakota CDL onayı (endorsement) gereklidir?","options":["N (Tank Araçları)","H (Tehlikeli Maddeler)","T (İkili/Üçlü)","P (Yolcu)"],"explanation":"ND'de, bireysel olarak 119 gallon'dan fazla ya da toplamda 1,000 gallon veya daha fazla değerlendirilmiş bir tankta sıvı veya gaz taşımak için N onayı gereklidir. Kaynak: NDDOT Commercial Driver License sayfası; 49 CFR 383.93."},"24":{"q":"Kuzey Dakota'da, ikili veya üçlü treyler çekmek için bir CDL sahibinin hangi onayı alması gerekir?","options":["T (İkili/Üçlü)","N (Tank Araçları)","X (Tank/HazMat kombinasyonu)","P (Yolcu)"],"explanation":"T onayı, Kuzey Dakota'da ikili veya üçlü treyler çekme yetkisi verir ve ikili/üçlü bilgi testini geçerek alınır. Kaynak: NDDOT Commercial Driver License sayfası ve ND CDL Manual; 49 CFR 383.93."},"25":{"q":"Yalnızca eyalet içi (INTRASTATE) sürüş için geçerli bir Kuzey Dakota CDL'si almak için asgari yaş nedir (Kuzey Dakota içinde)?","options":["18 yaşında","16 yaşında","19 yaşında","21 yaşında"],"explanation":"Kuzey Dakota, yalnızca eyalet içi sürüş için 18 yaşında CDL alınmasına izin verir. Sürücülerin eyaletler arası ticarette çalışmak için 21 yaşında olması gerekir. Kaynak: NDDOT CDL gereklilikleri; NDCC Title 39; 49 CFR 383."},"26":{"q":"Eyaletler arası ticarette araç kullanmak, tehlikeli madde taşımak veya ücret karşılığında yolcu taşımak isteyen bir Kuzey Dakota CDL başvuru sahibinin en az kaç yaşında olması gerekir?","options":["21 yaşında","18 yaşında","19 yaşında","25 yaşında"],"explanation":"Kuzey Dakota, bir sürücünün eyalet sınırlarını aşarak (eyaletler arası) araç kullanması, tehlikeli madde taşıması ya da ücret karşılığında yolcu taşıması için en az 21 yaşında olmasını şart koşar. Kaynak: NDDOT CDL gereklilikleri; 49 CFR 383."},"27":{"q":"Bir Kuzey Dakota Ticari Öğrenci İzni (CLP) verildikten sonra, başvuru sahibinin CDL beceri (yol) testine girmeye uygun hale gelmesi için ne kadar beklemesi gerekir?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"Kuzey Dakota, başvuru sahibinin CDL beceri testine girebilmesi için CLP'nin en az 14 gün elde tutulmasını gerektiren federal kuralı izler. Kaynak: NDDOT CDL başvuru sayfası; 49 CFR 383.25."},"28":{"q":"Kuzey Dakota'da bir Tehlikeli Maddeler (H) onayı almadan önce, başvuru sahibinin hangi federal olarak zorunlu kılınan geçmiş taramasını geçmesi gerekir?","options":["Parmak izi alınması dahil bir TSA güvenlik tehdidi değerlendirmesi","Parmak izi olmadan yalnızca FBI tarafından yapılan bir suç geçmişi kontrolü","Eyalet tarafından yürütülen bir yalan makinesi sınavı","Yalnızca işveren tarafından yapılan bir referans kontrolü"],"explanation":"ND'de H onayı başvuru sahiplerinin, onay eklenmeden önce parmak izi vermeyi içeren TSA güvenlik tehdidi değerlendirmesini tamamlaması gerekir. Kaynak: NDDOT Hazardous Material Requirements sayfası; 49 CFR 1572 / TSA."},"29":{"q":"Bir Kuzey Dakota başvuru sahibinin YENİ bir Tehlikeli Maddeler (H) onayı için bilgi testine girebilmesinden önce artık zorunlu olan giriş seviyesi eğitim adımı hangisidir?","options":["FMCSA Training Provider Registry'de yer alan bir sağlayıcıdan alınan federal ELDT hazmat teori eğitimi","40 saatlik kabin içi tanker çıraklığı","Kuzey Dakota eyaleti tarafından işletilen bir hazmat akademisi kursu","Eğitim gerekli değildir, yalnızca bilgi testi"],"explanation":"ND'de ilk kez H onayı alacak başvuru sahipleri, bilgi testinden önce FMCSA Training Provider Registry'de listelenen bir sağlayıcıdan federal olarak zorunlu kılınan hazmat teori Giriş Seviyesi Sürücü Eğitimini (ELDT) tamamlamak zorundadır. Kaynak: NDDOT Hazardous Material Requirements sayfası; 49 CFR 380."},"30":{"q":"İlk Kuzey Dakota Class A CDL'sini almadan önce gereken Giriş Seviyesi Sürücü Eğitiminin (ELDT) hangi sistem üzerinden tamamlanması gerekir?","options":["FMCSA Training Provider Registry'de listelenen bir sağlayıcı","Herhangi bir Kuzey Dakota community college, federal listeye dahil olmadan","NDDOT'un kendi sürücü akademisi","Sürücünün seçeceği herhangi bir eyalet dışı kamyon taşımacılığı işvereni"],"explanation":"ND, ilk Class A CDL için beceri testinden önce ELDT'nin FMCSA Training Provider Registry'de listelenen bir okul veya kuruluş aracılığıyla tamamlanmasını gerektirir. Kaynak: NDDOT How to Apply for a CDL sayfası; 49 CFR 380 Subpart F."},"31":{"q":"Bir Kuzey Dakota sürücüsünün, sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış bir aracı (okul otobüsü dışında) kullanmak için hangi onaya ihtiyacı vardır?","options":["P (Yolcu)","S (Okul Otobüsü)","N (Tank)","T (İkili/Üçlü)"],"explanation":"P (Yolcu) onayı, sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış bir otobüsü veya başka bir aracı kullanmak için gereklidir. Bir okul otobüsü ayrıca ayrı bir S onayı da gerektirir. Kaynak: ND CDL Manual; 49 CFR 383.93."},"32":{"q":"Bir Kuzey Dakota CDL'sine Okul Otobüsü (S) onayı eklemek için, sürücünün AYRICA hangi onaya sahip olması gerekir?","options":["P (Yolcu)","N (Tank)","H (Tehlikeli Maddeler)","T (İkili/Üçlü)"],"explanation":"Kuzey Dakota'da S (Okul Otobüsü) onayı, sürücünün önce P (Yolcu) onayına sahip olmasını ve okul otobüsü bilgi ve beceri testlerini geçmesini gerektirir. Kaynak: ND CDL Manual; 49 CFR 383.93."},"33":{"q":"Bir Kuzey Dakota CDL'sine başvururken, başvuru sahibinin bir Sosyal Güvenlik numarası kanıtı sunması gerekir. Aşağıdakilerden hangisi kabul edilebilir bir belgedir?","options":["Orijinal Sosyal Güvenlik kartı","Sosyal Güvenlik kartının bir fotokopisi","SSN'yi listeleyen el yazısı bir not","Numarayı gösteren bir kütüphane kartı"],"explanation":"ND, orijinal Sosyal Güvenlik kartı gibi Sosyal Güvenlik numarasının kanıtını gerektirir; fotokopiler kabul edilmez ve belgeler orijinal veya onaylı (certified) olmalıdır. Kaynak: NDDOT Driver License Requirements / REAL ID kontrol listesi."},"34":{"q":"Kuzey Dakota, başvuru sahibinin Kuzey Dakota'daki ikametgah adresini kanıtlaması için kaç adet ikamet kanıtı belgesi sunmasını gerektirir?","options":["İki belge","Bir belge","Üç belge","İkamet kanıtı gerekli değildir"],"explanation":"Kuzey Dakota, başvuru sahibinin Kuzey Dakota'daki ikamet adresini kanıtlayan iki belge gerektirir (örneğin, fatura/finansal belgeler, vergi kayıtları). Kaynak: NDDOT Driver License Requirements / REAL ID kontrol listesi."},"35":{"q":"Kimlik, Sosyal Güvenlik numarası ve ikametin yanı sıra, bir Kuzey Dakota CDL başvuru sahibinin hangi ek kanıtı sunması gerekir?","options":["ABD vatandaşlığı, yasal daimi ikamet veya yasal/geçici mevcudiyet kanıtı","Mevcut bir işverenden noter onaylı bir mektup","Araç sahipliği kanıtı","Bir lise diploması"],"explanation":"ND, kimlik, SSN ve ikamete ek olarak Amerika Birleşik Devletleri'nde vatandaşlık, yasal daimi ikamet veya yasal mevcudiyet kanıtı gerektirir. Kaynak: NDDOT Driver License Requirements sayfası."},"36":{"q":"Eyaletler arası ticarette araç kullanan ve bir Tıbbi Muayene Görevlisi Sertifikası (Medical Examiner's Certificate) taşıması gereken bir Kuzey Dakota CDL başvuru sahibi, hangi kategori altında öz-belgeleme (self-certify) yapar?","options":["Eyaletler arası, istisna dışı (NI)","Eyaletler arası, istisnalı (EI)","Eyalet içi, istisna dışı (NA)","Eyalet içi, istisnalı (EA)"],"explanation":"Federal fiziksel uygunluk standartlarını karşılamak zorunda olan, eyaletler arası ticaretteki sürücüler Eyaletler Arası İstisna Dışı (Interstate Non-Excepted) olarak öz-belgeleme yapar ve ND'de dosyada geçerli bir Tıbbi Muayene Görevlisi Sertifikası bulundurmak zorundadır. Kaynak: NDDOT CDL öz-belgeleme; 49 CFR 383.71 / 391."},"37":{"q":"Bir Kuzey Dakota CDL sahibi, faaliyet gösterdiği ticaret türünü belgelendirirken kaç adet tıbbi öz-belgeleme kategorisi arasından seçim yapmak zorundadır?","options":["Dört (eyaletler arası istisna dışı, eyaletler arası istisnalı, eyalet içi istisna dışı, eyalet içi istisnalı)","İki (yalnızca eyaletler arası ve eyalet içi)","Üç (eyaletler arası, eyalet içi ve muaf)","Beş (her CDL onayı için bir tane)"],"explanation":"ND tarafından benimsenen federal kurallar, dört öz-belgeleme kategorisinden birinin seçilmesini gerektirir: eyaletler arası istisna dışı, eyaletler arası istisnalı, eyalet içi istisna dışı veya eyalet içi istisnalı. Kaynak: NDDOT CDL öz-belgeleme; 49 CFR 383.71."},"38":{"q":"Kuzey Dakota'nın izlediği federal standarda göre, bir Ticari Öğrenci İzni (CLP), bilgi testleri tekrar alınmadan yenilenmesi gerekmeden önce en fazla ne kadar süre geçerli olabilir?","options":["180 gün","30 gün","12 ay","5 yıl"],"explanation":"Bir CLP, 180 güne kadar geçerlidir ve bir yıllık süre içinde yeniden test yapılmadan bir kez daha 180 gün için yenilenebilir; ND, CLP'leri bu federal standart kapsamında düzenler. Kaynak: ND CDL Manual; 49 CFR 383.25."},"39":{"q":"Bir Kuzey Dakota CDL başvuru sahibinin beceri (yol) testini ne tür bir araçta yapması gerekir?","options":["Başvuru sahibinin kullanmayı düşündüğü sınıf ve türü temsil eden bir araç","Başvuru sahibine ait herhangi bir binek otomobil","NDDOT muayene görevlisi tarafından sağlanan bir araç","Talep edilen lisanstan bağımsız olarak yalnızca bir Class A kombinasyon"],"explanation":"ND, beceri testinin başvuru sahibinin kullanmayı düşündüğü sınıf ve yapılandırmayı (okul otobüsü veya tank gibi onaylar dahil) temsil eden bir araçta yapılmasını gerektirir. Kaynak: NDDOT CDL başvuru sayfası; 49 CFR 383.71/383.113."},"40":{"q":"Kuzey Dakota'da, bir sürücünün ticari motorlu araç (CMV) kullanırken etki altında sayılması ve diskalifiye edilmeye tabi tutulması hangi kandaki alkol konsantrasyonunda (BAC) gerçekleşir?","options":["0.04 veya daha yüksek","0.08 veya daha yüksek","0.02 veya daha yüksek","0.10 veya daha yüksek"],"explanation":"Kuzey Dakota federal standardı izler: 0.04 veya daha yüksek bir BAC ile CMV kullanmak, bir CDL sahibini diskalifiye eden bir alkol suçudur. Bu, ticari olmayan sürüşe uygulanan 0.08 sınırının yarısıdır. Kaynak: NDDOT Commercial Driver License Manual (Disqualification); NDCC 39-06.2-10.1."},"41":{"q":"Kuzey Dakota'nın zımni rıza (implied-consent) yasası uyarınca, bir CMV kullanırken alkol için kimyasal teste girmeyi reddeden bir CDL sahibine ne olur?","options":["Bir DUI mahkumiyetiyle aynı şekilde değerlendirilir ve sürücüyü diskalifiye eder","İlk ret için yalnızca bir uyarı ile sonuçlanır","Bir DUI mahkumiyetinden daha küçük bir ceza taşır","Yalnızca 30 günlük bir askıyla sonuçlanır"],"explanation":"Kimyasal teste girmeyi reddetmek, CDL açısından bir alkol/DUI mahkumiyetiyle aynı şekilde değerlendirilir. İlk ret, ilk büyük suçla aynı şekilde sürücüyü en az bir yıl diskalifiye eder. Kaynak: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.1."},"42":{"q":"Tehlikeli madde taşınMADIĞINDA, bir CMV'de DUI gibi ilk büyük suç için Kuzey Dakota'daki asgari CDL diskalifiye süresi nedir?","options":["1 yıl","60 gün","6 ay","3 yıl"],"explanation":"İlk büyük suç (örneğin, 0.04 veya daha yüksek BAC ile CMV kullanmak, DUI veya testi reddetmek) sürücüyü en az bir yıl diskalifiye eder. Kaynak: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10; 49 CFR 383.51."},"43":{"q":"Kuzey Dakota'da, CMV plakart gerektiren tehlikeli madde taşırken işlenen ilk büyük suç için asgari CDL diskalifiyesi nedir?","options":["3 yıl","1 yıl","5 yıl","120 gün"],"explanation":"İlk büyük suç, tehlikeli maddeler için plakartlı bir CMV kullanılırken işlenirse, diskalifiye süresi bir yıldan en az üç yıla çıkar. Kaynak: NDDOT CDL Manual (Disqualification); 49 CFR 383.51."},"44":{"q":"Kuzey Dakota'da ikinci bir büyük suç (örneğin, bir CMV'de ikinci bir DUI) için CDL diskalifiye süresi nedir?","options":["Ömür boyu","10 yıl","3 yıl","5 yıl"],"explanation":"Herhangi bir büyük suçtan ikinci kez, herhangi bir kombinasyonda mahkumiyet, ömür boyu CDL diskalifiyesiyle sonuçlanır. Kaynak: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10; 49 CFR 383.51."},"45":{"q":"Bir Kuzey Dakota CDL sahibi, kontrollü bir maddenin üretimi veya dağıtımıyla ilgili bir suç (felony) işlemek için bir aracı kullanmaktan mahkum edilir. Hangi diskalifiye uygulanır?","options":["Yeniden alma (reinstatement) imkanı olmaksızın ömür boyu diskalifiye","1 yıllık diskalifiye","3 yıllık diskalifiye","60 günlük diskalifiye"],"explanation":"Kontrollü bir maddenin üretimi, dağıtımı veya dağıtılmasıyla ilgili bir suç işlemek için bir CMV kullanmak, yeniden alınamayan ömür boyu diskalifiyeyle sonuçlanır. Kaynak: NDDOT CDL Manual (Disqualification); 49 CFR 383.51."},"46":{"q":"Kuzey Dakota'da 3 yıllık bir süre içinde kaç ciddi trafik ihlali, 60 günlük bir CDL diskalifiyesini tetikler?","options":["2 (3 yıl içinde ikincisi)","1 (ilk ihlal)","3 (3 yıl içinde üçüncüsü)","4 (3 yıl içinde dördüncüsü)"],"explanation":"3 yıllık bir süre içinde, ayrı olaylardan kaynaklanan ikinci bir ciddi trafik ihlali, en az 60 günlük bir diskalifiyeyle sonuçlanır. Kaynak: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.5; 49 CFR 383.51."},"47":{"q":"Kuzey Dakota'da, 3 yıllık bir süre içinde üç ciddi trafik ihlali en az ne kadar süreyle bir CDL diskalifiyesiyle sonuçlanır?","options":["120 gün","60 gün","1 yıl","180 gün"],"explanation":"3 yıllık bir süre içinde (ayrı olaylardan) üçüncü bir ciddi trafik ihlali, en az 120 günlük bir diskalifiyeyle sonuçlanır. Kaynak: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.5; 49 CFR 383.51."},"48":{"q":"Kuzey Dakota'da CDL diskalifiye amaçları açısından aşağıdakilerden hangisi CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["Belirtilen hız sınırının 15 mph veya daha fazla üzerinde hız yapmak","0.04 veya daha yüksek BAC ile bir CMV kullanmak","Zımni rıza kapsamında kimyasal testi reddetmek","Bir kaza yerini terk etmek"],"explanation":"Aşırı hız (sınırın 15 mph veya daha fazla üzerinde) ciddi bir trafik ihlalidir. Listelenen diğer suçlar, çok daha uzun diskalifiyeler taşıyan büyük suçlardır. Kaynak: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.5; 49 CFR 383.51."},"49":{"q":"Eyalet veya yerel yasayı ihlal ederek bir CMV kullanırken mesaj yazmak (texting), Kuzey Dakota'da hangi tür diskalifiye edici suç olarak sınıflandırılır?","options":["Ciddi bir trafik ihlali","Büyük bir suç","Bir hizmet dışı (out-of-service) emri ihlali","Bir hemzemin geçit ihlali"],"explanation":"Bir CMV kullanırken mesaj yazmak ciddi bir trafik ihlalidir; 3 yıl içinde iki tanesi 60 günlük bir diskalifiyeye, 3 yıl içinde üç tanesi 120 günlük bir diskalifiyeye yol açar. Kaynak: NDDOT CDL Manual (Disqualification); 49 CFR 383.51; 49 CFR 392.80."},"50":{"q":"Bir CMV kullanırken, kuralı ihlal ederek elde tutulan bir cep telefonu kullanmak Kuzey Dakota'da şu şekilde değerlendirilir:","options":["Ciddi bir trafik ihlali","Küçük bir ekipman ihlali","1 yıl diskalifiye eden büyük bir suç","Bir hizmet dışı emri ihlali"],"explanation":"Bir CMV kullanırken elde tutulan bir cep telefonu kullanmak ciddi bir trafik ihlalidir. 3 yıl içinde iki veya üç tanesinin birikmesi sırasıyla 60 veya 120 günlük diskalifiyelerle sonuçlanır. Kaynak: NDDOT CDL Manual (Disqualification); 49 CFR 383.51; 49 CFR 392.82."},"51":{"q":"Kuzey Dakota'da geçerli olan federal kurala göre, bir CMV sürücüsünün araç kullanırken mesaj yazmak veya elde tutulan bir telefon kullanmaktan karşılaşabileceği azami idari para cezası nedir?","options":["$2,750","$500","$1,000","$5,000"],"explanation":"Bir sürücü, bir CMV kullanırken mesaj yazmak veya elde tutulan bir cep telefonu kullanmak nedeniyle, tekrarlanan ciddi ihlaller için diskalifiyeye ek olarak $2,750'ye kadar bir idari para cezasına tabi olabilir. Kaynak: Kuzey Dakota'da geçerli olan FMCSA dikkat dağınıklığı kuralı (49 CFR 392.80/392.82)."},"52":{"q":"HazMat olmayan, yolcu taşımayan bir CMV kullanırken bir hizmet dışı (OOS) emrini ihlal etmenin İLK mahkumiyeti için Kuzey Dakota'daki asgari CDL diskalifiyesi nedir?","options":["180 gün","60 gün","1 yıl","90 gün"],"explanation":"Bir hizmet dışı emrinin ilk ihlali, en az 180 günlük bir diskalifiyeyle sonuçlanır. Kaynak: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.9; 49 CFR 383.51."},"53":{"q":"Kuzey Dakota'da, 10 yıl içinde İKİNCİ bir hizmet dışı emri ihlali (HazMat olmayan, yolcu taşımayan) en az ne kadar diskalifiyeyle sonuçlanır:","options":["2 yıl","180 gün","1 yıl","3 yıl"],"explanation":"10 yıllık bir süre içinde ikinci bir hizmet dışı emri ihlali, sürücüyü en az 2 yıl diskalifiye eder. Kaynak: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.9; 49 CFR 383.51."},"54":{"q":"Bir Kuzey Dakota CDL sahibi, 10 yıl içinde ÜÇÜNCÜ bir hizmet dışı emri ihlali işler. Asgari diskalifiye nedir?","options":["3 yıl","2 yıl","1 yıl","5 yıl"],"explanation":"10 yıllık bir süre içinde üçüncü veya sonraki bir hizmet dışı emri ihlali, en az 3 yıllık bir diskalifiyeyle sonuçlanır. Kaynak: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.9; 49 CFR 383.51."},"55":{"q":"Plakart gerektiren tehlikeli madde taşırken veya 16 ya da daha fazla yolcu taşımak için tasarlanmış bir araç kullanırken İLK hizmet dışı emri ihlali için asgari CDL diskalifiyesi nedir?","options":["180 gün","90 gün","1 yıl","60 gün"],"explanation":"Plakartlı HazMat taşırken veya 16+ yolcu için tasarlanmış bir araç kullanırken ilk OOS emri ihlali, en az 180 günlük bir diskalifiye taşır (diğer CMV'lerle aynı ilk suç asgarisi, ancak ikinci ve üçüncü suçlar daha uzundur). Kaynak: NDDOT CDL Manual (Disqualification); 49 CFR 383.51."},"56":{"q":"Kuzey Dakota'da İLK bir demiryolu-karayolu hemzemin geçit ihlali için asgari CDL diskalifiyesi nedir?","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"Bir demiryolu-karayolu hemzemin geçit ihlali için ilk mahkumiyet, en az 60 günlük bir diskalifiyeyle sonuçlanır. Kaynak: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.6; 49 CFR 383.51."},"57":{"q":"Bir Kuzey Dakota CDL sahibi, 3 yıl içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali işler. Asgari diskalifiye nedir?","options":["120 gün","60 gün","180 gün","1 yıl"],"explanation":"3 yıllık bir süre içinde ikinci bir demiryolu hemzemin geçit ihlali, en az 120 günlük bir diskalifiyeyle sonuçlanır. Kaynak: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.6; 49 CFR 383.51."},"58":{"q":"Kuzey Dakota'da 3 yıl içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali için asgari diskalifiye nedir?","options":["1 yıl","120 gün","180 gün","60 gün"],"explanation":"3 yıllık bir süre içinde üçüncü veya sonraki bir demiryolu hemzemin geçit ihlali, en az 1 yıllık bir diskalifiyeyle sonuçlanır (kurala göre en az 180 günden 1 yıla kadar, azami değer uygulanır). Kaynak: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.6; 49 CFR 383.51."},"59":{"q":"Kuzey Dakota'daki bir CMV sürücüsünde, 0.04 BAC'nin altında ölçülebilir veya tespit edilebilir miktarda alkol bulunur. Bunun anlık sonucu nedir?","options":["24 saat hizmet dışı bırakılır","Kalıcı olarak diskalifiye edilir","Büyük bir suçla suçlanır","60 günlük bir diskalifiye verilir"],"explanation":"0.04'ün altında herhangi bir ölçülebilir alkol konsantrasyonu olan bir sürücü 24 saat hizmet dışı bırakılmalıdır; 0.04 veya daha yüksek bir BAC, diskalifiye edici büyük bir suçtur. Kaynak: NDDOT CDL Manual (Alcohol/Out-of-Service); 49 CFR 392.5."},"60":{"q":"Bir şehrin dışındaki Kuzey Dakota eyaletler arası karayolunda ilerlerken, sağ banketin üzerinde sarı (amber) yanıp sönen ışıkları açık şekilde duran bir çekiciye yaklaşıyorsunuz. Kuzey Dakota'nın Şerit Değiştir (Move Over) yasası kapsamında, yaklaşan bir ticari aracın sürücüsü ne yapmalıdır?","options":["Yalnızca polis araçları kapsama girdiğinden, ilan edilen hızda devam etmek","Tamamen durmak ve araç uzaklaşana kadar beklemek","Sol bankete geçip durmak","Güvenli bir şekilde yapılabiliyorsa duran aracın bitişiğinde olmayan bir şeride geçmek; aksi takdirde yavaşlayıp dikkatli bir şekilde geçmek"],"explanation":"Kuzey Dakota Century Code 39-10-26, bir şehrin dışındaki eyaletler arası veya çok şeritli karayolunda, sarı/mavi/beyaz/kırmızı ışık gösteren duran bir acil durum veya yol bakım aracının bitişiğinde olmayan bir şeride güvenli bir şekilde yapılabiliyorsa geçmelerini sürücülerden ister; yapılamıyorsa sürücü yavaşlamalı ve güvenli bir hızda dikkatlice devam etmelidir. 2023 yılındaki bir değişiklik, bunu tehlike (dörtlü) ikaz lambalarını gösteren herhangi bir duran araca da genişletti. Kaynak: NDCC 39-10-26; ND Highway Patrol Move Over Law."},"61":{"q":"2023 yılında Kuzey Dakota, Şerit Değiştir (Move Over) yasasını genişletti. Yetkili acil durum ve yol bakım araçlarının yanı sıra, şerit değiştirme veya yavaşlama yükümlülüğü artık hangi duran araca yaklaşırken de geçerlidir?","options":["Yanıp sönen tehlike ikaz sinyallerini gösteren herhangi bir araç","Yalnızca posta dağıtım araçları","Yalnızca mavi ışık gösteren araçlar","Şehir sınırları içinde park etmiş herhangi bir araç"],"explanation":"Kuzey Dakota'nın 2023 yılındaki Şerit Değiştir (Move Over) yasası genişlemesi (NDCC 39-10-26), bir şehrin dışındaki eyaletler arası veya çok şeritli karayolunda yanıp sönen tehlike ikaz sinyallerini gösteren herhangi bir duran motorlu aracı kapsama dahil etti. Kaynak: NDCC 39-10-26; ND Highway Patrol / NDDOT Move Over Law materyalleri."},"62":{"q":"1 Ağustos 2025 itibarıyla, kırsal Kuzey Dakota'daki erişimi kontrollü, asfaltlı, bölünmüş çok şeritli eyaletler arası karayollarında (ilan edildiği yerlerde) yasal azami hız sınırı kaçtır ve kamyonlar için farklı mıdır?","options":["Otomobiller için 75 mph ancak kamyonlar için 65 mph","80 mph, kamyonlar dahil tüm araçlara uygulanır","Tüm araçlar için 70 mph","Otomobiller için 80 mph ancak kamyonlar için 70 mph"],"explanation":"NDCC 39-09-02 (1 Ağustos 2025 tarihinde yürürlüğe giren HB 1298 ile değiştirildiği şekilde) uyarınca, kırsal erişimi kontrollü bölünmüş eyaletler arası karayollarında azami hız 80 mph'dir. Kuzey Dakota, kanunla kamyonlar için ayrı ve daha düşük bir hız sınırı belirlemez, bu nedenle sınır tüm araçlara uygulanır. Kaynak: NDCC 39-09-02; NDDOT / ND Highway Patrol hız sınırı rehberi."},"63":{"q":"Kuzey Dakota yasalarına göre, erişimi kontrollü bir eyaletler arası karayolu OLMAYAN, asfaltlı ve bölünmüş çok şeritli bir karayolundaki azami hız sınırı kaçtır?","options":["55 mph","65 mph","70 mph","80 mph"],"explanation":"NDCC 39-09-02, asfaltlı ve bölünmüş çok şeritli karayollarında (80 mph olan eyaletler arası karayolları dışında) yasal varsayılan azami hız olarak 70 mph belirler. Kaynak: NDCC 39-09-02."},"64":{"q":"Kuzey Dakota'da, ilan edilmiş bir sınırın bulunmadığı çakıl, toprak veya gevşek zeminli karayollarında (ve asfaltlı iki şeritli ilçe ve kasaba karayollarında) varsayılan azami yasal hız nedir?","options":["45 mph","50 mph","55 mph","65 mph"],"explanation":"NDCC 39-09-02, çakıl, toprak veya gevşek zeminli karayollarında ve hiçbir sınırın ilan edilmediği asfaltlı iki şeritli ilçe ve kasaba karayollarında yasal varsayılan azami hız olarak 55 mph belirler. Kaynak: NDCC 39-09-02."},"65":{"q":"Kuzey Dakota'da plakart (tehlikeli madde levhası) taşıyan bir tehlikeli madde ticari aracını kullanan bir sürücü, durulması gereken bir demir yolu hemzemin geçidine yaklaşıyor. Aracı nerede durdurmalıdır?","options":["En yakın raydan 75 feet'e kadar ancak 25 feet'ten az olmamak üzere","En yakın raydan 100 feet'e kadar ancak 50 feet'ten az olmamak üzere","En yakın raydan 50 feet'e kadar ancak 15 feet'ten az olmamak üzere","En yakın raydan 10 feet içinde herhangi bir yerde"],"explanation":"NDCC 39-10-43, plakart taşıyan bir HazMat aracının (ve belirli tank/klor araçlarının) sürücüsünden en yakın raydan 50 feet'e kadar ancak 15 feet'ten az olmamak üzere durmasını, ardından ilerlemeden önce bakıp dinlemesini ister. Kaynak: NDCC 39-10-43; ND CDL Manual."},"66":{"q":"Kuzey Dakota'da, hangi araç kanunen tüm demir yolu hemzemin geçitlerinde (yalnızca tehlikeli olanlarda değil) durmak zorundadır?","options":["Römork çeken herhangi bir araç","Yolcu taşıyan bir otobüs veya okul otobüsü","Çiftçilik için kullanılan herhangi bir kamyonet","Brüt ağırlığı 26.000 pound'un üzerinde olan herhangi bir araç"],"explanation":"NDCC 39-10-43, yolcu taşıyan bir otobüsün, okul otobüsünün ve plakart taşıyan HazMat/belirli tank araçlarının sürücüsünden tüm demir yolu hemzemin geçitlerinde en yakın raydan 50 feet'e kadar ancak 15 feet'ten az olmamak üzere durmasını ister. Kaynak: NDCC 39-10-43."},"67":{"q":"Kuzey Dakota'da bir demir yolu geçidinde gerektiği gibi durduktan sonra, kanun, rayları geçerken bir otobüs veya HazMat sürücüsüne hangi ek kısıtlamayı getirir?","options":["Sürücü, geçiş yaparken kornaya sürekli basmalıdır","Sürücü, rayların üzerinden geçerken vites kolunu elle değiştirmemelidir","Sürücü, geçiş yaparken dörtlü ikaz lambalarını yakmalıdır","Sürücü, mevcut en yüksek viteste geçiş yapmalıdır"],"explanation":"NDCC 39-10-43, sürücüyü yalnızca geçidin üzerindeyken vites değiştirme ihtiyacını ortadan kaldıracak bir viteste geçiş yapmaya yönlendirir ve sürücü, rayların üzerinden geçerken vitesi elle değiştiremez. Kaynak: NDCC 39-10-43; ND CDL Manual."},"68":{"q":"Kuzey Dakota'nın demir yolu geçitlerinde otobüsler ve HazMat araçları için durmayı zorunlu kılan kuralı kapsamında, ne zaman durmak GEREKLİ DEĞİLDİR?","options":["Araç boş olduğunda","Trafik bir polis memuru tarafından yönlendirildiğinde veya 'Exempt' (Muaf) ya da 'Tracks out of service' (Raylar hizmet dışı) olarak işaretlenmiş bir geçitte","Sürücünün bir yıldan fazla deneyimi olduğunda","Geçit bir ticari bölgede olduğunda"],"explanation":"NDCC 39-10-43, trafik bir polis memuru tarafından yönlendirildiğinde ve müdürün 'Exempt' (Muaf) veya 'Tracks out of service' (Raylar hizmet dışı) olarak belirlediği ve açıkça işaretlediği geçitlerde durma zorunluluğunu kaldırır. Kaynak: NDCC 39-10-43."},"69":{"q":"Bir Kuzey Dakota okul otobüsü, çocukları almak için yanıp sönen kırmızı ışıkları ve dur kolu (stop arm) açık şekilde durmaktadır. Bir ticari sürücü, iki şeritli bir yolda karşı yönden yaklaşmaktadır. Sürücü ne yapmalıdır?","options":["20 mph'ye yavaşlayıp dikkatli bir şekilde geçmek","Yalnızca soldan, düşük hızda geçmek","Devam etmek, çünkü karşı yöndeki trafiğin durması hiçbir zaman gerekmez","Otobüse ulaşmadan önce durmak ve ışıklar ile dur kolu artık etkin değilken devam etmek"],"explanation":"NDCC 39-10-46, yanıp sönen kırmızı ışıklar veya dur kolu etkinken her iki yönden bir okul otobüsüyle karşılaşan veya onu geçen bir sürücünün ona ulaşmadan önce durmasını ve otobüs hareket edene, sürücüye ilerlemesi için işaret verilene ya da ışıklar ile kol artık etkin olmayana kadar ilerlememesini ister. Kaynak: NDCC 39-10-46."},"70":{"q":"Kuzey Dakota'nın okul otobüsü için durma yasası, bölünmüş karayolu istisnası içerir. NDCC 39-10-46 uyarınca, bir sürücünün duran bir okul otobüsü için durmasına gerek OLMADIĞI tek durum şudur:","options":["Sürücünün gittiği yönde iki veya daha fazla şerit bulunduğunda","Otobüs, ayrı taşıt yolları bulunan bir karayolunun farklı bir taşıt yolunda olduğunda veya sürücü erişimi kontrollü bir karayolundayken otobüs, yayaların geçemeyeceği bir biniş bölgesinde olduğunda","Sürücü ile otobüs arasında merkezi iki yönlü sola dönüş şeridi bulunduğunda","Yolda boyalı bir orta çizgi olduğunda"],"explanation":"NDCC 39-10-46(5) uyarınca, istisna yalnızca otobüs, ayrı (fiziksel olarak bölünmüş) taşıt yolları bulunan bir karayolunun FARKLI bir taşıt yolunda olduğunda veya otobüsün bir biniş bölgesinde olduğu ve yayaların geçemeyeceği erişimi kontrollü bir karayolunda geçerlidir. Yalnızca bir orta dönüş şeridi veya boyalı bir çizgi nitelik kazandırmaz. Kaynak: NDCC 39-10-46."},"71":{"q":"Bölünmemiş dört şeritli bir Kuzey Dakota yolunda (her yönde iki şerit, yalnızca boyalı bir orta çizgiyle ayrılmış), karşı yönde giden bir okul otobüsü yanıp sönen kırmızı ışıklarıyla durur. Karşı yönden gelen trafik durmak zorunda mıdır?","options":["Hayır, çünkü birden fazla şerit vardır","Hayır, karşı yönden gelen trafik dört şeritli bir yolda hiçbir zaman durmaz","Yalnızca otobüse en yakın şeridin durması gerekir","Evet, çünkü taşıt yolu fiziksel olarak ayrı taşıt yollarına bölünmemiştir"],"explanation":"NDCC 39-10-46'nın istisnası yalnızca ayrı (fiziksel olarak bölünmüş) taşıt yolları bulunan karayollarında geçerlidir. Yalnızca boyalı bir orta çizgisi olan bölünmemiş çok şeritli bir yolda, karşı yönden gelen trafik yanıp sönen kırmızı ışıkları ve dur kolu gösteren bir okul otobüsü için yine de durmalıdır. Kaynak: NDCC 39-10-46."},"72":{"q":"Kuzey Dakota yasalarına göre, bir okul otobüsü sürücüsü, çocukların alınacağı veya bırakılacağı noktadan ne kadar mesafe önce sarı (amber) ikaz (uyarı) ışıklarını etkinleştirebilir?","options":["100 feet'ten az ve 300 feet'ten fazla olmamak üzere","200 feet'ten az ve 400 feet'ten fazla olmamak üzere","300 feet'ten az ve 500 feet'ten fazla olmamak üzere","Tam olarak 250 feet"],"explanation":"NDCC 39-10-46(3), sarı (amber) ikaz ışıklarının, çocukların alındığı veya bırakıldığı noktadan 300 feet'ten az ve 500 feet'ten fazla olmamak üzere etkinleştirilmesine izin verir. Kaynak: NDCC 39-10-46."},"73":{"q":"Kuzey Dakota yasaları, her okul otobüsünün arkasında demir yolu geçitleriyle ilgili belirli bir levha taşımasını gerektirir. Ne yazar?","options":["\"DO NOT PASS ON TRACKS\"","\"THIS SCHOOLBUS STOPS AT ALL RAILROAD CROSSINGS\"","\"CAUTION: RAILROAD AHEAD\"","\"SCHOOLBUS YIELDS AT CROSSINGS\""],"explanation":"NDCC 39-10-46(6), her okul otobüsünün arkasında \"THIS SCHOOLBUS STOPS AT ALL RAILROAD CROSSINGS.\" yazan, açıkça görülebilen bir levha taşımasını gerektirir. Kaynak: NDCC 39-10-46."},"74":{"q":"Kuzey Dakota'nın trafik kurallarına göre, çok şeritli bir karayolunda normal trafik hızından daha yavaş ilerleyen bir ticari araç:","options":["Birleşen trafikten uzak durmak için sol şeridi kullanmalıdır","Sürücünün tercih ettiği herhangi bir şeritte kalmalıdır","Geçiş yaparken veya sola dönüşe hazırlanırken hariç, sağdaki şeritte veya mümkün olduğunca sağ kenara yakın kullanılmalıdır","Üç şeritli bir yolda orta şeridi kullanmalıdır"],"explanation":"NDCC 39-10-08(2), normal trafik hızından daha yavaş hareket eden herhangi bir aracın, geçiş yaparken veya sola dönüşe hazırlanırken hariç, sağdaki şeritte (veya mümkün olduğunca sağ kenara yakın) kalmasını ister. Kaynak: NDCC 39-10-08."},"75":{"q":"Bir Kuzey Dakota CDL sürücüsünün kamyonu, gündüz vakti düz, dümdüz, bölünmemiş iki şeritli bir karayolunda arızalanır. Kuzey Dakota'nın uyguladığı ikaz cihazı kurallarına göre, üç ikaz üçgeni nereye yerleştirilmelidir?","options":["Üçünün de kamyonun arkasından 10 feet içinde","Aracın yaklaşık 50 feet, 150 feet ve 250 feet arkasına","Biri tavana, ikisi bankete","Aracın yaklaşık 10 feet arkasına, 100 feet arkasına ve 100 feet önüne"],"explanation":"Kuzey Dakota, federal yerleştirme standardını (49 CFR 392.22) izler: iki şeritli bir yolda, üçgenleri aracın trafik tarafında yaklaşık 10 feet arkasına, yaklaşık 100 feet arkasına ve yaklaşık 100 feet önüne yerleştirin. Kaynak: ND CDL Manual; 49 CFR 392.22."},"76":{"q":"Bir Kuzey Dakota CDL sürücüsü tek yönlü veya bölünmüş bir karayolunda durduğunda, üç ikaz üçgeni yaklaşan trafiğe doğru nasıl yerleştirilmelidir?","options":["Yaklaşan trafiğe doğru yaklaşık 10 feet, 100 feet ve 200 feet'e","Yaklaşan trafiğe doğru yaklaşık 25 feet, 75 feet ve 125 feet'e","Üçü de yaklaşan trafiğe doğru 100 feet'e","Yaklaşan trafiğe doğru yaklaşık 50 feet, 100 feet ve 150 feet'e"],"explanation":"Tek yönlü veya bölünmüş bir karayolunda, Kuzey Dakota'nın uyguladığı federal standart (49 CFR 392.22), üçgenlerin yaklaşan trafiğe doğru yaklaşık 10 feet, 100 feet ve 200 feet'e yerleştirilmesini öngörür. Kaynak: ND CDL Manual; 49 CFR 392.22."},"77":{"q":"Plakart taşıyan bir patlayıcı veya yanıcı sıvı yükü taşıyan bir Kuzey Dakota CDL sürücüsü durup ikaz cihazları yerleştirmelidir. Böyle bir araçta hangi ikaz cihazı YASAKTIR?","options":["Yansıtıcı ikaz üçgenleri","Üç taşınabilir kırmızı acil durum reflektörü","Flare'ler veya fusee'ler (alev üreten herhangi bir sinyal)","Kırmızı elektrikli fenerler"],"explanation":"Flare'ler, fusee'ler veya alev üreten herhangi bir sinyal, patlayıcı, yanıcı gaz/sıvı taşıyan ya da yakıt olarak sıkıştırılmış gaz kullanan araçlarda kullanılamaz; bunun yerine yansıtıcı üçgenler, kırmızı reflektörler veya kırmızı elektrikli fenerler kullanılmalıdır. Kaynak: ND CDL Manual; 49 CFR 392.22 / 393.95."},"78":{"q":"İlkbahar erime (thaw) dönemi dışında, Kuzey Dakota'nın ilan edilmiş ilkbahar yük kısıtlamaları sırasında bölünebilir yükler için aşırı yük izinlerine yönelik tutumu şudur:","options":["İlkbahar yol kısıtlamaları sırasında herhangi bir bölünebilir yük için aşırı yük izni VERİLMEZ","Bölünebilir yükler standart bir izinle yıl boyunca her zaman sınırları aşabilir","İlkbahar kısıtlamaları yalnızca eyaletler arası sisteme uygulanır","Bölünebilir yükler ilkbaharda tüm aks ağırlığı sınırlarından muaftır"],"explanation":"NDDOT ve ND Highway Patrol, koşullara bağlı olarak genellikle kabaca şubat ortasından mayıs ayına kadar süren ilan edilmiş ilkbahar yol (erime) kısıtlamaları sırasında bölünebilir yükler için aşırı yük izni vermez. Kaynak: NDDOT North Dakota Load Restrictions; ND Highway Patrol Oversize/Overweight Permit bilgileri."},"79":{"q":"Kuzey Dakota kanunu, belirli bir ekipman türü için özel olarak düşük bir azami hız belirler. Dolu lastiklerle (solid rubber tires) donatılmış bir araç ne kadardan daha hızlı sürülemez?","options":["5 mph","10 mph","20 mph","25 mph"],"explanation":"NDCC 39-09-04.1, dolu lastiklerle (solid rubber tires) donatılmış herhangi bir aracın 10 mph'den daha hızlı sürülmesini yasaklar. Kaynak: NDCC 39-09-04.1."},"80":{"q":"Kuzey Dakota'da Ticari Sürücü Belgelerini hangi kurum verir?","options":["North Dakota Department of Transportation (NDDOT) Driver License Division","Federal Motor Carrier Safety Administration (FMCSA)","North Dakota Highway Patrol","Sürücünün ikamet ettiği ilçenin şerif ofisi"],"explanation":"Kuzey Dakota'da CDL'ler, Driver License Division aracılığıyla North Dakota Department of Transportation (NDDOT) tarafından verilir; FMCSA federal standartları belirler ancak eyalet belgesi vermez. Kaynak: NDDOT Commercial Driver License sayfaları."},"81":{"q":"Kuzey Dakota'nın tıbbi öz beyanı (self-certification) kapsamında, bir CDL başvuru sahibi kaç öz beyan kategorisi arasından seçim yapmalıdır?","options":["Dört","İki","Üç","Altı"],"explanation":"Kuzey Dakota dört federal öz beyan kategorisini kullanır: muaf olmayan eyaletler arası (non-excepted interstate), muaf eyaletler arası (excepted interstate), muaf olmayan eyalet içi (non-excepted intrastate) ve muaf eyalet içi (excepted intrastate). Kaynak: NDDOT CDL Medical Certification Requirements."},"82":{"q":"Bir Kuzey Dakota sürücüsü kendisini 'non-excepted interstate' (muaf olmayan eyaletler arası) olarak öz beyan eder. Bu, tıbbi yeterlilik açısından neyi gerektirir?","options":["Sürücü, geçerli bir DOT tıbbi muayene uzmanı sertifikası almalı ve bunu güncel tutmalıdır","Sürücü tüm tıbbi sertifikasyon gereksinimlerinden muaftır","Sürücünün yalnızca bir görme muafiyetine (vision waiver) ihtiyacı vardır","Sürücü, DOT muayenesi yerine eyalet fiziksel uygunluk testini geçmelidir"],"explanation":"Muaf olmayan eyaletler arası (non-excepted interstate) sürücüler 49 CFR Part 391'e tabidir ve geçerli bir DOT tıbbi muayene uzmanı sertifikası almalı ve bunu güncel tutmalıdır. Kaynak: NDDOT CDL Medical Certification Requirements; 49 CFR 391.45."},"83":{"q":"Kuzey Dakota'da hangi öz beyan kategorisi bir DOT tıbbi muayene uzmanı sertifikası GEREKTİRMEZ?","options":["Excepted interstate (muaf eyaletler arası)","Non-excepted interstate (muaf olmayan eyaletler arası)","Non-excepted intrastate (muaf olmayan eyalet içi)","Eyaletler arası hazmat taşıyıcı"],"explanation":"Kendisini 'excepted' (muaf) olarak beyan eden sürücüler (eyaletler arası veya eyalet içi) yalnızca muaf operasyonlarda faaliyet gösterir ve bir tıbbi muayene uzmanı sertifikası taşımaları gerekmez; muaf olmayan (non-excepted) sürücülerin taşıması gerekir. Kaynak: NDDOT CDL Medical Certification Requirements."},"84":{"q":"21 Nisan 2025 itibarıyla, bir Kuzey Dakota CDL sahibinin DOT tıbbi muayene uzmanı sertifikası eyalete nasıl sunulur?","options":["Sertifikalı tıbbi muayene uzmanı bunu elektronik olarak yükler; NDDOT artık kağıt sertifikaları kabul etmez","Sürücü, NDDOT'a kağıt bir kopya posta ile gönderir","Sürücü, Driver License Division'a bir kopya faksla gönderir","İşveren bunu ilçe katibine (county clerk) dosyalar"],"explanation":"21 Nisan 2025 tarihinde yürürlüğe girdiği üzere, Kuzey Dakota artık tıbbi sertifikaları doğrudan kabul etmez; ulusal düzeyde sertifikalı tıbbi muayene uzmanları sertifikayı elektronik olarak kayda/eyalete yüklemelidir. Kaynak: NDDOT CDL tıbbi sertifika bildirimi."},"85":{"q":"Kuzey Dakota'da ilk Class A veya B belgesi için CDL beceri testine girmeden önce, yeni bir başvuru sahibinin hangi eğitimi tamamlaması gerekir?","options":["Training Provider Registry'de yer alan bir sağlayıcıdan Entry-Level Driver Training (ELDT)","İlçede bir savunmacı sürüş sınıf kursu","Lisanslı bir taşıyıcıyla dört yıllık bir çıraklık","Kayıt gereksinimi olmayan, yalnızca işverene özgü bir oryantasyon"],"explanation":"7 Şubat 2022'den bu yana, Kuzey Dakota tarafından benimsenen federal ELDT kuralları, yeni CDL başvuru sahiplerinin beceri testinden önce FMCSA Training Provider Registry'de listelenen bir sağlayıcıdan eğitim tamamlamasını gerektirir. Kaynak: NDDOT 'How to Apply'; FMCSA ELDT."},"86":{"q":"Kuzey Dakota CDL beceri testi sırasıyla hangi üç bölümden oluşur?","options":["Sefer öncesi muayene (pre-trip inspection), temel araç kontrolü ve yolda sürüş","Yazılı bilgi testi, göz muayenesi ve yolda sürüş","Paralel park, hazmat yazılı testi ve hava freni testi","Sefer öncesi muayene, hazmat onayı testi ve gece sürüşü"],"explanation":"Kuzey Dakota'nın CDL beceri testi federal üç bölümlü formatı izler: sefer öncesi araç muayenesi (pre-trip inspection), temel araç (kontrol) becerileri ve yolda sürüş. Kaynak: ND CDL Manual; NDDOT CDL sayfaları."},"87":{"q":"Kuzey Dakota'da, bir başvuru sahibinin CDL beceri (yol) testine girmesine izin verilmeden önce ne elde etmesi gerekir?","options":["Gerekli bilgi test(ler)ini geçtikten sonra bir Commercial Learner Permit (CLP)","Geçici olarak verilen tam bir CDL","Bir tehlikeli madde onayı","Bir federal işletme yetkisi numarası"],"explanation":"Başvuru sahipleri, beceri testini planlamadan önce ilk olarak bilgi test(ler)ini geçmeli ve bir Commercial Learner Permit (CLP) edinmelidir. Kaynak: NDDOT 'How to Apply for a Commercial Driver License.'"},"88":{"q":"Bir Kuzey Dakota CLP, sahibinin CDL beceri testine girebilmesi için en az kaç gün elde tutulmalıdır?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"Kuzey Dakota federal 14 günlük bekleme süresini uygular: başvuru sahibinin CDL beceri testine girebilmesi için bir CLP en az 14 gün elde tutulmalıdır. Kaynak: NDDOT CDL sayfaları; 49 CFR 383.25."},"89":{"q":"Kuzey Dakota'da bir Commercial Learner Permit, veriliş tarihinden itibaren en fazla kaç ardışık gün geçerlidir?","options":["180 gün","90 gün","365 gün","60 gün"],"explanation":"Bir Kuzey Dakota CLP'si, veriliş tarihinden itibaren en fazla 180 ardışık gün geçerlidir; yol testi zamanında geçilmezse, izin yenilenmelidir. Kaynak: NDDOT CDL sayfaları."},"90":{"q":"Bir Kuzey Dakota CLP'si ile pratik yaparken, izin sahibiyle birlikte araçta kim bulunmalıdır?","options":["Aynı veya daha yüksek sınıf/onaylara sahip, sürücünün yanında oturan bir CDL sahibi","21 yaş ve üzeri herhangi bir lisanslı sürücü","Bir North Dakota Highway Patrol memuru","Kamuya açık yolların dışında pratik yapılıyorsa kimse gerekli değildir"],"explanation":"Bir CLP sahibi, yalnızca yanında oturan nitelikli bir CDL sahibi (uygun sınıf ve onaylara sahip) eşliğinde ticari bir araç kullanabilir. Kaynak: NDDOT CDL sayfaları; 49 CFR 383.25."},"91":{"q":"Bir Kuzey Dakota CDL'si için standart yenileme döngüsü nedir?","options":["Dört yıl","Beş yıl","İki yıl","Sekiz yıl"],"explanation":"Kuzey Dakota CDL'leri dört yıllık bir süre için verilir ve o döngünün sonunda sürücünün doğum gününde gece yarısı sona erer. Kaynak: NDDOT 'How to Renew a Commercial Driver License.'"},"92":{"q":"Bir Kuzey Dakota CDL'si, yenileme yılının hangi tarihinde gece yarısı sona erer?","options":["Sürücünün doğum günü","31 Aralık","Orijinal veriliş tarihinin yıl dönümü","Veriliş ayının son günü"],"explanation":"Kuzey Dakota CDL'leri, yenileme yılında sürücünün doğum gününde gece yarısı sona erer. Kaynak: NDDOT yenileme bilgileri."},"93":{"q":"Bir Kuzey Dakota CDL başvuru sahibi başvuru yaparken tipik olarak hangi belgeleri sunmalıdır?","options":["Geçerli bir sürücü belgesi, yasal mevcudiyet (legal presence) kanıtı ve ikamet adresi kanıtı","Yalnızca bir Sosyal Güvenlik kartı","Yalnızca bir pasaport ve bir araç tescili","Bir doğum belgesi ve bir av ruhsatı"],"explanation":"NDDOT, başvuru sahiplerinin geçerli bir sürücü belgesi, yasal mevcudiyet/kimlik kanıtı ve Kuzey Dakota ikamet adresi kanıtı sunmasını gerektirir. Kaynak: NDDOT 'How to Apply for a Commercial Driver License.'"},"94":{"q":"Eyalet içi (Kuzey Dakota içinde) yalnızca geçerli bir CDL almak için asgari yaş nedir?","options":["18 yaş","16 yaş","21 yaş","19 yaş"],"explanation":"Kuzey Dakota, 18 yaşında eyalet içi (intrastate) bir CDL'ye izin verir; eyaletler arası (interstate) operasyon (ve hazmat) genellikle 21 yaş gerektirir. Kaynak: NDDOT 'How to Apply'; 49 CFR 383/391."},"95":{"q":"Kuzey Dakota'da eyaletler arası sürüş için (veya bir hazmat onayı için) geçerli bir CDL almanın asgari yaşı nedir?","options":["21 yaş","18 yaş","19 yaş","25 yaş"],"explanation":"Eyaletler arası (interstate) CDL operasyonu ve tehlikeli maddeler onayı, sürücünün en az 21 yaşında olmasını gerektirir. Kaynak: NDDOT CDL gereksinimleri; federal CDL kuralları."},"96":{"q":"Bir Kuzey Dakota CLP'si almak için, bilgi testini geçmenin yanı sıra hangi muayene gereklidir?","options":["Bir görme (göz) muayenesi","NDDOT tarafından uygulanan bir işitme testi","DOT ofisinde bir uyuşturucu ve alkol taraması","Bir psikolojik değerlendirme"],"explanation":"Kuzey Dakota, bir CLP vermek için gerekli bilgi test(ler)ini geçmenin yanı sıra bir görme/göz muayenesi gerektirir. Kaynak: NDDOT 'How to Apply for a Commercial Driver License.'"},"97":{"q":"Bir Kuzey Dakota CDL başvuru sahibi bilgi testinde başarısız olursa, NDDOT'un yeniden girme konusundaki politikası nedir?","options":["Genellikle günde bir deneme izni verilir; başvuru sahibi yeniden test için başka bir gün geri döner","Başvuru sahibi herhangi bir yeniden girişten önce 30 gün beklemelidir","Başvuru sahibi bir başarısızlıktan sonra kalıcı olarak men edilir","Aynı gün içinde sınırsız yeniden giriş yapılabilir"],"explanation":"NDDOT genellikle bilgi testini günde bir denemeyle sınırlar, bu nedenle başarısız olan bir başvuru sahibinin yeniden test için daha sonraki bir gün geri dönmesi gerekir. Kaynak: NDDOT CDL test/ücret bilgileri. (Tam ücretler değişebilir.)"},"98":{"q":"Bir sürücü, ilk kez bir Kuzey Dakota CDL'sine okul otobüsü (S) onayı eklemek istiyor. Beceri/onay testinden önce hangi süreç adımı gereklidir?","options":["S onayı için gerekli Entry-Level Driver Training (ELDT) eğitimini tamamlamak","Yalnızca bir görme testini geçmek","Temel CDL'yi en az beş yıl elde tutmak","Ayrı bir eyalet içi (intrastate) izni almak"],"explanation":"İlk kez bir yolcu (P), okul otobüsü (S) veya hazmat (H) onayı eklemek, testten önce tamamlanması gereken ELDT gereksinimini tetikler. Kaynak: NDDOT CDL sayfaları; 7 Şubat 2022'de yürürlüğe giren FMCSA ELDT kuralı."},"99":{"q":"Kuzey Dakota CDL beceri testinde, temel araç kontrolü bölümü esas olarak hangi yetenekleri test eder?","options":["Düz çizgide geri gitme, park etme/yanaştırma ve kontrollü dönüş gibi manevralar","Trafik işaretlerini ezbere okuma","Köprü ağırlık sınırlarını hesaplama","Sözlü hazmat sorularını yanıtlama"],"explanation":"Temel araç kontrolü bölümü, düz çizgide geri gitme, dar geçitte yanaştırma (alley docking), paralel park ve hassas dönüş gibi düşük hızlı kontrol manevralarını test eder. Kaynak: ND CDL Manual; NDDOT beceri testi formatı."}},"es":{"0":{"q":"En las carreteras de Dakota del Norte, ¿cuál es el ancho exterior total máximo legal de un vehículo y su carga?","options":["8 pies 6 pulgadas","8 pies","9 pies","10 pies"],"explanation":"Dakota del Norte limita el ancho exterior total del vehículo, incluida la carga, a 8 pies 6 pulgadas en todas las carreteras (NDCC 39-12-04; NDHP Motor Carrier Operations Legal Size and Weight Guide, Ref 9-1, Sec. A). Una carga más ancha que esto requiere un permiso."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo, cargado o descargado, en las carreteras de Dakota del Norte?","options":["13 pies 6 pulgadas","14 pies","13 pies","15 pies"],"explanation":"Dakota del Norte establece la altura máxima legal del vehículo en 14 pies, ya sea cargado o descargado, pero el conductor aún debe asegurarse de tener espacio libre debajo de puentes y pasos a desnivel de menos de 14 pies (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. B)."},"2":{"q":"En Dakota del Norte, ¿cuál es la longitud máxima de un remolque o semirremolque, incluida su carga (para unidades registradas después del 1 de julio de 1987)?","options":["48 pies","53 pies","57 pies","60 pies"],"explanation":"Un remolque o semirremolque, incluida la carga, no puede exceder los 53 pies en Dakota del Norte; los remolques/semirremolques con título y registro en el estado antes del 1 de julio de 1987 y los vehículos remolcados pueden alcanzar los 60 pies (NDCC 39-12-04; NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.4)."},"3":{"q":"¿Cuál es el peso bruto vehicular máximo permitido en el sistema de carreteras interestatales (Interstate) en Dakota del Norte?","options":["85,500 libras","90,000 libras","80,000 libras","105,500 libras"],"explanation":"El peso bruto vehicular máximo en el sistema de carreteras interestatales (Interstate) en Dakota del Norte es de 80,000 libras (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.b), de acuerdo con el límite federal para las interestatales."},"4":{"q":"En Dakota del Norte, ningún eje individual puede soportar un peso bruto superior a cuántas libras?","options":["18,000 libras","20,000 libras","22,000 libras","24,000 libras"],"explanation":"Dakota del Norte limita un eje individual a un peso bruto máximo de 20,000 libras (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.b). Los ejes separados por 40 pulgadas o menos cuentan como un solo eje."},"5":{"q":"¿Cuál es el peso bruto máximo que Dakota del Norte permite en un eje tándem?","options":["32,000 libras","36,000 libras","40,000 libras","34,000 libras"],"explanation":"En Dakota del Norte el peso bruto de un eje tándem no puede exceder las 34,000 libras (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.c), coincidiendo con el límite federal para el eje tándem."},"6":{"q":"¿Cuál es la longitud máxima de un vehículo de una sola unidad con dos o más ejes, incluida su carga, en Dakota del Norte?","options":["40 pies","45 pies","50 pies","53 pies"],"explanation":"Un vehículo de una sola unidad con dos o más ejes, incluida la carga, no puede exceder los 50 pies en Dakota del Norte (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.1)."},"7":{"q":"En las carreteras de Dakota del Norte DISTINTAS al sistema interestatal (Interstate), ¿cuál es el peso bruto máximo permitido para dos ejes individuales separados por 8 pies o más?","options":["34,000 libras","36,000 libras","40,000 libras","44,000 libras"],"explanation":"En las carreteras distintas al sistema interestatal (Interstate), el peso bruto combinado de dos ejes individuales separados por 8 pies o más no puede exceder las 40,000 libras en Dakota del Norte (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.b)."},"8":{"q":"En las carreteras no designadas de Dakota del Norte, ¿cuál es la longitud máxima de una combinación de dos, tres o cuatro unidades, incluida la carga?","options":["65 pies","70 pies","75 pies","85 pies"],"explanation":"Una combinación de dos, tres o cuatro unidades, incluida la carga, no puede exceder los 75 pies en las carreteras no designadas de Dakota del Norte; en las carreteras divididas de cuatro carriles designadas por el NDDOT, dichas combinaciones pueden alcanzar los 95 o 110 pies (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.2 y C.3)."},"9":{"q":"En las carreteras estatales de Dakota del Norte (distintas a la interestatal), el peso bruto vehicular máximo es generalmente de 80,000 libras a menos que la ruta esté designada para más, sin exceder qué tope?","options":["100,000 libras","105,500 libras","110,000 libras","129,000 libras"],"explanation":"En las carreteras de Dakota del Norte que no son interestatales, el peso bruto vehicular máximo es de 80,000 libras a menos que la carretera esté designada para más, en cuyo caso no puede exceder las 105,500 libras (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.2.a)."},"10":{"q":"Según la fórmula federal de puentes aplicada en Dakota del Norte, dos conjuntos consecutivos de ejes tándem pueden soportar cada uno 34,000 libras siempre que la distancia entre el primer y el último eje de esos conjuntos tándem sea de al menos cuántos pies?","options":["30 pies","34 pies","36 pies","40 pies"],"explanation":"Dakota del Norte aplica la fórmula de puentes W = 500(LN/(N-1) + 12N + 36), pero dos conjuntos consecutivos de ejes tándem pueden soportar cada uno 34,000 libras si la distancia total entre el primer y el último eje de esos conjuntos es de al menos 36 pies (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.a)."},"11":{"q":"En la fórmula de puentes de Dakota del Norte W = 500(LN/(N-1) + 12N + 36), ¿qué representa la letra N?","options":["El número de ejes en el grupo","La distancia entre los extremos de los ejes","El peso neto de la carga","El peso máximo en libras"],"explanation":"En la fórmula de puentes de Dakota del Norte, W es el peso máximo sobre un grupo de ejes, L es la distancia en pies entre los extremos del grupo, y N es el número de ejes en el grupo (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.a)."},"12":{"q":"En las carreteras distintas al sistema interestatal (Interstate) en Dakota del Norte, ¿cuál es el peso bruto máximo permitido en un grupo de tres o más ejes?","options":["42,000 libras","51,000 libras","54,000 libras","48,000 libras"],"explanation":"En las carreteras de Dakota del Norte distintas al sistema interestatal (Interstate), el peso bruto de un grupo de tres o más ejes no puede exceder las 48,000 libras; en la interestatal el grupo se rige por la fórmula de puentes (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.c)."},"13":{"q":"¿Cuándo se requiere un permiso de viaje único por sobredimensión/sobrepeso en Dakota del Norte?","options":["Para cualquier vehículo comercial que transporte materiales peligrosos","Solo para cargas que viajan por la interestatal después del anochecer","Para una carga no reducible que excede los límites legales de tamaño y/o peso de Dakota del Norte","Para cualquier vehículo que pese más de 26,001 libras"],"explanation":"Dakota del Norte requiere un permiso de viaje único por sobredimensión/sobrepeso para el movimiento de una carga no reducible con sobredimensión y/o sobrepeso que excede los límites legales de tamaño y peso del vehículo del estado (NDHP Oversize/Overweight Permit, e-permits)."},"14":{"q":"¿Por cuánto tiempo es válido un permiso de viaje único por sobredimensión/sobrepeso de Dakota del Norte para un movimiento de carga?","options":["Hasta 24 horas","Hasta 3 días","Hasta 5 días","Hasta 7 días"],"explanation":"Un permiso de viaje único por sobredimensión/sobrepeso de Dakota del Norte es válido para un movimiento de carga por hasta 5 días (NDHP Oversize/Overweight Permit, sistema e-permits en nd.gov/ndhp)."},"15":{"q":"El permiso de exención de peso por cosecha de Dakota del Norte permite que un vehículo que transporta un producto agrícola cosechado desde el campo hasta el primer punto de almacenamiento o venta lleve cuánto peso adicional?","options":["5 por ciento más de peso","10 por ciento más de peso","15 por ciento más de peso","20 por ciento más de peso"],"explanation":"El permiso de exención de peso por cosecha de Dakota del Norte permite un 10% más de peso al transportar un producto cosechado desde el campo hasta el punto inicial de almacenamiento o primer punto de venta, válido del 15 de julio al 30 de noviembre, y el peso bruto no puede exceder las 105,500 libras (NDHP e-permits, Harvest Weight Exemption Permit)."},"16":{"q":"¿Durante qué rango de fechas es válido el permiso de exención de peso por cosecha de Dakota del Norte?","options":["1 de mayo - 30 de septiembre","1 de junio - 31 de octubre","15 de julio - 30 de noviembre","1 de agosto - 31 de diciembre"],"explanation":"El permiso de exención de peso por cosecha de Dakota del Norte es válido entre el 15 de julio y el 30 de noviembre para transportar productos cosechados desde el campo hasta el punto inicial de almacenamiento o primera venta (NDHP e-permits, Harvest Weight Exemption Permit)."},"17":{"q":"En Dakota del Norte, un implemento agrícola que es trasladado por un agricultor residente entre el amanecer y el atardecer (no en la interestatal) puede exceder el límite normal de altura de 14 pies hasta qué altura máxima?","options":["14 pies 6 pulgadas","15 pies","15 pies 6 pulgadas","16 pies"],"explanation":"Dakota del Norte permite que los implementos agrícolas alcancen los 15 pies 6 pulgadas de altura cuando son trasladados por agricultores, ganaderos, distribuidores o fabricantes residentes entre el amanecer y el atardecer, por una distancia no superior a 60 millas y no en la interestatal (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. B.2.a)."},"18":{"q":"Un vehículo de Dakota del Norte impulsado principalmente por gas natural puede exceder el límite de peso bruto por cuánto, hasta qué máximo?","options":["Hasta 1,000 libras, máx 81,000 libras","Hasta 2,000 libras, máx 82,000 libras","Hasta 2,500 libras, máx 82,500 libras","Hasta 4,000 libras, máx 84,000 libras"],"explanation":"Un vehículo de Dakota del Norte operado por un motor que funciona principalmente con gas natural puede exceder el límite de peso por hasta 2,000 libras, hasta un peso bruto máximo de 82,000 libras, para tener en cuenta el sistema de combustible más pesado (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.8)."},"19":{"q":"En Dakota del Norte, el peso del eje de dirección lo establece la clasificación de eje del fabricante, pero no puede exceder cuántas libras al circular por el sistema interestatal (Interstate)?","options":["12,000 libras","18,000 libras","20,000 libras","24,000 libras"],"explanation":"Dakota del Norte limita el eje de dirección a la clasificación de eje del fabricante, sin exceder las 20,000 libras en el sistema interestatal (Interstate), y ningún neumático puede exceder las 550 libras por pulgada de ancho de neumático (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.a)."},"20":{"q":"En Dakota del Norte, ¿qué clase de CDL se requiere para operar cualquier combinación de vehículos con una clasificación de peso bruto combinado (GCWR) de 26,001 libras o más, siempre que el o los vehículos remolcados tengan un GVWR superior a 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"La CDL Clase A de Dakota del Norte (vehículo combinado) cubre cualquier combinación de vehículos con un GCWR de 26,001 lbs o más cuando el GVWR de la unidad remolcada excede las 10,000 lbs. Fuente: página de Commercial Driver License del NDDOT y ND CDL Manual; 49 CFR 383.91."},"21":{"q":"Según las reglas de Dakota del Norte, una CDL Clase B autoriza a un conductor a operar ¿cuál de las siguientes?","options":["Cualquier vehículo individual con un GVWR de 26,001 lbs o más, remolcando una unidad de no más de 10,000 lbs de GVWR","Cualquier combinación de vehículos de más de 26,001 lbs de GCWR con una unidad remolcada de más de 10,000 lbs","Solo vehículos diseñados para transportar 16 o más pasajeros","Solo vehículos de menos de 26,001 lbs de GVWR que transporten materiales peligrosos con letreros (placards)"],"explanation":"La Clase B de ND (vehículo recto pesado) cubre cualquier vehículo individual con un GVWR de 26,001 lbs o más, o dicho vehículo remolcando una unidad que no exceda las 10,000 lbs de GVWR. Fuente: página de Commercial Driver License del NDDOT y ND CDL Manual; 49 CFR 383.91."},"22":{"q":"Un conductor de Dakota del Norte opera un vehículo individual con clasificación inferior a 26,001 lbs de GVWR que está diseñado para transportar 16 o más pasajeros (incluido el conductor). ¿Qué clase de CDL aplica?","options":["Clase C","Clase A","Clase B","No se requiere CDL"],"explanation":"La Clase C de ND (vehículo pequeño) aplica a vehículos individuales de menos de 26,001 lbs de GVWR que están diseñados para transportar 16 o más pasajeros (incluido el conductor) o que transportan materiales peligrosos que requieren letreros (placards). Fuente: página de Commercial Driver License del NDDOT y ND CDL Manual; 49 CFR 383.91."},"23":{"q":"¿Qué endoso de CDL de Dakota del Norte se requiere para operar un vehículo cisterna utilizado para transportar un líquido o gas en un tanque montado permanentemente con una capacidad individual clasificada de más de 119 galones (y un total de 1,000 galones o más)?","options":["N (Vehículos cisterna)","H (Materiales peligrosos)","T (Dobles/Triples)","P (Pasajeros)"],"explanation":"El endoso N se requiere en ND para transportar líquidos o gases en un tanque clasificado en más de 119 galones individualmente o 1,000 galones o más en total. Fuente: página de Commercial Driver License del NDDOT; 49 CFR 383.93."},"24":{"q":"En Dakota del Norte, ¿qué endoso debe obtener un titular de CDL para remolcar remolques dobles o triples?","options":["T (Dobles/Triples)","N (Vehículos cisterna)","X (Combinación cisterna/HazMat)","P (Pasajeros)"],"explanation":"El endoso T autoriza el remolque de remolques dobles o triples en Dakota del Norte y se obtiene aprobando el examen de conocimientos de dobles/triples. Fuente: página de Commercial Driver License del NDDOT y ND CDL Manual; 49 CFR 383.93."},"25":{"q":"¿Cuál es la edad mínima para obtener una CDL de Dakota del Norte válida únicamente para conducir INTRAESTATAL (dentro de Dakota del Norte)?","options":["18 años","16 años","19 años","21 años"],"explanation":"Dakota del Norte permite una CDL para conducir solo intraestatal a los 18 años. Los conductores deben tener 21 años para operar en comercio interestatal. Fuente: requisitos de CDL del NDDOT; NDCC Título 39; 49 CFR 383."},"26":{"q":"Un solicitante de CDL de Dakota del Norte que desea conducir en comercio interestatal, transportar materiales peligrosos o transportar pasajeros por paga debe tener al menos qué edad?","options":["21 años","18 años","19 años","25 años"],"explanation":"Dakota del Norte requiere que un conductor tenga al menos 21 años para operar a través de las fronteras estatales (interestatal), para transportar materiales peligrosos o para transportar pasajeros por paga. Fuente: requisitos de CDL del NDDOT; 49 CFR 383."},"27":{"q":"Después de que se le emite un Permiso de Aprendizaje Comercial (CLP) de Dakota del Norte, ¿cuánto tiempo debe esperar un solicitante antes de ser elegible para tomar el examen de habilidades (de manejo) de la CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","Al menos 60 días"],"explanation":"Dakota del Norte sigue la regla federal que exige que se tenga un CLP durante al menos 14 días antes de que el solicitante pueda tomar el examen de habilidades de la CDL. Fuente: página de solicitud de CDL del NDDOT; 49 CFR 383.25."},"28":{"q":"Antes de obtener un endoso de Materiales Peligrosos (H) en Dakota del Norte, un solicitante debe aprobar ¿qué evaluación de antecedentes exigida por el gobierno federal?","options":["Una evaluación de amenazas a la seguridad de la TSA, que incluye toma de huellas dactilares","Una verificación de antecedentes penales solo del FBI sin huellas dactilares","Un examen de polígrafo administrado por el estado","Solo una verificación de referencias realizada por el empleador"],"explanation":"Los solicitantes del endoso H en ND deben completar la evaluación de amenazas a la seguridad de la TSA, que incluye la presentación de huellas dactilares, antes de que se pueda agregar el endoso. Fuente: página de Hazardous Material Requirements del NDDOT; 49 CFR 1572 / TSA."},"29":{"q":"¿Qué paso de capacitación de nivel inicial ahora se requiere antes de que un solicitante de Dakota del Norte pueda tomar el examen de conocimientos para un NUEVO endoso de Materiales Peligrosos (H)?","options":["Capacitación teórica federal de hazmat ELDT de un proveedor incluido en el FMCSA Training Provider Registry","Un aprendizaje de cabina de 40 horas en camión cisterna","Un curso de academia de hazmat administrado por el estado de Dakota del Norte","No se requiere capacitación, solo el examen de conocimientos"],"explanation":"Los solicitantes iniciales del endoso H en ND deben completar la capacitación teórica de hazmat de Capacitación de Conductores de Nivel Inicial (ELDT) exigida por el gobierno federal de un proveedor incluido en el FMCSA Training Provider Registry antes del examen de conocimientos. Fuente: página de Hazardous Material Requirements del NDDOT; 49 CFR 380."},"30":{"q":"La Capacitación de Conductores de Nivel Inicial (ELDT) requerida antes de obtener una primera CDL Clase A de Dakota del Norte debe completarse a través de ¿qué sistema?","options":["Un proveedor incluido en el FMCSA Training Provider Registry","Cualquier colegio comunitario de Dakota del Norte, sin inscripción federal","La academia interna de conductores del NDDOT","Cualquier empleador de transporte de otro estado que elija el conductor"],"explanation":"ND requiere que la ELDT se complete a través de una escuela o entidad incluida en el FMCSA Training Provider Registry antes del examen de habilidades para una CDL Clase A inicial. Fuente: página How to Apply for a CDL del NDDOT; 49 CFR 380 Subpart F."},"31":{"q":"¿Qué endoso necesita un conductor de Dakota del Norte para operar un vehículo (que no sea un autobús escolar) diseñado para transportar 16 o más personas, incluido el conductor?","options":["P (Pasajeros)","S (Autobús escolar)","N (Cisterna)","T (Dobles/Triples)"],"explanation":"El endoso P (Pasajeros) se requiere para operar un autobús u otro vehículo diseñado para transportar 16 o más personas, incluido el conductor. Un autobús escolar también requiere el endoso S por separado. Fuente: ND CDL Manual; 49 CFR 383.93."},"32":{"q":"Para agregar un endoso de Autobús Escolar (S) a una CDL de Dakota del Norte, ¿qué endoso debe tener TAMBIÉN el conductor?","options":["P (Pasajeros)","N (Cisterna)","H (Materiales peligrosos)","T (Dobles/Triples)"],"explanation":"En Dakota del Norte, el endoso S (Autobús escolar) requiere que el conductor tenga primero el endoso P (Pasajeros), además de aprobar los exámenes de conocimientos y habilidades de autobús escolar. Fuente: ND CDL Manual; 49 CFR 383.93."},"33":{"q":"Al solicitar una CDL de Dakota del Norte, un solicitante debe proporcionar prueba de un número de Seguro Social. ¿Cuál de estos es un documento aceptable?","options":["La tarjeta original del Seguro Social","Una fotocopia de la tarjeta del Seguro Social","Una nota escrita a mano que indique el SSN","Una tarjeta de biblioteca que muestre el número"],"explanation":"ND requiere prueba del número de Seguro Social, como la tarjeta original del Seguro Social; no se aceptan fotocopias y los documentos deben ser originales o certificados. Fuente: lista de verificación de Driver License Requirements / REAL ID del NDDOT."},"34":{"q":"¿Cuántos documentos de comprobante de residencia requiere Dakota del Norte que un solicitante presente para establecer su domicilio residencial en Dakota del Norte?","options":["Dos documentos","Un documento","Tres documentos","No se requiere comprobante de residencia"],"explanation":"Dakota del Norte requiere dos documentos que comprueben la dirección de residencia del solicitante en Dakota del Norte (por ejemplo, facturas de servicios públicos/estados de cuenta financieros, registros fiscales). Fuente: lista de verificación de Driver License Requirements / REAL ID del NDDOT."},"35":{"q":"Además de la identidad, el número de Seguro Social y la residencia, ¿qué prueba adicional debe proporcionar un solicitante de CDL de Dakota del Norte?","options":["Prueba de ciudadanía estadounidense, residencia permanente legal o presencia legal/temporal","Una carta notariada de un empleador actual","Prueba de propiedad del vehículo","Un diploma de escuela secundaria"],"explanation":"ND requiere prueba de ciudadanía, residencia permanente legal o presencia legal en los Estados Unidos, además de la identidad, el SSN y la residencia. Fuente: página de Driver License Requirements del NDDOT."},"36":{"q":"Un solicitante de CDL de Dakota del Norte que conduce en comercio interestatal y debe portar un Certificado de Examinador Médico se autocertificaría bajo ¿qué categoría?","options":["Interestatal, no exceptuado (NI)","Interestatal, exceptuado (EI)","Intraestatal, no exceptuado (NA)","Intraestatal, exceptuado (EA)"],"explanation":"Los conductores en comercio interestatal que deben cumplir con los estándares federales de calificación física se autocertifican como Interestatal No Exceptuado y deben mantener un Certificado de Examinador Médico válido archivado con ND. Fuente: autocertificación de CDL del NDDOT; 49 CFR 383.71 / 391."},"37":{"q":"¿Entre cuántas categorías de autocertificación médica debe elegir un titular de CDL de Dakota del Norte al certificar el tipo de comercio en el que opera?","options":["Cuatro (interestatal no exceptuado, interestatal exceptuado, intraestatal no exceptuado, intraestatal exceptuado)","Dos (solo interestatal e intraestatal)","Tres (interestatal, intraestatal y exento)","Cinco (una por cada endoso de CDL)"],"explanation":"Las reglas federales adoptadas por ND requieren seleccionar una de cuatro categorías de autocertificación: interestatal no exceptuado, interestatal exceptuado, intraestatal no exceptuado o intraestatal exceptuado. Fuente: autocertificación de CDL del NDDOT; 49 CFR 383.71."},"38":{"q":"Según el estándar federal que sigue Dakota del Norte, ¿cuál es el período máximo que un Permiso de Aprendizaje Comercial (CLP) puede ser válido antes de que deba renovarse (sin volver a tomar los exámenes de conocimientos)?","options":["180 días","30 días","12 meses","5 años"],"explanation":"Un CLP es válido por hasta 180 días y puede renovarse una vez por otros 180 días dentro de un período de un año sin volver a examinarse; ND emite CLP bajo este estándar federal. Fuente: ND CDL Manual; 49 CFR 383.25."},"39":{"q":"Un solicitante de CDL de Dakota del Norte debe tomar el examen de habilidades (de manejo) en ¿qué tipo de vehículo?","options":["Un vehículo representativo de la clase y el tipo que el solicitante pretende conducir","Cualquier automóvil de pasajeros que sea propiedad del solicitante","Un vehículo proporcionado por el examinador del NDDOT","Solo una combinación Clase A, independientemente de la licencia solicitada"],"explanation":"ND requiere que el examen de habilidades se tome en un vehículo representativo de la clase y configuración (incluidos endosos como autobús escolar o cisterna) que el solicitante pretende operar. Fuente: página de solicitud de CDL del NDDOT; 49 CFR 383.71/383.113."},"40":{"q":"En Dakota del Norte, ¿con qué concentración de alcohol en sangre (BAC) se considera que un conductor está operando un vehículo motorizado comercial (CMV) bajo los efectos del alcohol y sujeto a descalificación?","options":["0.04 o más","0.08 o más","0.02 o más","0.10 o más"],"explanation":"Dakota del Norte sigue el estándar federal: operar un CMV con un BAC de 0.04 o más es una infracción de alcohol que descalifica a un titular de CDL. Esto es la mitad del límite de 0.08 que aplica a la conducción no comercial. Fuente: Commercial Driver License Manual del NDDOT (Descalificación); NDCC 39-06.2-10.1."},"41":{"q":"Según la ley de consentimiento implícito de Dakota del Norte, ¿qué le sucede a un titular de CDL que se niega a someterse a una prueba química de alcohol mientras opera un CMV?","options":["Se trata igual que una condena por DUI y descalifica al conductor","Solo resulta en una advertencia por una primera negativa","Conlleva una sanción menor que una condena por DUI","Solo resulta en una suspensión de 30 días"],"explanation":"La negativa a someterse a una prueba química se trata, para efectos de la CDL, igual que una condena por alcohol/DUI. Una primera negativa descalifica al conductor por al menos un año, igual que una primera infracción mayor. Fuente: ND CDL Manual (Descalificación); NDCC 39-06.2-10.1."},"42":{"q":"¿Cuál es el período mínimo de descalificación de la CDL en Dakota del Norte por una primera infracción mayor, como un DUI en un CMV, cuando NO se transportan materiales peligrosos?","options":["1 año","60 días","6 meses","3 años"],"explanation":"Una primera infracción mayor (por ejemplo, operar un CMV con un BAC de 0.04 o más, DUI o negativa a la prueba) descalifica al conductor por al menos un año. Fuente: ND CDL Manual (Descalificación); NDCC 39-06.2-10; 49 CFR 383.51."},"43":{"q":"En Dakota del Norte, ¿cuál es la descalificación mínima de la CDL por una primera infracción mayor cometida mientras el CMV transporta materiales peligrosos con letreros (placards)?","options":["3 años","1 año","5 años","120 días"],"explanation":"Si una primera infracción mayor se comete mientras se opera un CMV que tiene letreros (placards) de materiales peligrosos, la descalificación aumenta de un año a al menos tres años. Fuente: ND CDL Manual (Descalificación); 49 CFR 383.51."},"44":{"q":"¿Cuál es el período de descalificación de la CDL en Dakota del Norte por una segunda infracción mayor (por ejemplo, un segundo DUI en un CMV)?","options":["De por vida","10 años","3 años","5 años"],"explanation":"Una segunda condena por cualquier infracción mayor, en cualquier combinación, resulta en una descalificación de la CDL de por vida. Fuente: ND CDL Manual (Descalificación); NDCC 39-06.2-10; 49 CFR 383.51."},"45":{"q":"Un titular de CDL de Dakota del Norte es condenado por usar un vehículo para cometer un delito grave que involucra la fabricación o distribución de una sustancia controlada. ¿Qué descalificación aplica?","options":["Descalificación de por vida sin reinstalación","Descalificación de 1 año","Descalificación de 3 años","Descalificación de 60 días"],"explanation":"Usar un CMV para cometer un delito grave que involucra la fabricación, distribución o dispensación de una sustancia controlada resulta en una descalificación de por vida que no está sujeta a reinstalación. Fuente: ND CDL Manual (Descalificación); 49 CFR 383.51."},"46":{"q":"¿Cuántas infracciones de tránsito graves dentro de un período de 3 años desencadenan una descalificación de la CDL de 60 días en Dakota del Norte?","options":["2 (la segunda dentro de 3 años)","1 (la primera infracción)","3 (la tercera dentro de 3 años)","4 (la cuarta dentro de 3 años)"],"explanation":"Una segunda infracción de tránsito grave dentro de un período de 3 años, derivada de incidentes separados, resulta en una descalificación de al menos 60 días. Fuente: ND CDL Manual (Descalificación); NDCC 39-06.2-10.5; 49 CFR 383.51."},"47":{"q":"En Dakota del Norte, tres infracciones de tránsito graves dentro de un período de 3 años resultan en una descalificación de la CDL de al menos cuánto tiempo?","options":["120 días","60 días","1 año","180 días"],"explanation":"Una tercera infracción de tránsito grave dentro de un período de 3 años (de incidentes separados) resulta en una descalificación de al menos 120 días. Fuente: ND CDL Manual (Descalificación); NDCC 39-06.2-10.5; 49 CFR 383.51."},"48":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE a efectos de la descalificación de la CDL en Dakota del Norte?","options":["Exceso de velocidad de 15 mph o más por encima del límite de velocidad señalizado","Operar un CMV con un BAC de 0.04 o más","Negarse a una prueba química bajo consentimiento implícito","Abandonar el lugar de un accidente"],"explanation":"El exceso de velocidad excesivo (15 mph o más por encima del límite) es una infracción de tránsito grave. Las otras infracciones enumeradas son infracciones mayores, que conllevan descalificaciones mucho más largas. Fuente: ND CDL Manual (Descalificación); NDCC 39-06.2-10.5; 49 CFR 383.51."},"49":{"q":"Conducir un CMV mientras se envían mensajes de texto, en violación de la ley estatal o local, se clasifica en Dakota del Norte como ¿qué tipo de infracción descalificadora?","options":["Una infracción de tránsito grave","Una infracción mayor","Una violación de una orden de fuera de servicio","Una violación de cruce ferroviario"],"explanation":"Enviar mensajes de texto mientras se conduce un CMV es una infracción de tránsito grave; dos dentro de 3 años causan una descalificación de 60 días y tres dentro de 3 años una descalificación de 120 días. Fuente: ND CDL Manual (Descalificación); 49 CFR 383.51; 49 CFR 392.80."},"50":{"q":"Usar un teléfono móvil de mano mientras se conduce un CMV, en violación de la regla, se trata en Dakota del Norte como:","options":["Una infracción de tránsito grave","Una infracción menor de equipo","Una infracción mayor descalificadora por 1 año","Una violación de una orden de fuera de servicio"],"explanation":"Conducir un CMV mientras se usa un teléfono móvil de mano es una infracción de tránsito grave. Acumular dos o tres dentro de 3 años resulta en descalificaciones de 60 o 120 días, respectivamente. Fuente: ND CDL Manual (Descalificación); 49 CFR 383.51; 49 CFR 392.82."},"51":{"q":"Según la regla federal que aplica en Dakota del Norte, ¿cuál es la sanción civil máxima que puede enfrentar un conductor de CMV por enviar mensajes de texto o usar un teléfono de mano mientras conduce?","options":["$2,750","$500","$1,000","$5,000"],"explanation":"Un conductor puede estar sujeto a una sanción civil de hasta $2,750 por enviar mensajes de texto o usar un teléfono móvil de mano mientras conduce un CMV, además de la descalificación por infracciones graves reiteradas. Fuente: regla de conducción distraída de la FMCSA (49 CFR 392.80/392.82), aplicable en Dakota del Norte."},"52":{"q":"¿Cuál es la descalificación mínima de la CDL en Dakota del Norte por una PRIMERA condena por violar una orden de fuera de servicio (OOS) mientras se conduce un CMV sin HazMat y sin pasajeros?","options":["180 días","60 días","1 año","90 días"],"explanation":"Una primera violación de una orden de fuera de servicio resulta en una descalificación de al menos 180 días. Fuente: ND CDL Manual (Descalificación); NDCC 39-06.2-10.9; 49 CFR 383.51."},"53":{"q":"En Dakota del Norte, una SEGUNDA violación de una orden de fuera de servicio dentro de 10 años (sin HazMat, sin pasajeros) resulta en una descalificación de al menos:","options":["2 años","180 días","1 año","3 años"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de un período de 10 años descalifica al conductor por al menos 2 años. Fuente: ND CDL Manual (Descalificación); NDCC 39-06.2-10.9; 49 CFR 383.51."},"54":{"q":"Un titular de CDL de Dakota del Norte comete una TERCERA violación de una orden de fuera de servicio dentro de 10 años. ¿Cuál es la descalificación mínima?","options":["3 años","2 años","1 año","5 años"],"explanation":"Una tercera o subsiguiente violación de una orden de fuera de servicio dentro de un período de 10 años resulta en una descalificación de al menos 3 años. Fuente: ND CDL Manual (Descalificación); NDCC 39-06.2-10.9; 49 CFR 383.51."},"55":{"q":"¿Cuál es la descalificación mínima de la CDL por una PRIMERA violación de una orden de fuera de servicio mientras se transportan materiales peligrosos con letreros (placards) o mientras se conduce un vehículo diseñado para transportar 16 o más pasajeros?","options":["180 días","90 días","1 año","60 días"],"explanation":"Una primera violación de una orden OOS mientras se transporta HazMat con letreros (placards) o se opera un vehículo diseñado para 16 o más pasajeros conlleva una descalificación mínima de 180 días (el mismo mínimo de primera infracción que otros CMV, pero la segunda y tercera infracciones son más largas). Fuente: ND CDL Manual (Descalificación); 49 CFR 383.51."},"56":{"q":"¿Cuál es la descalificación mínima de la CDL en Dakota del Norte por una PRIMERA violación en un cruce a nivel de ferrocarril y carretera?","options":["60 días","30 días","120 días","1 año"],"explanation":"Una primera condena por una violación en un cruce a nivel de ferrocarril y carretera resulta en una descalificación de al menos 60 días. Fuente: ND CDL Manual (Descalificación); NDCC 39-06.2-10.6; 49 CFR 383.51."},"57":{"q":"Un titular de CDL de Dakota del Norte comete una SEGUNDA violación en un cruce a nivel de ferrocarril y carretera dentro de 3 años. ¿Cuál es la descalificación mínima?","options":["120 días","60 días","180 días","1 año"],"explanation":"Una segunda violación en un cruce a nivel de ferrocarril dentro de un período de 3 años resulta en una descalificación de al menos 120 días. Fuente: ND CDL Manual (Descalificación); NDCC 39-06.2-10.6; 49 CFR 383.51."},"58":{"q":"¿Cuál es la descalificación mínima por una TERCERA violación en un cruce a nivel de ferrocarril y carretera dentro de 3 años en Dakota del Norte?","options":["1 año","120 días","180 días","60 días"],"explanation":"Una tercera o subsiguiente violación en un cruce a nivel de ferrocarril dentro de un período de 3 años resulta en una descalificación de al menos 1 año (de al menos 180 días hasta 1 año según la regla, aplicándose el máximo). Fuente: ND CDL Manual (Descalificación); NDCC 39-06.2-10.6; 49 CFR 383.51."},"59":{"q":"Se encuentra que un conductor de CMV en Dakota del Norte tiene una cantidad de alcohol medible o detectable por debajo de 0.04 de BAC. ¿Cuál es la consecuencia inmediata?","options":["Puesto fuera de servicio durante 24 horas","Descalificado permanentemente","Acusado de una infracción mayor","Recibe una descalificación de 60 días"],"explanation":"Un conductor con cualquier concentración de alcohol medible por debajo de 0.04 debe ser puesto fuera de servicio durante 24 horas; un BAC de 0.04 o más es una infracción mayor descalificadora. Fuente: ND CDL Manual (Alcohol/Fuera de servicio); 49 CFR 392.5."},"60":{"q":"En una carretera interestatal de Dakota del Norte, fuera de una ciudad, usted se acerca a una grúa de remolque detenida en el acotamiento derecho con sus luces ámbar intermitentes encendidas. Según la ley \"Move Over\" (Cámbiese de Carril) de Dakota del Norte, ¿qué debe hacer el conductor de un vehículo comercial que se aproxima?","options":["Continuar a la velocidad indicada, ya que la ley solo cubre a los vehículos policiales","Detenerse por completo y esperar hasta que el vehículo se retire","Cambiarse al acotamiento izquierdo y detenerse","Cambiarse a un carril que no sea adyacente al vehículo detenido si se puede hacer de forma segura; de lo contrario, reducir la velocidad y pasar con precaución"],"explanation":"El North Dakota Century Code 39-10-26 exige que los conductores en una carretera interestatal o de varios carriles fuera de una ciudad se cambien a un carril que no sea adyacente a un vehículo de emergencia o de mantenimiento vial detenido que muestre luces ámbar/azules/blancas/rojas, si se puede hacer de forma segura; si no es posible, el conductor debe reducir la velocidad y proceder con precaución a una velocidad segura. Una enmienda de 2023 extendió esto a cualquier vehículo detenido que muestre las luces intermitentes de emergencia. Fuente: NDCC 39-10-26; ND Highway Patrol Move Over Law."},"61":{"q":"En 2023, Dakota del Norte amplió su ley \"Move Over\" (Cámbiese de Carril). Además de los vehículos autorizados de emergencia y de mantenimiento vial, ¿al acercarse a qué otro vehículo detenido aplica ahora el deber de cambiarse de carril o reducir la velocidad?","options":["Cualquier vehículo que muestre sus luces intermitentes de advertencia de emergencia","Únicamente los vehículos de reparto de correo","Únicamente los vehículos que muestren una luz azul","Cualquier vehículo estacionado dentro de los límites de la ciudad"],"explanation":"La ampliación de 2023 de la ley \"Move Over\" de Dakota del Norte (NDCC 39-10-26) añadió cualquier vehículo de motor detenido que muestre las luces intermitentes de advertencia de emergencia en una carretera interestatal o de varios carriles fuera de una ciudad. Fuente: NDCC 39-10-26; materiales de la ND Highway Patrol / NDDOT sobre la Move Over Law."},"62":{"q":"A partir del 1 de agosto de 2025, ¿cuál es el límite de velocidad máximo establecido por ley en las carreteras interestatales rurales de Dakota del Norte que son de acceso controlado, pavimentadas, divididas y de varios carriles (donde esté señalizado), y difiere para los camiones?","options":["75 mph para los autos pero 65 mph para los camiones","80 mph, aplicable a todos los vehículos incluyendo los camiones","70 mph para todos los vehículos","80 mph para los autos pero 70 mph para los camiones"],"explanation":"Según el NDCC 39-09-02 (modificado por el HB 1298, vigente desde el 1 de agosto de 2025), el máximo es de 80 mph en las carreteras interestatales rurales de acceso controlado y divididas. Dakota del Norte no establece por ley un límite de velocidad menor por separado para camiones, por lo que el límite aplica a todos los vehículos. Fuente: NDCC 39-09-02; orientación de NDDOT / ND Highway Patrol sobre límites de velocidad."},"63":{"q":"Según la ley de Dakota del Norte, ¿cuál es el límite de velocidad máximo en una carretera pavimentada, dividida y de varios carriles que NO sea una interestatal de acceso controlado?","options":["55 mph","65 mph","70 mph","80 mph"],"explanation":"El NDCC 39-09-02 fija 70 mph como el máximo legal presunto en carreteras pavimentadas, divididas y de varios carriles (que no sean interestatales, las cuales son de 80 mph). Fuente: NDCC 39-09-02."},"64":{"q":"En Dakota del Norte, en carreteras de grava, tierra o superficie suelta (y en carreteras pavimentadas de dos carriles de condado y de municipio) sin límite señalizado, ¿cuál es la velocidad máxima legal presunta?","options":["45 mph","50 mph","55 mph","65 mph"],"explanation":"El NDCC 39-09-02 fija 55 mph como el máximo legal presunto en carreteras de grava, tierra o superficie suelta y en carreteras pavimentadas de dos carriles de condado y de municipio donde no haya límite señalizado. Fuente: NDCC 39-09-02."},"65":{"q":"Un conductor que opera un vehículo comercial con placas (rótulos) de materiales peligrosos en Dakota del Norte se acerca a un cruce a nivel de ferrocarril donde se requiere detenerse. ¿Dónde debe detenerse el vehículo?","options":["Dentro de 75 pies pero no a menos de 25 pies del riel más cercano","Dentro de 100 pies pero no a menos de 50 pies del riel más cercano","Dentro de 50 pies pero no a menos de 15 pies del riel más cercano","En cualquier lugar dentro de 10 pies del riel más cercano"],"explanation":"El NDCC 39-10-43 exige que el conductor de un vehículo HazMat con placas (rótulos) (y de ciertos vehículos cisterna/de cloro) se detenga dentro de 50 pies pero no a menos de 15 pies del riel más cercano, y luego mire y escuche antes de proceder. Fuente: NDCC 39-10-43; ND CDL Manual."},"66":{"q":"En Dakota del Norte, ¿qué vehículo está obligado por ley a detenerse en todos los cruces a nivel de ferrocarril (no solo en los peligrosos)?","options":["Cualquier vehículo que remolque un tráiler","Un autobús que transporta pasajeros o un autobús escolar","Cualquier camioneta pickup usada para labores agrícolas","Cualquier vehículo con un peso bruto superior a 26,000 libras"],"explanation":"El NDCC 39-10-43 exige que el conductor de un autobús que transporta pasajeros, un autobús escolar y vehículos HazMat con placas (rótulos)/ciertos vehículos cisterna se detenga en todos los cruces a nivel de ferrocarril dentro de 50 pies pero no a menos de 15 pies del riel más cercano. Fuente: NDCC 39-10-43."},"67":{"q":"Después de detenerse en un cruce de ferrocarril según lo requerido en Dakota del Norte, ¿qué restricción adicional impone la ley a un conductor de autobús o de HazMat mientras cruza las vías?","options":["El conductor debe tocar la bocina de forma continua mientras cruza","El conductor no debe cambiar de marcha manualmente mientras cruza la vía","El conductor debe encender las cuatro luces intermitentes de emergencia mientras cruza","El conductor debe cruzar en la marcha más alta disponible"],"explanation":"El NDCC 39-10-43 indica que el conductor debe cruzar únicamente en una marcha que evite la necesidad de cambiar de marcha mientras está sobre el cruce, y el conductor no puede cambiar de marcha manualmente mientras cruza la vía. Fuente: NDCC 39-10-43; ND CDL Manual."},"68":{"q":"Según la regla de Dakota del Norte que exige detenerse para autobuses y vehículos HazMat en los cruces de ferrocarril, ¿cuándo NO se requiere detenerse?","options":["Cuando el vehículo está vacío","Cuando el tránsito está controlado por un oficial de policía, o en un cruce marcado como 'Exempt' (Exento) o 'Tracks out of service' (Vías fuera de servicio)","Cuando el conductor tiene más de un año de experiencia","Cuando el cruce está en un distrito comercial"],"explanation":"El NDCC 39-10-43 exime de detenerse cuando el tránsito está controlado por un oficial de policía, y en los cruces que el director haya designado y marcado claramente como 'Exempt' (Exento) o 'Tracks out of service' (Vías fuera de servicio). Fuente: NDCC 39-10-43."},"69":{"q":"Un autobús escolar de Dakota del Norte está detenido con sus luces rojas intermitentes y el brazo de pare (stop arm) activados para recoger niños. Un conductor comercial se aproxima en sentido contrario en una carretera de dos carriles. ¿Qué debe hacer el conductor?","options":["Reducir a 20 mph y pasar con precaución","Pasar solo por la izquierda a velocidad reducida","Continuar, porque el tránsito en sentido contrario nunca está obligado a detenerse","Detenerse antes de llegar al autobús y no continuar hasta que las luces y el brazo de pare ya no estén activados"],"explanation":"El NDCC 39-10-46 exige que un conductor que se cruza o alcanza a un autobús escolar desde cualquier dirección se detenga antes de llegar a él cuando las luces rojas intermitentes o el brazo de pare estén activados, y que no continúe hasta que el autobús se mueva, se le indique al conductor que avance, o las luces y el brazo ya no estén activados. Fuente: NDCC 39-10-46."},"70":{"q":"La ley de Dakota del Norte sobre la detención ante autobuses escolares contiene una excepción para carreteras divididas. Según el NDCC 39-10-46, un conductor NO necesita detenerse ante un autobús escolar detenido únicamente cuando:","options":["Hay dos o más carriles en la dirección del conductor","El autobús está en una calzada distinta de una carretera con calzadas separadas, o el conductor está en una carretera de acceso controlado y el autobús está en una zona de carga donde los peatones no pueden cruzar","Hay un carril central de giro a la izquierda de doble sentido entre el conductor y el autobús","La carretera tiene una línea central pintada"],"explanation":"Según el NDCC 39-10-46(5), la excepción aplica únicamente cuando el autobús está en una calzada DISTINTA de una carretera con calzadas separadas (físicamente divididas), o en una carretera de acceso controlado donde el autobús está en una zona de carga y los peatones no pueden cruzar. Un simple carril central de giro o una línea pintada no califica. Fuente: NDCC 39-10-46."},"71":{"q":"En una carretera no dividida de cuatro carriles de Dakota del Norte (dos carriles en cada sentido, separados únicamente por una línea central pintada), un autobús escolar que va en sentido contrario se detiene con las luces rojas intermitentes encendidas. ¿Debe detenerse el tránsito que viene en sentido contrario?","options":["No, porque hay varios carriles","No, el tránsito en sentido contrario nunca se detiene en una carretera de cuatro carriles","Solo debe detenerse el carril más cercano al autobús","Sí, porque la calzada no está físicamente dividida en calzadas separadas"],"explanation":"La excepción del NDCC 39-10-46 aplica únicamente en carreteras con calzadas separadas (físicamente divididas). En una carretera no dividida de varios carriles con solo una línea central pintada, el tránsito en sentido contrario aún debe detenerse ante un autobús escolar que muestre las luces rojas intermitentes y el brazo de pare. Fuente: NDCC 39-10-46."},"72":{"q":"Según la ley de Dakota del Norte, ¿a qué distancia, antes del punto donde se recibirán o se dejarán niños, puede un conductor de autobús escolar activar las luces ámbar de precaución (advertencia)?","options":["No menos de 100 pies ni más de 300 pies","No menos de 200 pies ni más de 400 pies","No menos de 300 pies ni más de 500 pies","Exactamente 250 pies"],"explanation":"El NDCC 39-10-46(3) permite activar las luces ámbar de precaución no menos de 300 pies ni más de 500 pies antes del punto donde se reciben o se dejan los niños. Fuente: NDCC 39-10-46."},"73":{"q":"La ley de Dakota del Norte exige que todo autobús escolar lleve en la parte trasera un letrero específico relacionado con los cruces de ferrocarril. ¿Qué dice?","options":["\"DO NOT PASS ON TRACKS\" (NO REBASAR SOBRE LAS VÍAS)","\"THIS SCHOOLBUS STOPS AT ALL RAILROAD CROSSINGS\" (ESTE AUTOBÚS ESCOLAR SE DETIENE EN TODOS LOS CRUCES DE FERROCARRIL)","\"CAUTION: RAILROAD AHEAD\" (PRECAUCIÓN: FERROCARRIL ADELANTE)","\"SCHOOLBUS YIELDS AT CROSSINGS\" (EL AUTOBÚS ESCOLAR CEDE EL PASO EN LOS CRUCES)"],"explanation":"El NDCC 39-10-46(6) exige que todo autobús escolar lleve en la parte trasera un letrero claramente visible que diga \"THIS SCHOOLBUS STOPS AT ALL RAILROAD CROSSINGS\" (ESTE AUTOBÚS ESCOLAR SE DETIENE EN TODOS LOS CRUCES DE FERROCARRIL). Fuente: NDCC 39-10-46."},"74":{"q":"Según las reglas de tránsito de Dakota del Norte, un vehículo comercial que circula a una velocidad inferior a la normal del tránsito en una carretera de varios carriles debe:","options":["Usar el carril izquierdo para mantenerse fuera del tránsito que se incorpora","Permanecer en cualquier carril que el conductor prefiera","Conducirse en el carril derecho o lo más cerca posible del borde derecho, excepto al rebasar o al prepararse para un giro a la izquierda","Usar el carril central en una carretera de tres carriles"],"explanation":"El NDCC 39-10-08(2) exige que todo vehículo que circule a una velocidad inferior a la normal del tránsito se mantenga en el carril derecho (o lo más cerca posible del borde derecho), excepto al rebasar o al prepararse para un giro a la izquierda. Fuente: NDCC 39-10-08."},"75":{"q":"El camión de un conductor con CDL de Dakota del Norte se descompone en una carretera no dividida de dos carriles, plana y recta, durante el día. Siguiendo las reglas sobre dispositivos de advertencia que aplica Dakota del Norte, ¿dónde deben colocarse los tres triángulos de advertencia?","options":["Los tres dentro de 10 pies de la parte trasera del camión","Aproximadamente a 50 pies, 150 pies y 250 pies detrás del vehículo","Uno en el techo y dos en el acotamiento","Aproximadamente a 10 pies detrás, 100 pies detrás y 100 pies adelante del vehículo"],"explanation":"Dakota del Norte sigue el estándar federal de colocación (49 CFR 392.22): en una carretera de dos carriles, coloque los triángulos a aproximadamente 10 pies detrás del vehículo del lado del tránsito, a aproximadamente 100 pies detrás y a aproximadamente 100 pies adelante. Fuente: ND CDL Manual; 49 CFR 392.22."},"76":{"q":"Cuando un conductor con CDL de Dakota del Norte está detenido en una carretera de un solo sentido o dividida, ¿cómo deben colocarse los tres triángulos de advertencia hacia el tránsito que se aproxima?","options":["Aproximadamente a 10 pies, 100 pies y 200 pies hacia el tránsito que se aproxima","Aproximadamente a 25 pies, 75 pies y 125 pies hacia el tránsito que se aproxima","Los tres a 100 pies hacia el tránsito que se aproxima","Aproximadamente a 50 pies, 100 pies y 150 pies hacia el tránsito que se aproxima"],"explanation":"En una carretera de un solo sentido o dividida, el estándar federal que aplica Dakota del Norte (49 CFR 392.22) requiere colocar los triángulos aproximadamente a 10 pies, 100 pies y 200 pies hacia el tránsito que se aproxima. Fuente: ND CDL Manual; 49 CFR 392.22."},"77":{"q":"Un conductor con CDL de Dakota del Norte que transporta una carga con placas (rótulos) de explosivos o líquido inflamable debe detenerse y colocar dispositivos de advertencia. ¿Qué dispositivo de advertencia está PROHIBIDO en dicho vehículo?","options":["Triángulos reflectantes de advertencia","Tres reflectores de emergencia rojos portátiles","Bengalas o fusees (cualquier señal que produzca llama)","Linternas eléctricas rojas"],"explanation":"Las bengalas, fusees o cualquier señal que produzca llama no pueden usarse en vehículos que transportan explosivos, gas/líquido inflamable, o que usan gas comprimido como combustible; en su lugar deben usarse triángulos reflectantes, reflectores rojos o linternas eléctricas rojas. Fuente: ND CDL Manual; 49 CFR 392.22 / 393.95."},"78":{"q":"Fuera del periodo de deshielo primaveral, la postura de Dakota del Norte respecto a los permisos de sobrepeso para cargas divisibles durante las restricciones de carga primaverales señalizadas es que:","options":["NO se emitirán permisos de sobrepeso para ninguna carga divisible durante las restricciones viales primaverales","Las cargas divisibles siempre pueden exceder los límites con un permiso estándar durante todo el año","Las restricciones primaverales solo aplican al sistema interestatal","Las cargas divisibles están exentas de todos los límites de peso por eje en primavera"],"explanation":"El NDDOT y la ND Highway Patrol no emiten permisos de sobrepeso para cargas divisibles durante las restricciones viales primaverales (de deshielo) señalizadas, las cuales típicamente rigen desde aproximadamente mediados de febrero hasta mayo, según las condiciones. Fuente: NDDOT North Dakota Load Restrictions; información de la ND Highway Patrol sobre permisos de sobredimensión/sobrepeso."},"79":{"q":"La ley de Dakota del Norte establece una velocidad máxima especialmente baja para un tipo específico de equipo. Un vehículo equipado con llantas de caucho sólido no puede conducirse a más de:","options":["5 mph","10 mph","20 mph","25 mph"],"explanation":"El NDCC 39-09-04.1 prohíbe conducir cualquier vehículo equipado con llantas de caucho sólido a más de 10 mph. Fuente: NDCC 39-09-04.1."},"80":{"q":"¿Qué agencia emite las Licencias de Conducir Comerciales (CDL) en Dakota del Norte?","options":["La División de Licencias de Conducir del Departamento de Transporte de Dakota del Norte (NDDOT)","La Administración Federal de Seguridad de Autotransportes (FMCSA)","La ND Highway Patrol","La oficina del sheriff del condado donde reside el conductor"],"explanation":"En Dakota del Norte, las CDL son emitidas por el Departamento de Transporte de Dakota del Norte (NDDOT) a través de su División de Licencias de Conducir; la FMCSA establece los estándares federales pero no emite licencias estatales. Fuente: páginas de Commercial Driver License del NDDOT."},"81":{"q":"Según la autocertificación médica de Dakota del Norte, ¿de cuántas categorías de autocertificación debe elegir un solicitante de CDL?","options":["Cuatro","Dos","Tres","Seis"],"explanation":"Dakota del Norte usa las cuatro categorías federales de autocertificación: interestatal no exceptuado, interestatal exceptuado, intraestatal no exceptuado e intraestatal exceptuado. Fuente: NDDOT CDL Medical Certification Requirements."},"82":{"q":"Un conductor de Dakota del Norte se autocertifica como 'interestatal no exceptuado'. ¿Qué requiere esto en cuanto a la calificación médica?","options":["El conductor debe obtener y mantener vigente un certificado médico de examinador DOT","El conductor está exento de todos los requisitos de certificación médica","El conductor solo necesita una exención de visión","El conductor debe aprobar una prueba estatal de aptitud física en lugar de un examen DOT"],"explanation":"Los conductores interestatales no exceptuados están sujetos al 49 CFR Parte 391 y deben obtener y mantener vigente un certificado médico de examinador DOT. Fuente: NDDOT CDL Medical Certification Requirements; 49 CFR 391.45."},"83":{"q":"¿Qué categoría de autocertificación en Dakota del Norte NO requiere un certificado médico de examinador DOT?","options":["Interestatal exceptuado","Interestatal no exceptuado","Intraestatal no exceptuado","Transportista interestatal de materiales peligrosos (hazmat)"],"explanation":"Los conductores que se certifican como 'exceptuados' (interestatal o intraestatal) operan exclusivamente en operaciones exceptuadas y no están obligados a tener un certificado médico de examinador; los conductores no exceptuados sí deben tenerlo. Fuente: NDDOT CDL Medical Certification Requirements."},"84":{"q":"A partir del 21 de abril de 2025, ¿cómo se presenta al estado el certificado médico de examinador DOT de un titular de CDL de Dakota del Norte?","options":["El examinador médico certificado lo carga electrónicamente; el NDDOT ya no acepta certificados en papel","El conductor envía por correo una copia en papel al NDDOT","El conductor envía por fax una copia a la División de Licencias de Conducir","El empleador lo presenta ante el secretario del condado"],"explanation":"A partir del 21 de abril de 2025, Dakota del Norte ya no acepta certificados médicos directamente; los examinadores médicos certificados a nivel nacional deben cargar el certificado electrónicamente al registro/estado. Fuente: aviso del NDDOT sobre el certificado médico de CDL."},"85":{"q":"Antes de presentar el examen de habilidades de la CDL en Dakota del Norte para una primera licencia Clase A o B, ¿qué capacitación debe completar un nuevo solicitante?","options":["Capacitación de Conductor de Nivel Inicial (ELDT) de un proveedor que figure en el Training Provider Registry","Un curso de conducción defensiva en aula en el condado","Un aprendizaje de cuatro años con un transportista autorizado","Una orientación únicamente del empleador sin requisito de registro"],"explanation":"Desde el 7 de febrero de 2022, las reglas federales de ELDT adoptadas por Dakota del Norte exigen que los nuevos solicitantes de CDL completen la capacitación de un proveedor listado en el Training Provider Registry de la FMCSA antes del examen de habilidades. Fuente: NDDOT 'How to Apply'; FMCSA ELDT."},"86":{"q":"El examen de habilidades de la CDL de Dakota del Norte consta de ¿qué tres partes, en orden?","options":["Inspección previa al viaje, control básico del vehículo y conducción en la carretera","Examen escrito de conocimientos, examen de la vista y conducción en la carretera","Estacionamiento en paralelo, examen escrito de hazmat y examen de frenos de aire","Inspección previa al viaje, examen del endoso de hazmat y conducción nocturna"],"explanation":"El examen de habilidades de la CDL de Dakota del Norte sigue el formato federal de tres partes: inspección del vehículo previa al viaje, habilidades básicas (de control) del vehículo y conducción en la carretera. Fuente: ND CDL Manual; páginas de CDL del NDDOT."},"87":{"q":"En Dakota del Norte, ¿qué debe obtener un solicitante antes de que se le permita presentar el examen de habilidades (de carretera) de la CDL?","options":["Un Permiso de Aprendiz Comercial (CLP) después de aprobar el/los examen(es) de conocimientos requerido(s)","Una CDL completa emitida de forma provisional","Un endoso de materiales peligrosos","Un número de autoridad operativa federal"],"explanation":"Los solicitantes primero deben aprobar el/los examen(es) de conocimientos y obtener un Permiso de Aprendiz Comercial (CLP) antes de programar el examen de habilidades. Fuente: NDDOT 'How to Apply for a Commercial Driver License.'"},"88":{"q":"¿Durante cuántos días debe haberse tenido un CLP de Dakota del Norte antes de que el titular pueda presentar el examen de habilidades de la CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","Al menos 60 días"],"explanation":"Dakota del Norte hace cumplir el periodo de espera federal de 14 días: un CLP debe haberse tenido durante al menos 14 días antes de que el solicitante pueda presentar el examen de habilidades de la CDL. Fuente: páginas de CDL del NDDOT; 49 CFR 383.25."},"89":{"q":"En Dakota del Norte, ¿por cuántos días consecutivos a partir de su fecha de emisión es válido un Permiso de Aprendiz Comercial?","options":["180 días","90 días","365 días","60 días"],"explanation":"Un CLP de Dakota del Norte es válido por hasta 180 días consecutivos a partir de la fecha de emisión; si no se aprueba el examen de carretera a tiempo, el permiso debe renovarse. Fuente: páginas de CDL del NDDOT."},"90":{"q":"Al practicar con un CLP de Dakota del Norte, ¿quién debe estar en el vehículo con el titular del permiso?","options":["Un titular de CDL con la misma clase/endosos o de clase/endosos superiores, sentado junto al conductor","Cualquier conductor licenciado de 21 años o más","Un oficial de la ND Highway Patrol","No se requiere a nadie si se practica fuera de las vías públicas"],"explanation":"Un titular de CLP solo puede conducir un vehículo comercial cuando va acompañado de un titular de CDL calificado (con la clase y los endosos adecuados) sentado a su lado. Fuente: páginas de CDL del NDDOT; 49 CFR 383.25."},"91":{"q":"¿Cuál es el ciclo estándar de renovación de una CDL de Dakota del Norte?","options":["Cuatro años","Cinco años","Dos años","Ocho años"],"explanation":"Las CDL de Dakota del Norte se emiten por un periodo de cuatro años y vencen a la medianoche del cumpleaños del conductor al final de ese ciclo. Fuente: NDDOT 'How to Renew a Commercial Driver License.'"},"92":{"q":"Una CDL de Dakota del Norte vence a la medianoche de ¿qué fecha del año de renovación?","options":["El cumpleaños del conductor","El 31 de diciembre","El aniversario de la fecha de emisión original","El último día del mes de emisión"],"explanation":"Las CDL de Dakota del Norte vencen a la medianoche del cumpleaños del conductor en el año de renovación. Fuente: información de renovación del NDDOT."},"93":{"q":"¿Qué documentos debe presentar normalmente un solicitante de CDL de Dakota del Norte al hacer la solicitud?","options":["Una licencia de conducir vigente, comprobante de presencia legal y comprobante de domicilio de residencia","Únicamente una tarjeta del Seguro Social","Solo un pasaporte y un registro de vehículo","Un acta de nacimiento y una licencia de caza"],"explanation":"El NDDOT exige que los solicitantes presenten una licencia de conducir vigente, comprobante de presencia legal/identidad y comprobante de domicilio de residencia en Dakota del Norte. Fuente: NDDOT 'How to Apply for a Commercial Driver License.'"},"94":{"q":"¿Cuál es la edad mínima para obtener una CDL solo intraestatal (dentro de Dakota del Norte)?","options":["18 años","16 años","21 años","19 años"],"explanation":"Dakota del Norte permite una CDL intraestatal a los 18 años; la operación interestatal (y hazmat) generalmente requiere tener 21 años. Fuente: NDDOT 'How to Apply'; 49 CFR 383/391."},"95":{"q":"¿Cuál es la edad mínima para obtener una CDL válida para conducción interestatal (o para un endoso de hazmat) en Dakota del Norte?","options":["21 años","18 años","19 años","25 años"],"explanation":"La operación interestatal de la CDL, y el endoso de materiales peligrosos, requieren que el conductor tenga al menos 21 años. Fuente: requisitos de CDL del NDDOT; reglas federales de CDL."},"96":{"q":"Para obtener un CLP de Dakota del Norte, además de aprobar el examen de conocimientos, ¿qué examen se requiere?","options":["Un examen de la vista (visión)","Una prueba de audición administrada por el NDDOT","Una prueba de detección de drogas y alcohol en la oficina del DOT","Una evaluación psicológica"],"explanation":"Dakota del Norte exige un examen de la vista/visión para emitir un CLP, junto con la aprobación del/los examen(es) de conocimientos requerido(s). Fuente: NDDOT 'How to Apply for a Commercial Driver License.'"},"97":{"q":"Si un solicitante de CDL de Dakota del Norte reprueba el examen de conocimientos, ¿cuál es la política del NDDOT para volver a presentarlo?","options":["Por lo general se permite un intento por día; el solicitante regresa otro día para volver a presentarlo","El solicitante debe esperar 30 días antes de cualquier nuevo intento","El solicitante queda permanentemente inhabilitado tras una reprobación","Se permiten nuevos intentos ilimitados el mismo día"],"explanation":"El NDDOT generalmente limita el examen de conocimientos a un intento por día, por lo que un solicitante que repruebe debe regresar otro día para volver a presentarlo. Fuente: información del NDDOT sobre exámenes/tarifas de CDL. (Las tarifas exactas pueden cambiar.)"},"98":{"q":"Un conductor desea agregar un endoso de autobús escolar (S) a una CDL de Dakota del Norte por primera vez. ¿Qué paso del proceso se requiere antes del examen de habilidades/endoso?","options":["Completar la Capacitación de Conductor de Nivel Inicial (ELDT) requerida para el endoso S","Solo aprobar un examen de la vista","Tener la CDL base durante al menos cinco años","Obtener un permiso aparte solo intraestatal"],"explanation":"Agregar por primera vez un endoso de pasajeros (P), autobús escolar (S) o hazmat (H) activa el requisito de ELDT, el cual debe completarse antes del examen. Fuente: páginas de CDL del NDDOT; regla de ELDT de la FMCSA vigente desde el 7 de febrero de 2022."},"99":{"q":"En el examen de habilidades de la CDL de Dakota del Norte, la parte de control básico del vehículo evalúa principalmente ¿qué habilidades?","options":["Maniobras como retroceso en línea recta, estacionamiento/acoplamiento (docking) y giros controlados","Leer señales de tránsito de memoria","Calcular los límites de peso de los puentes","Responder preguntas orales sobre hazmat"],"explanation":"La parte de control básico del vehículo evalúa maniobras de control a baja velocidad, como el retroceso en línea recta, el acoplamiento en callejón (alley docking), el estacionamiento en paralelo y los giros precisos. Fuente: ND CDL Manual; formato del examen de habilidades del NDDOT."}},"hi":{"0":{"q":"नॉर्थ डकोटा के राजमार्गों पर, किसी वाहन और उसके भार की अधिकतम कानूनी कुल बाहरी चौड़ाई कितनी है?","options":["8 feet 6 inches","8 feet","9 feet","10 feet"],"explanation":"नॉर्थ डकोटा सभी राजमार्गों पर वाहन की कुल बाहरी चौड़ाई, भार सहित, 8 feet 6 inches तक सीमित करता है (NDCC 39-12-04; NDHP Motor Carrier Operations Legal Size and Weight Guide, Ref 9-1, Sec. A)। इससे अधिक चौड़े भार के लिए परमिट आवश्यक है।"},"1":{"q":"नॉर्थ डकोटा के राजमार्गों पर किसी वाहन की अधिकतम कानूनी ऊंचाई, भरा हुआ या खाली, कितनी है?","options":["13 feet 6 inches","14 feet","13 feet","15 feet"],"explanation":"नॉर्थ डकोटा वाहन की अधिकतम कानूनी ऊंचाई 14 feet निर्धारित करता है, चाहे वह भरा हुआ हो या खाली, लेकिन चालक को फिर भी 14 feet से नीचे के पुलों और अंडरपास के नीचे से निकलने का ध्यान रखना चाहिए (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. B)।"},"2":{"q":"नॉर्थ डकोटा में, किसी ट्रेलर या सेमीट्रेलर की उसके भार सहित अधिकतम लंबाई कितनी है (1 जुलाई 1987 के बाद पंजीकृत इकाइयों के लिए)?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"नॉर्थ डकोटा में कोई ट्रेलर या सेमीट्रेलर, भार सहित, 53 feet से अधिक नहीं हो सकता; राज्य में 1 जुलाई 1987 से पहले टाइटल और पंजीकृत ट्रेलर/सेमीट्रेलर और खींचे जाने वाले वाहन 60 feet तक पहुंच सकते हैं (NDCC 39-12-04; NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.4)।"},"3":{"q":"नॉर्थ डकोटा में इंटरस्टेट राजमार्ग प्रणाली पर अनुमत अधिकतम सकल वाहन वजन कितना है?","options":["85,500 pounds","90,000 pounds","80,000 pounds","105,500 pounds"],"explanation":"नॉर्थ डकोटा में इंटरस्टेट राजमार्ग प्रणाली पर अधिकतम सकल वाहन वजन 80,000 pounds है (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.b), जो संघीय इंटरस्टेट सीमा के अनुरूप है।"},"4":{"q":"नॉर्थ डकोटा में, कोई एकल धुरा (single axle) कितने pounds से अधिक सकल वजन नहीं उठा सकता?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"explanation":"नॉर्थ डकोटा एकल धुरे को अधिकतम 20,000 pounds सकल वजन तक सीमित करता है (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.b)। 40 inches या उससे कम दूरी पर लगे धुरों को एक धुरा माना जाता है।"},"5":{"q":"नॉर्थ डकोटा एक टैंडम धुरे (tandem axle) पर अधिकतम कितना सकल वजन अनुमत करता है?","options":["32,000 pounds","36,000 pounds","40,000 pounds","34,000 pounds"],"explanation":"नॉर्थ डकोटा में एक टैंडम धुरे का सकल वजन 34,000 pounds से अधिक नहीं हो सकता (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.c), जो संघीय टैंडम-धुरा सीमा से मेल खाता है।"},"6":{"q":"नॉर्थ डकोटा में दो या अधिक धुरों वाले किसी एकल-इकाई वाहन (single-unit vehicle) की उसके भार सहित अधिकतम लंबाई कितनी है?","options":["40 feet","45 feet","50 feet","53 feet"],"explanation":"नॉर्थ डकोटा में दो या अधिक धुरों वाला एकल-इकाई वाहन, भार सहित, 50 feet से अधिक नहीं हो सकता (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.1)।"},"7":{"q":"नॉर्थ डकोटा के इंटरस्टेट प्रणाली के अलावा अन्य राजमार्गों पर, 8 feet या उससे अधिक दूरी पर लगे दो अलग-अलग धुरों के लिए अधिकतम कितना सकल वजन अनुमत है?","options":["34,000 pounds","36,000 pounds","40,000 pounds","44,000 pounds"],"explanation":"नॉर्थ डकोटा में इंटरस्टेट प्रणाली के अलावा अन्य राजमार्गों पर, 8 feet या उससे अधिक दूरी पर लगे दो अलग-अलग धुरों का संयुक्त सकल वजन 40,000 pounds से अधिक नहीं हो सकता (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.b)।"},"8":{"q":"नॉर्थ डकोटा में गैर-निर्दिष्ट (non-designated) राजमार्गों पर, दो, तीन, या चार इकाइयों के संयोजन की, भार सहित, अधिकतम लंबाई कितनी है?","options":["65 feet","70 feet","75 feet","85 feet"],"explanation":"नॉर्थ डकोटा के गैर-निर्दिष्ट राजमार्गों पर दो, तीन, या चार इकाइयों का संयोजन, भार सहित, 75 feet से अधिक नहीं हो सकता; NDDOT द्वारा निर्दिष्ट चार-लेन विभाजित राजमार्गों पर ऐसे संयोजन 95 या 110 feet तक पहुंच सकते हैं (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.2 and C.3)।"},"9":{"q":"नॉर्थ डकोटा के राज्य राजमार्गों पर (इंटरस्टेट के अलावा), अधिकतम सकल वाहन वजन आम तौर पर 80,000 pounds है जब तक कि मार्ग अधिक के लिए निर्दिष्ट न हो, जो किस सीमा से अधिक नहीं हो सकता?","options":["100,000 pounds","105,500 pounds","110,000 pounds","129,000 pounds"],"explanation":"नॉर्थ डकोटा के गैर-इंटरस्टेट राजमार्गों पर अधिकतम सकल वाहन वजन 80,000 pounds है जब तक कि राजमार्ग अधिक के लिए निर्दिष्ट न हो, ऐसी स्थिति में यह 105,500 pounds से अधिक नहीं हो सकता (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.2.a)।"},"10":{"q":"नॉर्थ डकोटा में लागू संघीय ब्रिज फॉर्मूले के तहत, टैंडम धुरों के दो लगातार सेट प्रत्येक 34,000 pounds उठा सकते हैं बशर्ते उन टैंडम सेटों के पहले और अंतिम धुरों के बीच की दूरी कम से कम कितने feet हो?","options":["30 feet","34 feet","36 feet","40 feet"],"explanation":"नॉर्थ डकोटा ब्रिज फॉर्मूला W = 500(LN/(N-1) + 12N + 36) लागू करता है, लेकिन टैंडम धुरों के दो लगातार सेट प्रत्येक 34,000 pounds उठा सकते हैं यदि उन सेटों के पहले और अंतिम धुरों के बीच कुल दूरी कम से कम 36 feet हो (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.a)।"},"11":{"q":"नॉर्थ डकोटा के ब्रिज फॉर्मूला W = 500(LN/(N-1) + 12N + 36) में, अक्षर N क्या दर्शाता है?","options":["समूह में धुरों की संख्या","धुरों के दोनों छोरों के बीच की दूरी","भार का शुद्ध वजन","pounds में अधिकतम वजन"],"explanation":"नॉर्थ डकोटा के ब्रिज फॉर्मूले में, W धुरों के एक समूह पर अधिकतम वजन है, L समूह के छोरों के बीच feet में दूरी है, और N समूह में धुरों की संख्या है (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.a)।"},"12":{"q":"नॉर्थ डकोटा में इंटरस्टेट प्रणाली के अलावा अन्य राजमार्गों पर, तीन या अधिक धुरों के समूह पर अनुमत अधिकतम सकल वजन कितना है?","options":["42,000 pounds","51,000 pounds","54,000 pounds","48,000 pounds"],"explanation":"नॉर्थ डकोटा के इंटरस्टेट प्रणाली के अलावा अन्य राजमार्गों पर, तीन या अधिक धुरों के समूह का सकल वजन 48,000 pounds से अधिक नहीं हो सकता; इंटरस्टेट पर यह समूह ब्रिज फॉर्मूले द्वारा नियंत्रित होता है (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.c)।"},"13":{"q":"नॉर्थ डकोटा में सिंगल-ट्रिप ओवरसाइज़/ओवरवेट परमिट कब आवश्यक होता है?","options":["खतरनाक सामग्री ले जाने वाले किसी भी वाणिज्यिक वाहन के लिए","केवल अंधेरे के बाद इंटरस्टेट पर चलने वाले भार के लिए","ऐसे गैर-कम करने योग्य (non-reducible) भार के लिए जो नॉर्थ डकोटा की कानूनी आकार और/या वजन सीमा से अधिक हो","26,001 pounds से अधिक वजन वाले किसी भी वाहन के लिए"],"explanation":"नॉर्थ डकोटा ऐसे गैर-कम करने योग्य ओवरसाइज़ और/या ओवरवेट भार की आवाजाही के लिए सिंगल-ट्रिप ओवरसाइज़/ओवरवेट परमिट आवश्यक करता है जो राज्य की कानूनी वाहन आकार और वजन सीमा से अधिक हो (NDHP Oversize/Overweight Permit, e-permits)।"},"14":{"q":"नॉर्थ डकोटा का सिंगल-ट्रिप ओवरसाइज़/ओवरवेट परमिट एक भार आवाजाही के लिए कितने समय तक वैध रहता है?","options":["Up to 24 hours","Up to 3 days","Up to 5 days","Up to 7 days"],"explanation":"नॉर्थ डकोटा का सिंगल-ट्रिप ओवरसाइज़/ओवरवेट परमिट एक भार आवाजाही के लिए up to 5 days तक वैध रहता है (NDHP Oversize/Overweight Permit, e-permits system at nd.gov/ndhp)।"},"15":{"q":"नॉर्थ डकोटा का हार्वेस्ट वेट छूट परमिट किसी ऐसे वाहन को जो खेत से भंडारण या बिक्री के पहले स्थान तक कटाई किया हुआ कृषि उत्पाद ले जा रहा हो, कितना अतिरिक्त वजन ले जाने की अनुमति देता है?","options":["5 percent more weight","10 percent more weight","15 percent more weight","20 percent more weight"],"explanation":"नॉर्थ डकोटा का हार्वेस्ट वेट छूट परमिट खेत से भंडारण के प्रारंभिक स्थान या बिक्री के पहले स्थान तक कटाई किया हुआ उत्पाद ले जाने पर 10% अधिक वजन की अनुमति देता है, जो 15 जुलाई से 30 नवंबर तक वैध है, और सकल वजन 105,500 pounds से अधिक नहीं हो सकता (NDHP e-permits, Harvest Weight Exemption Permit)।"},"16":{"q":"नॉर्थ डकोटा का हार्वेस्ट वेट छूट परमिट किस तारीख सीमा के दौरान वैध रहता है?","options":["May 1 - September 30","June 1 - October 31","July 15 - November 30","August 1 - December 31"],"explanation":"नॉर्थ डकोटा का हार्वेस्ट वेट छूट परमिट खेत से भंडारण के प्रारंभिक स्थान या पहली बिक्री तक कटाई किए गए उत्पादों को ले जाने के लिए July 15 और November 30 के बीच वैध रहता है (NDHP e-permits, Harvest Weight Exemption Permit)।"},"17":{"q":"नॉर्थ डकोटा में, किसी निवासी किसान द्वारा सूर्योदय और सूर्यास्त के बीच (इंटरस्टेट पर नहीं) ले जाया जा रहा कोई कृषि उपकरण (implement of husbandry) सामान्य 14-foot ऊंचाई सीमा से अधिक किस अधिकतम ऊंचाई तक जा सकता है?","options":["14 feet 6 inches","15 feet","15 feet 6 inches","16 feet"],"explanation":"नॉर्थ डकोटा निवासी किसानों, पशुपालकों, डीलरों, या निर्माताओं द्वारा सूर्योदय और सूर्यास्त के बीच, 60 miles से अधिक न होने वाली दूरी के लिए और इंटरस्टेट पर नहीं, ले जाए जाने पर कृषि उपकरणों को 15 feet 6 inches की ऊंचाई तक पहुंचने की अनुमति देता है (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. B.2.a)।"},"18":{"q":"मुख्य रूप से प्राकृतिक गैस से चलने वाला कोई नॉर्थ डकोटा वाहन सकल वजन सीमा से कितना अधिक हो सकता है, और किस अधिकतम तक?","options":["Up to 1,000 pounds, max 81,000 pounds","Up to 2,000 pounds, max 82,000 pounds","Up to 2,500 pounds, max 82,500 pounds","Up to 4,000 pounds, max 84,000 pounds"],"explanation":"मुख्य रूप से प्राकृतिक गैस से ईंधित इंजन द्वारा चलाया जाने वाला कोई नॉर्थ डकोटा वाहन भारी ईंधन प्रणाली को ध्यान में रखते हुए वजन सीमा से up to 2,000 pounds अधिक हो सकता है, अधिकतम सकल वजन 82,000 pounds तक (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.8)।"},"19":{"q":"नॉर्थ डकोटा में, स्टीयरिंग धुरे का वजन निर्माता की धुरा रेटिंग द्वारा निर्धारित होता है लेकिन इंटरस्टेट प्रणाली पर चलते समय कितने pounds से अधिक नहीं हो सकता?","options":["12,000 pounds","18,000 pounds","20,000 pounds","24,000 pounds"],"explanation":"नॉर्थ डकोटा स्टीयरिंग धुरे को निर्माता की धुरा रेटिंग तक सीमित करता है, जो इंटरस्टेट प्रणाली पर 20,000 pounds से अधिक नहीं हो सकती, और कोई भी टायर टायर चौड़ाई के प्रति inch 550 pounds से अधिक नहीं हो सकता (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.a)।"},"20":{"q":"नॉर्थ डकोटा में, 26,001 pounds या उससे अधिक सकल संयोजन वजन रेटिंग (GCWR) वाले वाहनों के किसी भी संयोजन को चलाने के लिए कौन-सा CDL वर्ग आवश्यक है, बशर्ते खींचे जा रहे वाहन(नों) का GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"नॉर्थ डकोटा का CDL Class A (संयोजन वाहन) 26,001 lbs या उससे अधिक GCWR वाले वाहनों के किसी भी संयोजन को कवर करता है जब खींची जा रही इकाई का GVWR 10,000 lbs से अधिक हो। स्रोत: NDDOT Commercial Driver License page और ND CDL Manual; 49 CFR 383.91।"},"21":{"q":"नॉर्थ डकोटा के नियमों के तहत, Class B CDL किसी चालक को निम्नलिखित में से किसे चलाने का अधिकार देता है?","options":["26,001 lbs या उससे अधिक GVWR वाला कोई भी एकल वाहन, जो 10,000 lbs GVWR से अधिक न खींची जा रही इकाई को खींच रहा हो","26,001 lbs GCWR से अधिक वाहनों का कोई भी संयोजन जिसमें खींची जा रही इकाई 10,000 lbs से अधिक हो","केवल 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन","केवल 26,001 lbs GVWR से कम वाहन जो प्लेकार्ड वाली खतरनाक सामग्री ले जा रहे हों"],"explanation":"ND Class B (भारी सीधा वाहन) 26,001 lbs या उससे अधिक GVWR वाले किसी भी एकल वाहन, या ऐसे वाहन को कवर करता है जो 10,000 lbs GVWR से अधिक न खींची जा रही इकाई को खींच रहा हो। स्रोत: NDDOT Commercial Driver License page और ND CDL Manual; 49 CFR 383.91।"},"22":{"q":"कोई नॉर्थ डकोटा चालक 26,001 lbs GVWR से कम रेटेड एक एकल वाहन चलाता है जो 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया है। कौन-सा CDL वर्ग लागू होता है?","options":["Class C","Class A","Class B","किसी CDL की आवश्यकता नहीं"],"explanation":"ND Class C (छोटा वाहन) उन एकल वाहनों पर लागू होता है जो 26,001 lbs GVWR से कम हैं और जो 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किए गए हैं या जो प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ले जाते हैं। स्रोत: NDDOT Commercial Driver License page और ND CDL Manual; 49 CFR 383.91।"},"23":{"q":"किसी ऐसे टैंक वाहन को चलाने के लिए कौन-सा नॉर्थ डकोटा CDL एंडोर्समेंट आवश्यक है जिसका उपयोग 119 gallons से अधिक की व्यक्तिगत रेटेड क्षमता (और कुल मिलाकर 1,000 gallons या अधिक) वाले स्थायी रूप से लगे टैंक में किसी तरल या गैस को ले जाने के लिए किया जाता है?","options":["N (Tank Vehicles)","H (Hazardous Materials)","T (Doubles/Triples)","P (Passenger)"],"explanation":"ND में व्यक्तिगत रूप से 119 gallons से अधिक या कुल मिलाकर 1,000 gallons या अधिक रेटेड टैंक में तरल या गैस ले जाने के लिए N एंडोर्समेंट आवश्यक है। स्रोत: NDDOT Commercial Driver License page; 49 CFR 383.93।"},"24":{"q":"नॉर्थ डकोटा में, डबल या ट्रिपल ट्रेलर खींचने के लिए किसी CDL धारक को कौन-सा एंडोर्समेंट प्राप्त करना चाहिए?","options":["T (Doubles/Triples)","N (Tank Vehicles)","X (Tank/HazMat combination)","P (Passenger)"],"explanation":"T एंडोर्समेंट नॉर्थ डकोटा में डबल या ट्रिपल ट्रेलर खींचने का अधिकार देता है और इसे डबल्स/ट्रिपल्स ज्ञान परीक्षा पास करके प्राप्त किया जाता है। स्रोत: NDDOT Commercial Driver License page और ND CDL Manual; 49 CFR 383.93।"},"25":{"q":"केवल इंट्रास्टेट ड्राइविंग (नॉर्थ डकोटा के भीतर) के लिए वैध नॉर्थ डकोटा CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 years old","16 years old","19 years old","21 years old"],"explanation":"नॉर्थ डकोटा 18 वर्ष की आयु में केवल-इंट्रास्टेट ड्राइविंग के लिए CDL की अनुमति देता है। इंटरस्टेट वाणिज्य में संचालन के लिए चालकों की आयु 21 होनी चाहिए। स्रोत: NDDOT CDL requirements; NDCC Title 39; 49 CFR 383।"},"26":{"q":"ऐसे नॉर्थ डकोटा CDL आवेदक को जो इंटरस्टेट वाणिज्य में चलाना, खतरनाक सामग्री ले जाना, या किराए पर यात्रियों को ले जाना चाहता है, कम से कम कितनी आयु का होना चाहिए?","options":["21 years old","18 years old","19 years old","25 years old"],"explanation":"नॉर्थ डकोटा राज्य की सीमाओं के पार (इंटरस्टेट) संचालन करने, खतरनाक सामग्री ले जाने, या किराए पर यात्रियों को ले जाने के लिए चालक की आयु कम से कम 21 वर्ष होना आवश्यक करता है। स्रोत: NDDOT CDL requirements; 49 CFR 383।"},"27":{"q":"नॉर्थ डकोटा कमर्शियल लर्नर्स परमिट (CLP) जारी होने के बाद, किसी आवेदक को CDL स्किल्स (रोड) टेस्ट देने के योग्य होने से पहले कितने समय तक प्रतीक्षा करनी चाहिए?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"explanation":"नॉर्थ डकोटा उस संघीय नियम का पालन करता है जिसके अनुसार आवेदक द्वारा CDL स्किल्स टेस्ट देने से पहले CLP को कम से कम 14 days तक रखना आवश्यक है। स्रोत: NDDOT CDL application page; 49 CFR 383.25।"},"28":{"q":"नॉर्थ डकोटा में Hazardous Materials (H) एंडोर्समेंट प्राप्त करने से पहले, आवेदक को कौन-सी संघीय रूप से आवश्यक पृष्ठभूमि जांच पास करनी चाहिए?","options":["एक TSA सुरक्षा खतरा मूल्यांकन, जिसमें फिंगरप्रिंटिंग शामिल है","बिना फिंगरप्रिंट के केवल FBI आपराधिक इतिहास जांच","राज्य द्वारा संचालित एक पॉलीग्राफ परीक्षा","केवल नियोक्ता द्वारा की गई संदर्भ जांच"],"explanation":"ND H-एंडोर्समेंट आवेदकों को एंडोर्समेंट जोड़े जाने से पहले TSA सुरक्षा खतरा मूल्यांकन पूरा करना होगा, जिसमें फिंगरप्रिंट जमा करना शामिल है। स्रोत: NDDOT Hazardous Material Requirements page; 49 CFR 1572 / TSA।"},"29":{"q":"किसी नॉर्थ डकोटा आवेदक द्वारा नए Hazardous Materials (H) एंडोर्समेंट के लिए ज्ञान परीक्षा देने से पहले अब कौन-सा प्रवेश-स्तरीय प्रशिक्षण चरण आवश्यक है?","options":["FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से संघीय ELDT हैज़मैट सिद्धांत प्रशिक्षण","एक 40-घंटे की इन-कैब टैंकर शिक्षुता (apprenticeship)","एक नॉर्थ डकोटा राज्य-संचालित हैज़मैट अकादमी पाठ्यक्रम","किसी प्रशिक्षण की आवश्यकता नहीं, केवल ज्ञान परीक्षा"],"explanation":"ND में प्रारंभिक H-एंडोर्समेंट आवेदकों को ज्ञान परीक्षा से पहले FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से संघीय रूप से आवश्यक हैज़मैट सिद्धांत Entry-Level Driver Training (ELDT) पूरा करना होगा। स्रोत: NDDOT Hazardous Material Requirements page; 49 CFR 380।"},"30":{"q":"पहला नॉर्थ डकोटा Class A CDL प्राप्त करने से पहले आवश्यक Entry-Level Driver Training (ELDT) किस प्रणाली के माध्यम से पूरा किया जाना चाहिए?","options":["FMCSA Training Provider Registry पर सूचीबद्ध एक प्रदाता","कोई भी नॉर्थ डकोटा सामुदायिक कॉलेज, बिना किसी संघीय सूचीकरण के","NDDOT की आंतरिक ड्राइवर अकादमी","चालक की पसंद का कोई भी राज्य-बाहरी ट्रकिंग नियोक्ता"],"explanation":"ND को प्रारंभिक Class A CDL के लिए स्किल्स टेस्ट से पहले FMCSA Training Provider Registry पर सूचीबद्ध किसी स्कूल या संस्था के माध्यम से ELDT पूरा करना आवश्यक है। स्रोत: NDDOT How to Apply for a CDL page; 49 CFR 380 Subpart F।"},"31":{"q":"किसी नॉर्थ डकोटा चालक को 16 या अधिक लोगों (चालक सहित) को ले जाने के लिए डिज़ाइन किए गए वाहन (स्कूल बस के अलावा) को चलाने के लिए कौन-सा एंडोर्समेंट चाहिए?","options":["P (Passenger)","S (School Bus)","N (Tank)","T (Doubles/Triples)"],"explanation":"16 या अधिक लोगों (चालक सहित) को ले जाने के लिए डिज़ाइन की गई बस या अन्य वाहन को चलाने के लिए P (Passenger) एंडोर्समेंट आवश्यक है। स्कूल बस के लिए अलग S एंडोर्समेंट भी आवश्यक होता है। स्रोत: ND CDL Manual; 49 CFR 383.93।"},"32":{"q":"किसी नॉर्थ डकोटा CDL में School Bus (S) एंडोर्समेंट जोड़ने के लिए, चालक के पास और कौन-सा एंडोर्समेंट होना आवश्यक है?","options":["P (Passenger)","N (Tank)","H (Hazardous Materials)","T (Doubles/Triples)"],"explanation":"नॉर्थ डकोटा में S (School Bus) एंडोर्समेंट के लिए चालक के पास पहले P (Passenger) एंडोर्समेंट होना आवश्यक है, साथ ही स्कूल बस ज्ञान और स्किल्स परीक्षाओं को पास करना होगा। स्रोत: ND CDL Manual; 49 CFR 383.93।"},"33":{"q":"नॉर्थ डकोटा CDL के लिए आवेदन करते समय, आवेदक को सोशल सिक्योरिटी नंबर का प्रमाण देना होगा। इनमें से कौन-सा एक स्वीकार्य दस्तावेज़ है?","options":["मूल सोशल सिक्योरिटी कार्ड","सोशल सिक्योरिटी कार्ड की एक फोटोकॉपी","SSN सूचीबद्ध करने वाला एक हस्तलिखित नोट","नंबर दिखाने वाला एक लाइब्रेरी कार्ड"],"explanation":"ND को सोशल सिक्योरिटी नंबर का प्रमाण आवश्यक है, जैसे मूल सोशल सिक्योरिटी कार्ड; फोटोकॉपी स्वीकार नहीं की जाती और दस्तावेज़ मूल या प्रमाणित होने चाहिए। स्रोत: NDDOT Driver License Requirements / REAL ID checklist।"},"34":{"q":"अपना नॉर्थ डकोटा आवासीय पता स्थापित करने के लिए नॉर्थ डकोटा को आवेदक से कितने निवास-प्रमाण दस्तावेज़ प्रस्तुत करने की आवश्यकता होती है?","options":["दो दस्तावेज़","एक दस्तावेज़","तीन दस्तावेज़","किसी निवास प्रमाण की आवश्यकता नहीं"],"explanation":"नॉर्थ डकोटा को आवेदक के नॉर्थ डकोटा निवास पते को सिद्ध करने वाले दो दस्तावेज़ों की आवश्यकता होती है (उदा. यूटिलिटी/वित्तीय विवरण, कर रिकॉर्ड)। स्रोत: NDDOT Driver License Requirements / REAL ID checklist।"},"35":{"q":"पहचान, सोशल सिक्योरिटी नंबर, और निवास के अलावा, किसी नॉर्थ डकोटा CDL आवेदक को कौन-सा अतिरिक्त प्रमाण देना होगा?","options":["अमेरिकी नागरिकता, वैध स्थायी निवास, या कानूनी/अस्थायी उपस्थिति का प्रमाण","वर्तमान नियोक्ता से एक नोटरीकृत पत्र","वाहन स्वामित्व का प्रमाण","एक हाई स्कूल डिप्लोमा"],"explanation":"ND को पहचान, SSN, और निवास के अलावा संयुक्त राज्य अमेरिका में नागरिकता, वैध स्थायी निवास, या कानूनी उपस्थिति का प्रमाण आवश्यक है। स्रोत: NDDOT Driver License Requirements page।"},"36":{"q":"कोई नॉर्थ डकोटा CDL आवेदक जो इंटरस्टेट वाणिज्य में चलाता है और जिसे Medical Examiner's Certificate रखना होगा, किस श्रेणी के तहत स्व-प्रमाणन (self-certify) करेगा?","options":["Interstate, non-excepted (NI)","Interstate, excepted (EI)","Intrastate, non-excepted (NA)","Intrastate, excepted (EA)"],"explanation":"इंटरस्टेट वाणिज्य में ऐसे चालक जिन्हें संघीय शारीरिक-योग्यता मानकों को पूरा करना होता है, Interstate Non-Excepted के रूप में स्व-प्रमाणन करते हैं और उन्हें ND के पास एक वैध Medical Examiner's Certificate फाइल पर रखना होगा। स्रोत: NDDOT CDL self-certification; 49 CFR 383.71 / 391।"},"37":{"q":"किसी नॉर्थ डकोटा CDL धारक को उस वाणिज्य के प्रकार को प्रमाणित करते समय जिसमें वह संचालन करता है, कितनी चिकित्सा स्व-प्रमाणन श्रेणियों में से चुनना होगा?","options":["चार (interstate non-excepted, interstate excepted, intrastate non-excepted, intrastate excepted)","दो (केवल interstate और intrastate)","तीन (interstate, intrastate, और exempt)","पांच (प्रति CDL एंडोर्समेंट एक)"],"explanation":"ND द्वारा अपनाए गए संघीय नियमों के अनुसार चार स्व-प्रमाणन श्रेणियों में से एक चुनना आवश्यक है: interstate non-excepted, interstate excepted, intrastate non-excepted, या intrastate excepted। स्रोत: NDDOT CDL self-certification; 49 CFR 383.71।"},"38":{"q":"नॉर्थ डकोटा जिस संघीय मानक का पालन करता है, उसके तहत, ज्ञान परीक्षाओं को दोबारा दिए बिना नवीनीकृत किए जाने से पहले कोई कमर्शियल लर्नर्स परमिट (CLP) अधिकतम कितनी अवधि तक वैध रह सकता है?","options":["180 days","30 days","12 months","5 years"],"explanation":"कोई CLP up to 180 days तक वैध रहता है और एक-वर्ष की खिड़की के भीतर बिना दोबारा परीक्षा दिए एक बार अन्य 180 days के लिए नवीनीकृत किया जा सकता है; ND इस संघीय मानक के तहत CLP जारी करता है। स्रोत: ND CDL Manual; 49 CFR 383.25।"},"39":{"q":"किसी नॉर्थ डकोटा CDL आवेदक को स्किल्स (रोड) टेस्ट किस प्रकार के वाहन में देना होगा?","options":["उस वर्ग और प्रकार का एक प्रतिनिधि वाहन जिसे आवेदक चलाने का इरादा रखता है","आवेदक के स्वामित्व वाली कोई भी यात्री कार","NDDOT परीक्षक द्वारा प्रदान किया गया एक वाहन","मांगे गए लाइसेंस की परवाह किए बिना केवल एक Class A संयोजन"],"explanation":"ND को स्किल्स टेस्ट उस वर्ग और कॉन्फ़िगरेशन (स्कूल बस या टैंक जैसे एंडोर्समेंट सहित) के प्रतिनिधि वाहन में देना आवश्यक है जिसे आवेदक संचालित करने का इरादा रखता है। स्रोत: NDDOT CDL application page; 49 CFR 383.71/383.113।"},"40":{"q":"नॉर्थ डकोटा में, किस रक्त अल्कोहल सांद्रता (BAC) पर किसी चालक को नशे में वाणिज्यिक मोटर वाहन (CMV) चलाने वाला माना जाता है और अयोग्यता के अधीन होता है?","options":["0.04 or higher","0.08 or higher","0.02 or higher","0.10 or higher"],"explanation":"नॉर्थ डकोटा संघीय मानक का पालन करता है: 0.04 या उससे अधिक BAC के साथ CMV चलाना एक अल्कोहल अपराध है जो किसी CDL धारक को अयोग्य घोषित करता है। यह गैर-वाणिज्यिक ड्राइविंग पर लागू 0.08 सीमा का आधा है। स्रोत: NDDOT Commercial Driver License Manual (Disqualification); NDCC 39-06.2-10.1।"},"41":{"q":"नॉर्थ डकोटा के अंतर्निहित-सहमति (implied-consent) कानून के तहत, CMV चलाते समय अल्कोहल के रासायनिक परीक्षण से इनकार करने वाले किसी CDL धारक के साथ क्या होता है?","options":["इसे DUI दोषसिद्धि के समान माना जाता है और चालक को अयोग्य घोषित करता है","पहली बार इनकार पर केवल चेतावनी मिलती है","इसमें DUI दोषसिद्धि से कम जुर्माना होता है","इसके परिणामस्वरूप केवल 30-दिन का निलंबन होता है"],"explanation":"रासायनिक परीक्षण से इनकार को, CDL उद्देश्यों के लिए, अल्कोहल/DUI दोषसिद्धि के समान ही माना जाता है। पहली बार इनकार पर चालक कम से कम एक वर्ष के लिए अयोग्य घोषित होता है, पहले प्रमुख अपराध के समान। स्रोत: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.1।"},"42":{"q":"नॉर्थ डकोटा में पहले प्रमुख अपराध, जैसे CMV में DUI, के लिए न्यूनतम CDL अयोग्यता अवधि क्या है, जब खतरनाक सामग्री नहीं ले जाई जा रही हो?","options":["1 year","60 days","6 months","3 years"],"explanation":"पहला प्रमुख अपराध (उदाहरण के लिए, 0.04 या अधिक BAC के साथ CMV चलाना, DUI, या परीक्षण से इनकार) चालक को कम से कम एक वर्ष के लिए अयोग्य घोषित करता है। स्रोत: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10; 49 CFR 383.51।"},"43":{"q":"नॉर्थ डकोटा में, ऐसे पहले प्रमुख अपराध के लिए न्यूनतम CDL अयोग्यता क्या है जो CMV द्वारा प्लेकार्ड वाली खतरनाक सामग्री ले जाते समय किया गया हो?","options":["3 years","1 year","5 years","120 days"],"explanation":"यदि कोई पहला प्रमुख अपराध खतरनाक सामग्री के लिए प्लेकार्ड वाले CMV को चलाते समय किया जाता है, तो अयोग्यता एक वर्ष से बढ़कर कम से कम तीन वर्ष हो जाती है। स्रोत: NDDOT CDL Manual (Disqualification); 49 CFR 383.51।"},"44":{"q":"नॉर्थ डकोटा में दूसरे प्रमुख अपराध (उदाहरण के लिए, CMV में दूसरा DUI) के लिए CDL अयोग्यता अवधि क्या है?","options":["Lifetime","10 years","3 years","5 years"],"explanation":"किसी भी प्रमुख अपराध के लिए दूसरी दोषसिद्धि, किसी भी संयोजन में, आजीवन CDL अयोग्यता का परिणाम होती है। स्रोत: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10; 49 CFR 383.51।"},"45":{"q":"कोई नॉर्थ डकोटा CDL धारक नियंत्रित पदार्थ के निर्माण या वितरण से जुड़े किसी अपराध को करने के लिए वाहन का उपयोग करने का दोषी पाया जाता है। कौन-सी अयोग्यता लागू होती है?","options":["बिना पुनर्बहाली के आजीवन अयोग्यता","1-वर्ष की अयोग्यता","3-वर्ष की अयोग्यता","60-दिन की अयोग्यता"],"explanation":"किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से जुड़े अपराध को करने के लिए CMV का उपयोग करने पर आजीवन अयोग्यता होती है जो पुनर्बहाली के अधीन नहीं है। स्रोत: NDDOT CDL Manual (Disqualification); 49 CFR 383.51।"},"46":{"q":"नॉर्थ डकोटा में 3-वर्ष की अवधि के भीतर कितने गंभीर यातायात उल्लंघन 60-दिन की CDL अयोग्यता को सक्रिय करते हैं?","options":["2 (3 वर्ष के भीतर दूसरा)","1 (पहला उल्लंघन)","3 (3 वर्ष के भीतर तीसरा)","4 (3 वर्ष के भीतर चौथा)"],"explanation":"3-वर्ष की अवधि के भीतर अलग-अलग घटनाओं से उत्पन्न दूसरा गंभीर यातायात उल्लंघन कम से कम 60 दिनों की अयोग्यता का परिणाम होता है। स्रोत: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.5; 49 CFR 383.51।"},"47":{"q":"नॉर्थ डकोटा में, 3-वर्ष की अवधि के भीतर तीन गंभीर यातायात उल्लंघन कम से कम कितने समय की CDL अयोग्यता का परिणाम होते हैं?","options":["120 days","60 days","1 year","180 days"],"explanation":"3-वर्ष की अवधि के भीतर तीसरा गंभीर यातायात उल्लंघन (अलग-अलग घटनाओं से) कम से कम 120 दिनों की अयोग्यता का परिणाम होता है। स्रोत: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.5; 49 CFR 383.51।"},"48":{"q":"नॉर्थ डकोटा में CDL अयोग्यता उद्देश्यों के लिए निम्नलिखित में से किसे एक गंभीर (SERIOUS) यातायात उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["पोस्ट की गई गति सीमा से 15 mph या अधिक तेज़ गाड़ी चलाना","0.04 या अधिक BAC के साथ CMV चलाना","अंतर्निहित सहमति के तहत रासायनिक परीक्षण से इनकार करना","दुर्घटना स्थल को छोड़ना"],"explanation":"अत्यधिक तेज़ गति (सीमा से 15 mph या अधिक) एक गंभीर यातायात उल्लंघन है। सूचीबद्ध अन्य अपराध प्रमुख अपराध हैं, जिनमें बहुत लंबी अयोग्यता होती है। स्रोत: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.5; 49 CFR 383.51।"},"49":{"q":"राज्य या स्थानीय कानून का उल्लंघन करते हुए टेक्स्टिंग करते समय CMV चलाना, नॉर्थ डकोटा में किस प्रकार के अयोग्य ठहराने वाले अपराध के रूप में वर्गीकृत है?","options":["एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध","एक out-of-service आदेश उल्लंघन","एक रेलमार्ग-क्रॉसिंग उल्लंघन"],"explanation":"CMV चलाते समय टेक्स्टिंग एक गंभीर यातायात उल्लंघन है; 3 वर्षों के भीतर दो उल्लंघन 60-दिन की अयोग्यता और 3 वर्षों के भीतर तीन उल्लंघन 120-दिन की अयोग्यता का कारण बनते हैं। स्रोत: NDDOT CDL Manual (Disqualification); 49 CFR 383.51; 49 CFR 392.80।"},"50":{"q":"नियम का उल्लंघन करते हुए CMV चलाते समय हैंड-हेल्ड मोबाइल टेलीफोन का उपयोग करना, नॉर्थ डकोटा में किस रूप में माना जाता है:","options":["एक गंभीर यातायात उल्लंघन","एक मामूली उपकरण उल्लंघन","1 वर्ष के लिए अयोग्य ठहराने वाला एक प्रमुख अपराध","एक out-of-service आदेश उल्लंघन"],"explanation":"हैंड-हेल्ड मोबाइल टेलीफोन का उपयोग करते हुए CMV चलाना एक गंभीर यातायात उल्लंघन है। 3 वर्षों के भीतर दो या तीन जमा होने पर क्रमशः 60- या 120-दिन की अयोग्यता होती है। स्रोत: NDDOT CDL Manual (Disqualification); 49 CFR 383.51; 49 CFR 392.82।"},"51":{"q":"नॉर्थ डकोटा में लागू संघीय नियम के तहत, गाड़ी चलाते समय टेक्स्टिंग या हैंड-हेल्ड फोन का उपयोग करने के लिए किसी CMV चालक को अधिकतम कितना सिविल जुर्माना भुगतना पड़ सकता है?","options":["$2,750","$500","$1,000","$5,000"],"explanation":"किसी चालक को CMV चलाते समय टेक्स्टिंग या हैंड-हेल्ड मोबाइल फोन का उपयोग करने के लिए up to $2,750 के सिविल जुर्माने का सामना करना पड़ सकता है, बार-बार गंभीर उल्लंघनों के लिए अयोग्यता के अतिरिक्त। स्रोत: FMCSA distracted-driving rule (49 CFR 392.80/392.82), नॉर्थ डकोटा में लागू।"},"52":{"q":"नॉर्थ डकोटा में किसी गैर-HazMat, गैर-यात्री CMV को चलाते समय out-of-service (OOS) आदेश का उल्लंघन करने की पहली दोषसिद्धि के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["180 days","60 days","1 year","90 days"],"explanation":"out-of-service आदेश का पहला उल्लंघन कम से कम 180 दिनों की अयोग्यता का परिणाम होता है। स्रोत: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.9; 49 CFR 383.51।"},"53":{"q":"नॉर्थ डकोटा में, 10 वर्षों के भीतर दूसरा out-of-service आदेश उल्लंघन (गैर-HazMat, गैर-यात्री) कम से कम कितनी अयोग्यता का परिणाम होता है:","options":["2 years","180 days","1 year","3 years"],"explanation":"10-वर्ष की अवधि के भीतर दूसरा out-of-service आदेश उल्लंघन चालक को कम से कम 2 वर्षों के लिए अयोग्य घोषित करता है। स्रोत: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.9; 49 CFR 383.51।"},"54":{"q":"कोई नॉर्थ डकोटा CDL धारक 10 वर्षों के भीतर तीसरा out-of-service आदेश उल्लंघन करता है। न्यूनतम अयोग्यता क्या है?","options":["3 years","2 years","1 year","5 years"],"explanation":"10-वर्ष की अवधि के भीतर तीसरा या उसके बाद का out-of-service आदेश उल्लंघन कम से कम 3 वर्षों की अयोग्यता का परिणाम होता है। स्रोत: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.9; 49 CFR 383.51।"},"55":{"q":"प्लेकार्ड वाली खतरनाक सामग्री ले जाते समय या 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाते समय पहले out-of-service आदेश उल्लंघन के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["180 days","90 days","1 year","60 days"],"explanation":"प्लेकार्ड वाली HazMat ले जाते समय या 16+ यात्रियों के लिए डिज़ाइन किए गए वाहन को चलाते समय पहला OOS-आदेश उल्लंघन न्यूनतम 180 दिनों की अयोग्यता वहन करता है (अन्य CMV के समान पहला-अपराध न्यूनतम, लेकिन दूसरे और तीसरे अपराध लंबे होते हैं)। स्रोत: NDDOT CDL Manual (Disqualification); 49 CFR 383.51।"},"56":{"q":"नॉर्थ डकोटा में पहले रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["60 days","30 days","120 days","1 year"],"explanation":"रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए पहली दोषसिद्धि कम से कम 60 दिनों की अयोग्यता का परिणाम होती है। स्रोत: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.6; 49 CFR 383.51।"},"57":{"q":"कोई नॉर्थ डकोटा CDL धारक 3 वर्षों के भीतर दूसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन करता है। न्यूनतम अयोग्यता क्या है?","options":["120 days","60 days","180 days","1 year"],"explanation":"3-वर्ष की अवधि के भीतर दूसरा रेलमार्ग-ग्रेड क्रॉसिंग उल्लंघन कम से कम 120 दिनों की अयोग्यता का परिणाम होता है। स्रोत: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.6; 49 CFR 383.51।"},"58":{"q":"नॉर्थ डकोटा में 3 वर्षों के भीतर तीसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["1 year","120 days","180 days","60 days"],"explanation":"3-वर्ष की अवधि के भीतर तीसरा या उसके बाद का रेलमार्ग-ग्रेड क्रॉसिंग उल्लंघन कम से कम 1 वर्ष की अयोग्यता का परिणाम होता है (नियम के तहत कम से कम 180 days से लेकर 1 year तक, अधिकतम लागू किया जाता है)। स्रोत: NDDOT CDL Manual (Disqualification); NDCC 39-06.2-10.6; 49 CFR 383.51।"},"59":{"q":"नॉर्थ डकोटा में किसी CMV चालक के पास 0.04 BAC से कम मापने योग्य या पता लगाने योग्य मात्रा में अल्कोहल पाया जाता है। तत्काल परिणाम क्या है?","options":["24 घंटे के लिए out of service रखा जाता है","स्थायी रूप से अयोग्य घोषित","एक प्रमुख अपराध का आरोप","60-दिन की अयोग्यता दी जाती है"],"explanation":"0.04 से कम किसी भी मापने योग्य अल्कोहल सांद्रता वाले चालक को 24 घंटे के लिए out of service रखा जाना चाहिए; 0.04 या अधिक BAC एक अयोग्य ठहराने वाला प्रमुख अपराध है। स्रोत: NDDOT CDL Manual (Alcohol/Out-of-Service); 49 CFR 392.5।"},"60":{"q":"किसी शहर के बाहर नॉर्थ डकोटा के एक इंटरस्टेट हाईवे पर, आप एक टो ट्रक के पास पहुँचते हैं जो दाहिने शोल्डर पर रुका हुआ है और उसकी एम्बर फ्लैशिंग लाइटें जल रही हैं। नॉर्थ डकोटा के Move Over कानून के तहत, पास आ रहे एक कमर्शियल वाहन के चालक को क्या करना चाहिए?","options":["पोस्ट की गई गति पर चलते रहें क्योंकि केवल पुलिस वाहन ही इसके अंतर्गत आते हैं","पूरी तरह रुक जाएँ और वाहन के जाने तक प्रतीक्षा करें","बाएँ शोल्डर पर जाएँ और रुकें","यदि सुरक्षित रूप से किया जा सके तो रुके हुए वाहन से सटी हुई न होने वाली लेन में चले जाएँ, अन्यथा गति धीमी करें और सावधानी से गुज़रें"],"explanation":"नॉर्थ डकोटा Century Code 39-10-26 के अनुसार किसी शहर के बाहर इंटरस्टेट या मल्टीलेन हाईवे पर चालकों को, एम्बर/नीली/सफ़ेद/लाल लाइटें दिखाने वाले रुके हुए आपातकालीन या हाईवे-रखरखाव वाहन से सटी हुई न होने वाली लेन में जाना होगा यदि यह सुरक्षित रूप से किया जा सके; यदि नहीं, तो चालक को गति धीमी करनी होगी और एक सुरक्षित गति पर सावधानी से आगे बढ़ना होगा। एक 2023 संशोधन ने इसे हैज़र्ड फ्लैशर दिखाने वाले किसी भी रुके हुए वाहन तक बढ़ा दिया। स्रोत: NDCC 39-10-26; ND Highway Patrol Move Over Law।"},"61":{"q":"2023 में नॉर्थ डकोटा ने अपने Move Over कानून का विस्तार किया। अधिकृत आपातकालीन और हाईवे-रखरखाव वाहनों के अलावा, अब लेन बदलने या गति धीमी करने का कर्तव्य किस रुके हुए वाहन के पास पहुँचने पर भी लागू होता है?","options":["अपने फ्लैशिंग हैज़र्ड चेतावनी संकेत दिखाने वाला कोई भी वाहन","केवल डाक-वितरण वाहन","केवल नीली लाइट दिखाने वाले वाहन","शहर की सीमा के भीतर खड़ा कोई भी वाहन"],"explanation":"नॉर्थ डकोटा के Move Over कानून के 2023 विस्तार (NDCC 39-10-26) ने किसी शहर के बाहर इंटरस्टेट या मल्टीलेन हाईवे पर फ्लैशिंग हैज़र्ड चेतावनी संकेत दिखाने वाले किसी भी रुके हुए मोटर वाहन को जोड़ा। स्रोत: NDCC 39-10-26; ND Highway Patrol / NDDOT Move Over Law सामग्री।"},"62":{"q":"1 अगस्त, 2025 तक, ग्रामीण नॉर्थ डकोटा में एक्सेस-कंट्रोल्ड, पक्की, विभाजित मल्टीलेन इंटरस्टेट हाईवे पर (जहाँ पोस्ट किया गया हो) अधिकतम वैधानिक गति सीमा क्या है, और क्या यह ट्रकों के लिए अलग है?","options":["कारों के लिए 75 mph लेकिन ट्रकों के लिए 65 mph","80 mph, जो ट्रकों सहित सभी वाहनों पर लागू होती है","सभी वाहनों के लिए 70 mph","कारों के लिए 80 mph लेकिन ट्रकों के लिए 70 mph"],"explanation":"NDCC 39-09-02 (HB 1298 द्वारा संशोधित, 1 अगस्त, 2025 से प्रभावी) के तहत, ग्रामीण एक्सेस-कंट्रोल्ड विभाजित इंटरस्टेट हाईवे पर अधिकतम 80 mph है। नॉर्थ डकोटा वैधानिक रूप से ट्रकों के लिए अलग कम गति सीमा निर्धारित नहीं करता, इसलिए यह सीमा सभी वाहनों पर लागू होती है। स्रोत: NDCC 39-09-02; NDDOT / ND Highway Patrol गति सीमा मार्गदर्शन।"},"63":{"q":"नॉर्थ डकोटा कानून के तहत, ऐसे पक्के और विभाजित मल्टीलेन हाईवे पर अधिकतम गति सीमा क्या है जो एक्सेस-कंट्रोल्ड इंटरस्टेट नहीं है?","options":["55 mph","65 mph","70 mph","80 mph"],"explanation":"NDCC 39-09-02 पक्के और विभाजित मल्टीलेन हाईवे पर (इंटरस्टेट को छोड़कर, जो 80 mph हैं) 70 mph को अनुमानित वैध अधिकतम के रूप में निर्धारित करता है। स्रोत: NDCC 39-09-02।"},"64":{"q":"नॉर्थ डकोटा में, बिना पोस्ट की गई सीमा वाले बजरी, मिट्टी, या ढीली सतह वाले हाईवे (और पक्के टू-लेन काउंटी और टाउनशिप हाईवे) पर, अनुमानित अधिकतम वैध गति क्या है?","options":["45 mph","50 mph","55 mph","65 mph"],"explanation":"NDCC 39-09-02 बजरी, मिट्टी, या ढीली सतह वाले हाईवे पर और पक्के टू-लेन काउंटी तथा टाउनशिप हाईवे पर जहाँ कोई सीमा पोस्ट नहीं की गई है, 55 mph को अनुमानित वैध अधिकतम के रूप में निर्धारित करता है। स्रोत: NDCC 39-09-02।"},"65":{"q":"नॉर्थ डकोटा में एक प्लेकार्ड लगे खतरनाक-सामग्री वाले कमर्शियल वाहन का चालक एक ऐसी रेलरोड ग्रेड क्रॉसिंग के पास पहुँचता है जहाँ रुकना आवश्यक है। वाहन को कहाँ रुकना चाहिए?","options":["निकटतम रेल से 75 फीट के भीतर लेकिन 25 फीट से कम नहीं","निकटतम रेल से 100 फीट के भीतर लेकिन 50 फीट से कम नहीं","निकटतम रेल से 50 फीट के भीतर लेकिन 15 फीट से कम नहीं","निकटतम रेल से 10 फीट के भीतर कहीं भी"],"explanation":"NDCC 39-10-43 के अनुसार एक प्लेकार्ड लगे HazMat वाहन (और कुछ टैंक/क्लोरीन वाहनों) के चालक को निकटतम रेल से 50 फीट के भीतर लेकिन 15 फीट से कम नहीं रुकना होगा, फिर आगे बढ़ने से पहले देखना और सुनना होगा। स्रोत: NDCC 39-10-43; ND CDL Manual।"},"66":{"q":"नॉर्थ डकोटा में, किस वाहन को क़ानून द्वारा सभी रेलरोड ग्रेड क्रॉसिंग पर (केवल खतरनाक क्रॉसिंग पर नहीं) रुकना आवश्यक है?","options":["ट्रेलर खींचने वाला कोई भी वाहन","यात्रियों को ले जाने वाली बस या एक स्कूल बस","खेती के लिए उपयोग किया जाने वाला कोई भी पिकअप ट्रक","26,000 पाउंड से अधिक सकल वजन वाला कोई भी वाहन"],"explanation":"NDCC 39-10-43 के अनुसार यात्रियों को ले जाने वाली बस, एक स्कूल बस, और प्लेकार्ड लगे HazMat/कुछ टैंक वाहनों के चालक को सभी रेलरोड ग्रेड क्रॉसिंग पर निकटतम रेल से 50 फीट के भीतर लेकिन 15 फीट से कम नहीं रुकना होगा। स्रोत: NDCC 39-10-43।"},"67":{"q":"नॉर्थ डकोटा में आवश्यकतानुसार एक रेलरोड क्रॉसिंग पर रुकने के बाद, क़ानून ट्रैक पार करते समय एक बस या HazMat चालक पर कौन-सा अतिरिक्त प्रतिबंध लगाता है?","options":["चालक को पार करते समय लगातार हॉर्न बजाना होगा","चालक को ट्रैक पार करते समय मैन्युअल रूप से गियर नहीं बदलना चाहिए","चालक को पार करते समय फोर-वे फ्लैशर चालू करने होंगे","चालक को उपलब्ध उच्चतम गियर में पार करना होगा"],"explanation":"NDCC 39-10-43 चालक को केवल ऐसे गियर में पार करने का निर्देश देता है जिससे क्रॉसिंग पर रहते हुए गियर बदलने की आवश्यकता से बचा जा सके, और चालक ट्रैक पार करते समय मैन्युअल रूप से गियर नहीं बदल सकता। स्रोत: NDCC 39-10-43; ND CDL Manual।"},"68":{"q":"रेलरोड क्रॉसिंग पर बसों और HazMat वाहनों के लिए नॉर्थ डकोटा के रुकना-आवश्यक नियम के तहत, कब रुकना आवश्यक नहीं है?","options":["जब वाहन खाली हो","जब यातायात किसी पुलिस अधिकारी द्वारा नियंत्रित हो, या 'Exempt' या 'Tracks out of service' चिह्नित क्रॉसिंग पर","जब चालक के पास एक वर्ष से अधिक का अनुभव हो","जब क्रॉसिंग किसी व्यावसायिक क्षेत्र में हो"],"explanation":"NDCC 39-10-43 तब रुकने की आवश्यकता को माफ़ करता है जब यातायात किसी पुलिस अधिकारी द्वारा नियंत्रित हो, और उन क्रॉसिंग पर जिन्हें निदेशक ने 'Exempt' या 'Tracks out of service' के रूप में निर्दिष्ट और स्पष्ट रूप से चिह्नित किया है। स्रोत: NDCC 39-10-43।"},"69":{"q":"एक नॉर्थ डकोटा स्कूल बस बच्चों को चढ़ाने के लिए अपनी फ्लैशिंग लाल लाइटों और स्टॉप आर्म के साथ रुकी हुई है। एक कमर्शियल चालक एक टू-लेन सड़क पर विपरीत दिशा से पास आ रहा है। चालक को क्या करना चाहिए?","options":["20 mph तक धीमे होकर सावधानी से गुज़रें","केवल बाईं ओर से कम गति पर गुज़रें","चलते रहें, क्योंकि विपरीत दिशा के यातायात को कभी रुकना आवश्यक नहीं है","बस तक पहुँचने से पहले रुकें और तब तक आगे न बढ़ें जब तक लाइटें और स्टॉप आर्म चालू न रहें"],"explanation":"NDCC 39-10-46 के अनुसार किसी भी दिशा से स्कूल बस से मिलने या उसे ओवरटेक करने वाले चालक को, जब फ्लैशिंग लाल लाइटें या स्टॉप आर्म चालू हों, बस तक पहुँचने से पहले रुकना होगा, और तब तक आगे नहीं बढ़ना होगा जब तक बस चल न दे, चालक को आगे बढ़ने का संकेत न दिया जाए, या लाइटें और आर्म चालू न रहें। स्रोत: NDCC 39-10-46।"},"70":{"q":"नॉर्थ डकोटा के स्कूल-बस रुकने वाले कानून में एक विभाजित-हाईवे अपवाद है। NDCC 39-10-46 के तहत, एक चालक को रुकी हुई स्कूल बस के लिए केवल तभी रुकने की आवश्यकता नहीं है जब:","options":["चालक की दिशा में दो या अधिक लेन हों","बस अलग सड़कमार्गों वाले हाईवे के एक अलग सड़कमार्ग पर हो, या चालक एक कंट्रोल्ड-एक्सेस हाईवे पर हो और बस एक लोडिंग ज़ोन में हो जहाँ पैदल यात्री पार नहीं कर सकते","चालक और बस के बीच एक केंद्रीय टू-वे लेफ्ट-टर्न लेन हो","सड़क पर एक पेंट की गई केंद्र रेखा हो"],"explanation":"NDCC 39-10-46(5) के तहत, अपवाद केवल तभी लागू होता है जब बस अलग (भौतिक रूप से विभाजित) सड़कमार्गों वाले हाईवे के एक अलग सड़कमार्ग पर हो, या किसी कंट्रोल्ड-एक्सेस हाईवे पर हो जहाँ बस एक लोडिंग ज़ोन में हो और पैदल यात्री पार नहीं कर सकते। केवल एक केंद्र टर्न लेन या पेंट की गई रेखा योग्य नहीं है। स्रोत: NDCC 39-10-46।"},"71":{"q":"एक अविभाजित चार-लेन नॉर्थ डकोटा सड़क पर (प्रत्येक दिशा में दो लेन, केवल एक पेंट की गई केंद्र रेखा से अलग), विपरीत दिशा में जा रही एक स्कूल बस लाल लाइटें फ्लैश करते हुए रुकती है। क्या सामने से आने वाले यातायात को रुकना चाहिए?","options":["नहीं, क्योंकि कई लेन हैं","नहीं, चार-लेन सड़क पर सामने से आने वाला यातायात कभी नहीं रुकता","केवल बस के निकटतम लेन को रुकना होगा","हाँ, क्योंकि सड़कमार्ग भौतिक रूप से अलग सड़कमार्गों में विभाजित नहीं है"],"explanation":"NDCC 39-10-46 का अपवाद केवल अलग (भौतिक रूप से विभाजित) सड़कमार्गों वाले हाईवे पर लागू होता है। केवल एक पेंट की गई केंद्र रेखा वाली अविभाजित मल्टीलेन सड़क पर, सामने से आने वाले यातायात को फ्लैशिंग लाल लाइटें और स्टॉप आर्म दिखाने वाली स्कूल बस के लिए फिर भी रुकना होगा। स्रोत: NDCC 39-10-46।"},"72":{"q":"नॉर्थ डकोटा कानून के अनुसार, एक स्कूल बस चालक उस बिंदु से कितनी दूरी पर एम्बर सावधानी (चेतावनी) लाइटें चालू कर सकता है जहाँ बच्चों को चढ़ाया या उतारा जाएगा?","options":["100 फीट से कम नहीं और 300 फीट से अधिक नहीं","200 फीट से कम नहीं और 400 फीट से अधिक नहीं","300 फीट से कम नहीं और 500 फीट से अधिक नहीं","ठीक 250 फीट"],"explanation":"NDCC 39-10-46(3) एम्बर सावधानी लाइटों को उस बिंदु से जहाँ बच्चों को चढ़ाया या उतारा जाता है, 300 फीट से कम नहीं और 500 फीट से अधिक नहीं की दूरी पर चालू करने की अनुमति देता है। स्रोत: NDCC 39-10-46।"},"73":{"q":"नॉर्थ डकोटा कानून के अनुसार प्रत्येक स्कूल बस को रेलरोड क्रॉसिंग से संबंधित अपने पीछे एक विशेष चिह्न लगाना आवश्यक है। उस पर क्या लिखा होता है?","options":["\"DO NOT PASS ON TRACKS\"","\"THIS SCHOOLBUS STOPS AT ALL RAILROAD CROSSINGS\"","\"CAUTION: RAILROAD AHEAD\"","\"SCHOOLBUS YIELDS AT CROSSINGS\""],"explanation":"NDCC 39-10-46(6) के अनुसार प्रत्येक स्कूल बस को अपने पीछे एक स्पष्ट रूप से दिखने वाला चिह्न लगाना आवश्यक है जिस पर लिखा हो \"THIS SCHOOLBUS STOPS AT ALL RAILROAD CROSSINGS.\" स्रोत: NDCC 39-10-46।"},"74":{"q":"नॉर्थ डकोटा के यातायात नियमों के तहत, एक मल्टीलेन हाईवे पर यातायात की सामान्य गति से कम पर चल रहे एक कमर्शियल वाहन को:","options":["मर्जिंग यातायात से बचे रहने के लिए बाईं लेन का उपयोग करें","जिस भी लेन को चालक पसंद करे उसमें रहें","दाहिनी लेन में या व्यावहारिक रूप से जितना संभव हो दाहिने किनारे के करीब चलाया जाए, सिवाय ओवरटेक करते समय या बाएँ मोड़ की तैयारी करते समय","एक तीन-लेन सड़क पर केंद्र लेन का उपयोग करें"],"explanation":"NDCC 39-10-08(2) के अनुसार यातायात की सामान्य गति से धीमे चल रहे किसी भी वाहन को दाहिनी लेन में (या व्यावहारिक रूप से जितना संभव हो दाहिने किनारे के करीब) रहना होगा, सिवाय ओवरटेक करते समय या बाएँ मोड़ की तैयारी करते समय। स्रोत: NDCC 39-10-08।"},"75":{"q":"एक नॉर्थ डकोटा CDL चालक का ट्रक दिन के उजाले में एक समतल, सीधे, अविभाजित टू-लेन हाईवे पर खराब हो जाता है। नॉर्थ डकोटा द्वारा लागू किए जाने वाले चेतावनी-उपकरण नियमों का पालन करते हुए, तीन चेतावनी त्रिकोण कहाँ रखे जाने चाहिए?","options":["तीनों ट्रक के पीछे 10 फीट के भीतर","वाहन के पीछे लगभग 50 फीट, 150 फीट, और 250 फीट","एक छत पर और दो शोल्डर पर","वाहन के लगभग 10 फीट पीछे, 100 फीट पीछे, और 100 फीट आगे"],"explanation":"नॉर्थ डकोटा संघीय प्लेसमेंट मानक (49 CFR 392.22) का पालन करता है: एक टू-लेन सड़क पर, त्रिकोणों को वाहन के यातायात वाले हिस्से पर लगभग 10 फीट पीछे, लगभग 100 फीट पीछे, और लगभग 100 फीट आगे रखें। स्रोत: ND CDL Manual; 49 CFR 392.22।"},"76":{"q":"जब एक नॉर्थ डकोटा CDL चालक एक वन-वे या विभाजित हाईवे पर रुका हो, तो पास आ रहे यातायात की ओर तीन चेतावनी त्रिकोण कैसे रखे जाने चाहिए?","options":["पास आ रहे यातायात की ओर लगभग 10 फीट, 100 फीट, और 200 फीट पर","पास आ रहे यातायात की ओर लगभग 25 फीट, 75 फीट, और 125 फीट पर","पास आ रहे यातायात की ओर तीनों 100 फीट पर","पास आ रहे यातायात की ओर लगभग 50 फीट, 100 फीट, और 150 फीट पर"],"explanation":"एक वन-वे या विभाजित हाईवे पर, नॉर्थ डकोटा द्वारा लागू संघीय मानक (49 CFR 392.22) पास आ रहे यातायात की ओर लगभग 10 फीट, 100 फीट, और 200 फीट पर त्रिकोण रखने की माँग करता है। स्रोत: ND CDL Manual; 49 CFR 392.22।"},"77":{"q":"विस्फोटक या ज्वलनशील तरल का प्लेकार्ड लगा भार ढो रहे एक नॉर्थ डकोटा CDL चालक को रुककर चेतावनी उपकरण लगाने होंगे। ऐसे वाहन पर कौन-सा चेतावनी उपकरण निषिद्ध है?","options":["परावर्तक चेतावनी त्रिकोण","तीन पोर्टेबल लाल आपातकालीन परावर्तक","फ्लेयर या फ्यूज़ी (कोई भी लौ-उत्पादक संकेत)","लाल विद्युत लालटेन"],"explanation":"विस्फोटक, ज्वलनशील गैस/तरल ले जाने वाले, या ईंधन के रूप में संपीड़ित गैस का उपयोग करने वाले वाहनों पर फ्लेयर, फ्यूज़ी, या कोई भी लौ-उत्पादक संकेत उपयोग नहीं किया जा सकता; इसके बजाय परावर्तक त्रिकोण, लाल परावर्तक, या लाल विद्युत लालटेन का उपयोग किया जाना चाहिए। स्रोत: ND CDL Manual; 49 CFR 392.22 / 393.95।"},"78":{"q":"स्प्रिंग थॉ अवधि के बाहर, पोस्ट की गई स्प्रिंग लोड प्रतिबंधों के दौरान विभाज्य भारों के लिए ओवरवेट परमिट के प्रति नॉर्थ डकोटा का रुख यह है कि:","options":["स्प्रिंग रोड प्रतिबंधों के दौरान किसी भी विभाज्य भार के लिए ओवरवेट परमिट जारी नहीं किए जाएंगे","विभाज्य भार पूरे वर्ष एक मानक परमिट के साथ हमेशा सीमाओं से अधिक हो सकते हैं","स्प्रिंग प्रतिबंध केवल इंटरस्टेट सिस्टम पर लागू होते हैं","विभाज्य भार स्प्रिंग में सभी एक्सल-वजन सीमाओं से मुक्त हैं"],"explanation":"NDDOT और ND Highway Patrol पोस्ट की गई स्प्रिंग रोड (थॉ) प्रतिबंधों के दौरान विभाज्य भारों के लिए ओवरवेट परमिट जारी नहीं करते, जो आमतौर पर परिस्थितियों के आधार पर लगभग फरवरी के मध्य से मई तक चलते हैं। स्रोत: NDDOT North Dakota Load Restrictions; ND Highway Patrol Oversize/Overweight Permit जानकारी।"},"79":{"q":"नॉर्थ डकोटा क़ानून एक विशिष्ट उपकरण प्रकार के लिए एक विशेष कम अधिकतम गति निर्धारित करता है। ठोस रबर टायरों से सुसज्जित एक वाहन को इससे तेज़ नहीं चलाया जा सकता:","options":["5 mph","10 mph","20 mph","25 mph"],"explanation":"NDCC 39-09-04.1 ठोस रबर टायरों से सुसज्जित किसी भी वाहन को 10 mph से अधिक चलाने से प्रतिबंधित करता है। स्रोत: NDCC 39-09-04.1।"},"80":{"q":"नॉर्थ डकोटा में कमर्शियल ड्राइवर लाइसेंस कौन-सी एजेंसी जारी करती है?","options":["नॉर्थ डकोटा Department of Transportation (NDDOT) Driver License Division","Federal Motor Carrier Safety Administration (FMCSA)","नॉर्थ डकोटा Highway Patrol","उस काउंटी का शेरिफ कार्यालय जहाँ चालक रहता है"],"explanation":"नॉर्थ डकोटा में, CDL नॉर्थ डकोटा Department of Transportation (NDDOT) द्वारा अपने Driver License Division के माध्यम से जारी किए जाते हैं; FMCSA संघीय मानक निर्धारित करता है लेकिन राज्य लाइसेंस जारी नहीं करता। स्रोत: NDDOT Commercial Driver License पृष्ठ।"},"81":{"q":"नॉर्थ डकोटा के मेडिकल सेल्फ-सर्टिफिकेशन के तहत, एक CDL आवेदक को कितनी सेल्फ-सर्टिफिकेशन श्रेणियों में से चुनना होगा?","options":["चार","दो","तीन","छह"],"explanation":"नॉर्थ डकोटा चार संघीय सेल्फ-सर्टिफिकेशन श्रेणियों का उपयोग करता है: non-excepted interstate, excepted interstate, non-excepted intrastate, और excepted intrastate। स्रोत: NDDOT CDL Medical Certification Requirements।"},"82":{"q":"एक नॉर्थ डकोटा चालक 'non-excepted interstate' के रूप में सेल्फ-सर्टिफाई करता है। मेडिकल योग्यता के संबंध में इसके लिए क्या आवश्यक है?","options":["चालक को एक वर्तमान DOT मेडिकल परीक्षक का प्रमाणपत्र प्राप्त करना और बनाए रखना होगा","चालक सभी मेडिकल सर्टिफिकेशन आवश्यकताओं से मुक्त है","चालक को केवल एक विज़न छूट की आवश्यकता है","चालक को DOT परीक्षा के बजाय एक राज्य शारीरिक फिटनेस परीक्षण पास करना होगा"],"explanation":"Non-excepted interstate चालक 49 CFR Part 391 के अधीन हैं और उन्हें एक वर्तमान DOT मेडिकल परीक्षक का प्रमाणपत्र प्राप्त करना और बनाए रखना होगा। स्रोत: NDDOT CDL Medical Certification Requirements; 49 CFR 391.45।"},"83":{"q":"नॉर्थ डकोटा में किस सेल्फ-सर्टिफिकेशन श्रेणी के लिए DOT मेडिकल परीक्षक के प्रमाणपत्र की आवश्यकता नहीं है?","options":["Excepted interstate","Non-excepted interstate","Non-excepted intrastate","Interstate hazmat ढोने वाला"],"explanation":"'Excepted' (interstate या intrastate) के रूप में प्रमाणित करने वाले चालक विशेष रूप से excepted परिचालनों में काम करते हैं और उन्हें मेडिकल परीक्षक का प्रमाणपत्र रखने की आवश्यकता नहीं है; non-excepted चालकों को रखना होगा। स्रोत: NDDOT CDL Medical Certification Requirements।"},"84":{"q":"21 अप्रैल, 2025 तक, एक नॉर्थ डकोटा CDL धारक का DOT मेडिकल परीक्षक का प्रमाणपत्र राज्य को कैसे प्रस्तुत किया जाता है?","options":["प्रमाणित मेडिकल परीक्षक इसे इलेक्ट्रॉनिक रूप से अपलोड करता है; NDDOT अब कागज़ी प्रमाणपत्र स्वीकार नहीं करता","चालक NDDOT को एक कागज़ी प्रति मेल करता है","चालक Driver License Division को एक प्रति फैक्स करता है","नियोक्ता इसे काउंटी क्लर्क के पास दाखिल करता है"],"explanation":"21 अप्रैल, 2025 से प्रभावी, नॉर्थ डकोटा अब सीधे मेडिकल प्रमाणपत्र स्वीकार नहीं करता; राष्ट्रीय रूप से प्रमाणित मेडिकल परीक्षकों को प्रमाणपत्र इलेक्ट्रॉनिक रूप से रजिस्ट्री/राज्य को अपलोड करना होगा। स्रोत: NDDOT CDL मेडिकल प्रमाणपत्र सूचना।"},"85":{"q":"पहली बार Class A या B लाइसेंस के लिए नॉर्थ डकोटा में CDL स्किल्स टेस्ट देने से पहले, एक नए आवेदक को कौन-सा प्रशिक्षण पूरा करना होगा?","options":["Training Provider Registry पर सूचीबद्ध किसी प्रदाता से Entry-Level Driver Training (ELDT)","काउंटी में एक डिफेंसिव ड्राइविंग कक्षा पाठ्यक्रम","एक लाइसेंस प्राप्त कैरियर के साथ चार-वर्षीय अप्रेंटिसशिप","बिना किसी रजिस्ट्री आवश्यकता के केवल नियोक्ता-वार ओरिएंटेशन"],"explanation":"7 फरवरी, 2022 से, नॉर्थ डकोटा द्वारा अपनाए गए संघीय ELDT नियमों के अनुसार नए CDL आवेदकों को स्किल्स टेस्ट से पहले एक FMCSA Training Provider Registry में सूचीबद्ध प्रदाता से प्रशिक्षण पूरा करना होगा। स्रोत: NDDOT 'How to Apply'; FMCSA ELDT।"},"86":{"q":"नॉर्थ डकोटा CDL स्किल्स टेस्ट में क्रम से कौन-से तीन भाग होते हैं?","options":["Pre-trip inspection, basic vehicle control, और on-road driving","लिखित ज्ञान परीक्षण, नेत्र परीक्षण, और on-road driving","पैरेलल पार्किंग, hazmat लिखित परीक्षण, और एयर ब्रेक परीक्षण","Pre-trip inspection, hazmat एंडोर्समेंट परीक्षण, और रात्रि ड्राइविंग"],"explanation":"नॉर्थ डकोटा का CDL स्किल्स टेस्ट संघीय तीन-भाग प्रारूप का पालन करता है: pre-trip वाहन निरीक्षण, basic vehicle (control) कौशल, और on-road driving। स्रोत: ND CDL Manual; NDDOT CDL पृष्ठ।"},"87":{"q":"नॉर्थ डकोटा में, CDL स्किल्स (रोड) टेस्ट देने की अनुमति मिलने से पहले एक आवेदक को क्या प्राप्त करना होगा?","options":["आवश्यक ज्ञान परीक्षण(ओं) को पास करने के बाद एक Commercial Learner Permit (CLP)","अस्थायी रूप से जारी किया गया एक पूर्ण CDL","एक खतरनाक सामग्री एंडोर्समेंट","एक संघीय परिचालन प्राधिकरण संख्या"],"explanation":"आवेदकों को पहले ज्ञान परीक्षण(ओं) को पास करना होगा और स्किल्स टेस्ट शेड्यूल करने से पहले एक Commercial Learner Permit (CLP) प्राप्त करना होगा। स्रोत: NDDOT 'How to Apply for a Commercial Driver License.'"},"88":{"q":"धारक के CDL स्किल्स टेस्ट देने से पहले एक नॉर्थ डकोटा CLP को कितने समय तक रखना आवश्यक है?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 7 दिन","कम से कम 60 दिन"],"explanation":"नॉर्थ डकोटा संघीय 14-दिन की होल्ड को लागू करता है: एक आवेदक के CDL स्किल्स टेस्ट देने से पहले एक CLP को कम से कम 14 दिनों तक रखना होगा। स्रोत: NDDOT CDL पृष्ठ; 49 CFR 383.25।"},"89":{"q":"नॉर्थ डकोटा में, एक Commercial Learner Permit अपनी जारी तिथि से अधिकतम कितने लगातार दिनों तक वैध होता है?","options":["180 दिन","90 दिन","365 दिन","60 दिन"],"explanation":"एक नॉर्थ डकोटा CLP जारी होने की तिथि से अधिकतम 180 लगातार दिनों तक वैध होता है; यदि समय पर रोड टेस्ट पास नहीं किया जाता, तो परमिट का नवीनीकरण करना होगा। स्रोत: NDDOT CDL पृष्ठ।"},"90":{"q":"नॉर्थ डकोटा CLP के साथ अभ्यास करते समय, परमिट धारक के साथ वाहन में किसका होना आवश्यक है?","options":["समान या उच्च श्रेणी/एंडोर्समेंट वाला एक CDL धारक, जो चालक के बगल में बैठा हो","कोई भी 21 वर्ष या उससे अधिक आयु का लाइसेंस प्राप्त चालक","एक नॉर्थ डकोटा Highway Patrol अधिकारी","सार्वजनिक सड़कों से दूर अभ्यास करने पर किसी की आवश्यकता नहीं है"],"explanation":"एक CLP धारक केवल तभी कमर्शियल वाहन चला सकता है जब उसके साथ एक योग्य CDL धारक (उचित श्रेणी और एंडोर्समेंट के साथ) उसके बगल में बैठा हो। स्रोत: NDDOT CDL पृष्ठ; 49 CFR 383.25।"},"91":{"q":"एक नॉर्थ डकोटा CDL के लिए मानक नवीनीकरण चक्र क्या है?","options":["चार वर्ष","पाँच वर्ष","दो वर्ष","आठ वर्ष"],"explanation":"नॉर्थ डकोटा CDL चार-वर्ष की अवधि के लिए जारी किए जाते हैं और उस चक्र के अंत में चालक के जन्मदिन की आधी रात को समाप्त हो जाते हैं। स्रोत: NDDOT 'How to Renew a Commercial Driver License.'"},"92":{"q":"एक नॉर्थ डकोटा CDL नवीनीकरण वर्ष की किस तिथि की आधी रात को समाप्त होता है?","options":["चालक का जन्मदिन","31 दिसंबर","मूल जारी तिथि की वर्षगांठ","जारी करने वाले महीने का अंतिम दिन"],"explanation":"नॉर्थ डकोटा CDL नवीनीकरण वर्ष में चालक के जन्मदिन की आधी रात को समाप्त हो जाते हैं। स्रोत: NDDOT नवीनीकरण जानकारी।"},"93":{"q":"एक नॉर्थ डकोटा CDL आवेदक को आवेदन करते समय आमतौर पर कौन-से दस्तावेज़ प्रस्तुत करने होंगे?","options":["एक वर्तमान ड्राइवर लाइसेंस, कानूनी उपस्थिति का प्रमाण, और निवास पते का प्रमाण","केवल एक Social Security कार्ड","केवल एक पासपोर्ट और एक वाहन पंजीकरण","एक जन्म प्रमाणपत्र और एक शिकार लाइसेंस"],"explanation":"NDDOT आवेदकों से एक वर्तमान ड्राइवर लाइसेंस, कानूनी उपस्थिति/पहचान का प्रमाण, और नॉर्थ डकोटा निवास पते का प्रमाण प्रस्तुत करने की माँग करता है। स्रोत: NDDOT 'How to Apply for a Commercial Driver License.'"},"94":{"q":"एक intrastate-only (नॉर्थ डकोटा के भीतर) CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["18 वर्ष","16 वर्ष","21 वर्ष","19 वर्ष"],"explanation":"नॉर्थ डकोटा 18 वर्ष की आयु में एक intrastate CDL की अनुमति देता है; interstate परिचालन (और hazmat) के लिए आमतौर पर 21 वर्ष की आयु आवश्यक होती है। स्रोत: NDDOT 'How to Apply'; 49 CFR 383/391।"},"95":{"q":"नॉर्थ डकोटा में interstate ड्राइविंग के लिए (या एक hazmat एंडोर्समेंट के लिए) वैध CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","25 वर्ष"],"explanation":"Interstate CDL परिचालन, और खतरनाक सामग्री एंडोर्समेंट के लिए, चालक का कम से कम 21 वर्ष का होना आवश्यक है। स्रोत: NDDOT CDL आवश्यकताएँ; संघीय CDL नियम।"},"96":{"q":"एक नॉर्थ डकोटा CLP प्राप्त करने के लिए, ज्ञान परीक्षण पास करने के अलावा, कौन-सी परीक्षा आवश्यक है?","options":["एक विज़न (नेत्र) परीक्षा","NDDOT द्वारा प्रशासित एक श्रवण परीक्षण","DOT कार्यालय में एक ड्रग और अल्कोहल जाँच","एक मनोवैज्ञानिक मूल्यांकन"],"explanation":"नॉर्थ डकोटा एक CLP जारी करने के लिए आवश्यक ज्ञान परीक्षण(ओं) को पास करने के साथ-साथ एक विज़न/नेत्र परीक्षा की माँग करता है। स्रोत: NDDOT 'How to Apply for a Commercial Driver License.'"},"97":{"q":"यदि एक नॉर्थ डकोटा CDL आवेदक ज्ञान परीक्षण में असफल हो जाता है, तो इसे फिर से देने पर NDDOT की नीति क्या है?","options":["आमतौर पर प्रति दिन एक प्रयास की अनुमति है; आवेदक फिर से परीक्षण देने के लिए दूसरे दिन लौटता है","किसी भी पुनः परीक्षण से पहले आवेदक को 30 दिन प्रतीक्षा करनी होगी","एक असफलता के बाद आवेदक को स्थायी रूप से प्रतिबंधित कर दिया जाता है","उसी दिन असीमित पुनः परीक्षण की अनुमति है"],"explanation":"NDDOT आमतौर पर ज्ञान परीक्षण को प्रति दिन एक प्रयास तक सीमित करता है, इसलिए एक असफल आवेदक को फिर से परीक्षण देने के लिए बाद के दिन लौटना होगा। स्रोत: NDDOT CDL परीक्षण/शुल्क जानकारी। (सटीक शुल्क बदल सकते हैं।)"},"98":{"q":"एक चालक पहली बार एक नॉर्थ डकोटा CDL में एक स्कूल बस (S) एंडोर्समेंट जोड़ना चाहता है। स्किल्स/एंडोर्समेंट परीक्षण से पहले कौन-सा प्रक्रिया चरण आवश्यक है?","options":["S एंडोर्समेंट के लिए आवश्यक Entry-Level Driver Training (ELDT) पूरा करें","केवल एक विज़न परीक्षण पास करें","बेस CDL को कम से कम पाँच वर्ष तक रखें","एक अलग intrastate-only परमिट प्राप्त करें"],"explanation":"पहली बार एक passenger (P), school bus (S), या hazmat (H) एंडोर्समेंट जोड़ने पर ELDT आवश्यकता शुरू हो जाती है, जिसे परीक्षण से पहले पूरा करना होगा। स्रोत: NDDOT CDL पृष्ठ; FMCSA ELDT नियम 7 फरवरी, 2022 से प्रभावी।"},"99":{"q":"नॉर्थ डकोटा CDL स्किल्स टेस्ट में, basic vehicle control भाग मुख्य रूप से किन क्षमताओं का परीक्षण करता है?","options":["सीधी-रेखा में बैकिंग, पार्किंग/डॉकिंग, और नियंत्रित मुड़ाव जैसे युद्धाभ्यास","स्मृति से सड़क संकेत पढ़ना","ब्रिज वजन सीमा की गणना करना","मौखिक hazmat प्रश्नों का उत्तर देना"],"explanation":"Basic vehicle control भाग कम-गति वाले नियंत्रण युद्धाभ्यासों का परीक्षण करता है जैसे सीधी-रेखा में बैकिंग, एली डॉकिंग, पैरेलल पार्किंग, और सटीक मुड़ाव। स्रोत: ND CDL Manual; NDDOT स्किल्स टेस्ट प्रारूप।"}},"ar":{"0":{"q":"على طرق ولاية نورث داكوتا السريعة، ما هو الحد الأقصى القانوني للعرض الخارجي الإجمالي للمركبة وحمولتها؟","options":["8 أقدام و6 بوصات","8 أقدام","9 أقدام","10 أقدام"],"explanation":"تحدد ولاية نورث داكوتا العرض الخارجي الإجمالي للمركبة، بما في ذلك الحمولة، بـ 8 أقدام و6 بوصات على جميع الطرق السريعة (NDCC 39-12-04؛ دليل NDHP لعمليات الناقلين التجاريين بشأن الحجم والوزن القانونيين، Ref 9-1, Sec. A). تتطلب أي حمولة أعرض من ذلك تصريحاً."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة، محمّلة أو غير محمّلة، على طرق ولاية نورث داكوتا السريعة؟","options":["13 قدماً و6 بوصات","14 قدماً","13 قدماً","15 قدماً"],"explanation":"تحدد ولاية نورث داكوتا الحد الأقصى القانوني لارتفاع المركبة بـ 14 قدماً، سواء كانت محمّلة أو غير محمّلة، لكن يجب على السائق مع ذلك التأكد من وجود مسافة كافية أسفل الجسور والممرات السفلية التي يقل ارتفاعها عن 14 قدماً (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. B)."},"2":{"q":"في ولاية نورث داكوتا، ما هو الحد الأقصى لطول المقطورة أو نصف المقطورة، بما في ذلك حمولتها (للوحدات المسجلة بعد 1 يوليو 1987)؟","options":["48 قدماً","53 قدماً","57 قدماً","60 قدماً"],"explanation":"لا يجوز أن يتجاوز طول المقطورة أو نصف المقطورة، بما في ذلك الحمولة، 53 قدماً في ولاية نورث داكوتا؛ أما المقطورات/أنصاف المقطورات التي صدرت لها وثائق ملكية وسُجِّلت في الولاية قبل 1 يوليو 1987 والمركبات المقطورة فقد تصل إلى 60 قدماً (NDCC 39-12-04؛ NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.4)."},"3":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به على شبكة الطرق السريعة بين الولايات (Interstate) في ولاية نورث داكوتا؟","options":["85,500 رطلاً","90,000 رطل","80,000 رطل","105,500 رطلاً"],"explanation":"الحد الأقصى للوزن الإجمالي للمركبة على شبكة الطرق السريعة بين الولايات (Interstate) في ولاية نورث داكوتا هو 80,000 رطل (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.b)، بما يتوافق مع الحد الفيدرالي للطرق بين الولايات."},"4":{"q":"في ولاية نورث داكوتا، لا يجوز لأي محور مفرد أن يحمل وزناً إجمالياً يتجاوز كم رطلاً؟","options":["18,000 رطل","20,000 رطل","22,000 رطل","24,000 رطل"],"explanation":"تحدد ولاية نورث داكوتا المحور المفرد بوزن إجمالي أقصى قدره 20,000 رطل (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.b). وتُحتسب المحاور المتباعدة بمسافة 40 بوصة أو أقل كمحور واحد."},"5":{"q":"ما هو الحد الأقصى للوزن الإجمالي الذي تسمح به ولاية نورث داكوتا على المحور المزدوج (tandem axle)؟","options":["32,000 رطل","36,000 رطل","40,000 رطل","34,000 رطل"],"explanation":"في ولاية نورث داكوتا، لا يجوز أن يتجاوز الوزن الإجمالي للمحور المزدوج 34,000 رطل (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.c)، بما يتطابق مع الحد الفيدرالي للمحور المزدوج."},"6":{"q":"ما هو الحد الأقصى لطول مركبة أحادية الوحدة ذات محورين أو أكثر، بما في ذلك حمولتها، في ولاية نورث داكوتا؟","options":["40 قدماً","45 قدماً","50 قدماً","53 قدماً"],"explanation":"لا يجوز أن يتجاوز طول المركبة أحادية الوحدة ذات المحورين أو أكثر، بما في ذلك الحمولة، 50 قدماً في ولاية نورث داكوتا (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.1)."},"7":{"q":"على طرق ولاية نورث داكوتا السريعة غير شبكة الطرق بين الولايات (Interstate)، ما هو الحد الأقصى للوزن الإجمالي المسموح به لمحورين منفردين متباعدين بمسافة 8 أقدام أو أكثر؟","options":["34,000 رطل","36,000 رطل","40,000 رطل","44,000 رطل"],"explanation":"على الطرق السريعة غير شبكة الطرق بين الولايات (Interstate)، لا يجوز أن يتجاوز الوزن الإجمالي المجتمع لمحورين منفردين متباعدين بمسافة 8 أقدام أو أكثر 40,000 رطل في ولاية نورث داكوتا (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.b)."},"8":{"q":"على الطرق السريعة غير المُخصَّصة في ولاية نورث داكوتا، ما هو الحد الأقصى لطول تركيبة مكوّنة من وحدتين أو ثلاث أو أربع وحدات، بما في ذلك الحمولة؟","options":["65 قدماً","70 قدماً","75 قدماً","85 قدماً"],"explanation":"لا يجوز أن يتجاوز طول التركيبة المكوّنة من وحدتين أو ثلاث أو أربع وحدات، بما في ذلك الحمولة، 75 قدماً على الطرق السريعة غير المُخصَّصة في نورث داكوتا؛ وعلى الطرق السريعة المقسومة ذات الأربعة مسارات المُخصَّصة من NDDOT قد تصل هذه التركيبات إلى 95 أو 110 قدماً (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. C.2 and C.3)."},"9":{"q":"على طرق ولاية نورث داكوتا السريعة (غير شبكة الطرق بين الولايات)، يكون الحد الأقصى للوزن الإجمالي للمركبة عموماً 80,000 رطل ما لم يكن المسار مُخصَّصاً لأكثر من ذلك، على ألا يتجاوز أي سقف؟","options":["100,000 رطل","105,500 رطلاً","110,000 رطل","129,000 رطل"],"explanation":"على طرق ولاية نورث داكوتا السريعة غير شبكة الطرق بين الولايات، يكون الحد الأقصى للوزن الإجمالي للمركبة 80,000 رطل ما لم يكن الطريق السريع مُخصَّصاً لأكثر من ذلك، وفي هذه الحالة لا يجوز أن يتجاوز 105,500 رطلاً (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.2.a)."},"10":{"q":"بموجب صيغة الجسر الفيدرالية كما تُطبَّق في ولاية نورث داكوتا، يجوز لمجموعتين متتاليتين من المحاور المزدوجة أن تحمل كل منهما 34,000 رطل شريطة أن تكون المسافة بين المحور الأول والأخير من هاتين المجموعتين المزدوجتين على الأقل كم قدماً؟","options":["30 قدماً","34 قدماً","36 قدماً","40 قدماً"],"explanation":"تطبّق ولاية نورث داكوتا صيغة الجسر W = 500(LN/(N-1) + 12N + 36)، لكن يجوز لمجموعتين متتاليتين من المحاور المزدوجة أن تحمل كل منهما 34,000 رطل إذا كانت المسافة الإجمالية بين المحور الأول والأخير من هاتين المجموعتين 36 قدماً على الأقل (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.a)."},"11":{"q":"في صيغة الجسر W = 500(LN/(N-1) + 12N + 36) المعمول بها في نورث داكوتا، ماذا يمثّل الحرف N؟","options":["عدد المحاور في المجموعة","المسافة بين أطراف المحاور","الوزن الصافي للحمولة","الوزن الأقصى بالأرطال"],"explanation":"في صيغة الجسر المعمول بها في نورث داكوتا، W هو الوزن الأقصى على مجموعة من المحاور، وL هي المسافة بالأقدام بين أطراف المجموعة، وN هو عدد المحاور في المجموعة (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.1.a)."},"12":{"q":"على الطرق السريعة غير شبكة الطرق بين الولايات (Interstate) في ولاية نورث داكوتا، ما هو الحد الأقصى للوزن الإجمالي المسموح به على مجموعة من ثلاثة محاور أو أكثر؟","options":["42,000 رطل","51,000 رطلاً","54,000 رطل","48,000 رطل"],"explanation":"على طرق ولاية نورث داكوتا السريعة غير شبكة الطرق بين الولايات، لا يجوز أن يتجاوز الوزن الإجمالي لمجموعة من ثلاثة محاور أو أكثر 48,000 رطل؛ أما على الطرق بين الولايات فتخضع المجموعة لصيغة الجسر (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.c)."},"13":{"q":"متى يكون تصريح الرحلة الواحدة للحمولة الزائدة الحجم/الوزن مطلوباً في ولاية نورث داكوتا؟","options":["لأي مركبة تجارية تنقل مواد خطرة","فقط للحمولات المتنقلة على الطرق بين الولايات (Interstate) بعد حلول الظلام","لحمولة غير قابلة للتقليل تتجاوز حدود الحجم و/أو الوزن القانونية في ولاية نورث داكوتا","لأي مركبة يزيد وزنها عن 26,001 رطلاً"],"explanation":"تتطلب ولاية نورث داكوتا تصريح رحلة واحدة للحمولة الزائدة الحجم/الوزن لنقل حمولة غير قابلة للتقليل زائدة الحجم و/أو الوزن تتجاوز حدود حجم ووزن المركبة القانونية في الولاية (NDHP Oversize/Overweight Permit, e-permits)."},"14":{"q":"ما هي مدة صلاحية تصريح الرحلة الواحدة للحمولة الزائدة الحجم/الوزن في ولاية نورث داكوتا لنقل حمولة واحدة؟","options":["حتى 24 ساعة","حتى 3 أيام","حتى 5 أيام","حتى 7 أيام"],"explanation":"يكون تصريح الرحلة الواحدة للحمولة الزائدة الحجم/الوزن في ولاية نورث داكوتا صالحاً لنقل حمولة واحدة لمدة تصل إلى 5 أيام (NDHP Oversize/Overweight Permit, نظام e-permits على nd.gov/ndhp)."},"15":{"q":"يسمح تصريح إعفاء وزن الحصاد في ولاية نورث داكوتا للمركبة التي تنقل منتجاً زراعياً محصوداً من الحقل إلى أول نقطة تخزين أو بيع بحمل كم وزناً إضافياً؟","options":["وزن أكثر بنسبة 5 بالمئة","وزن أكثر بنسبة 10 بالمئة","وزن أكثر بنسبة 15 بالمئة","وزن أكثر بنسبة 20 بالمئة"],"explanation":"يسمح تصريح إعفاء وزن الحصاد في ولاية نورث داكوتا بوزن أكثر بنسبة 10% عند نقل منتج محصود من الحقل إلى نقطة التخزين الأولية أو أول نقطة بيع، ويكون صالحاً من 15 يوليو حتى 30 نوفمبر، ولا يجوز أن يتجاوز الوزن الإجمالي 105,500 رطلاً (NDHP e-permits, Harvest Weight Exemption Permit)."},"16":{"q":"خلال أي نطاق زمني يكون تصريح إعفاء وزن الحصاد في ولاية نورث داكوتا صالحاً؟","options":["1 مايو - 30 سبتمبر","1 يونيو - 31 أكتوبر","15 يوليو - 30 نوفمبر","1 أغسطس - 31 ديسمبر"],"explanation":"يكون تصريح إعفاء وزن الحصاد في ولاية نورث داكوتا صالحاً بين 15 يوليو و30 نوفمبر لنقل المنتجات المحصودة من الحقل إلى نقطة التخزين الأولية أو أول عملية بيع (NDHP e-permits, Harvest Weight Exemption Permit)."},"17":{"q":"في ولاية نورث داكوتا، يجوز للآلة الزراعية التي ينقلها مزارع مقيم بين شروق الشمس وغروبها (وليس على الطرق بين الولايات) أن تتجاوز الحد العادي للارتفاع البالغ 14 قدماً حتى أي ارتفاع أقصى؟","options":["14 قدماً و6 بوصات","15 قدماً","15 قدماً و6 بوصات","16 قدماً"],"explanation":"تسمح ولاية نورث داكوتا للآلات الزراعية بالوصول إلى ارتفاع 15 قدماً و6 بوصات عندما ينقلها مزارعون أو مربو ماشية أو تجار أو مصنّعون مقيمون بين شروق الشمس وغروبها، لمسافة لا تتجاوز 60 ميلاً وليس على الطرق بين الولايات (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. B.2.a)."},"18":{"q":"يجوز لمركبة في ولاية نورث داكوتا تعمل بشكل أساسي بالغاز الطبيعي أن تتجاوز حد الوزن الإجمالي بمقدار كم، وحتى أي حد أقصى؟","options":["حتى 1,000 رطل، بحد أقصى 81,000 رطل","حتى 2,000 رطل، بحد أقصى 82,000 رطل","حتى 2,500 رطل، بحد أقصى 82,500 رطل","حتى 4,000 رطل، بحد أقصى 84,000 رطل"],"explanation":"يجوز لمركبة في ولاية نورث داكوتا تعمل بمحرك يُشغَّل بشكل أساسي بالغاز الطبيعي أن تتجاوز حد الوزن بمقدار يصل إلى 2,000 رطل، بحد أقصى للوزن الإجمالي قدره 82,000 رطل، لمراعاة نظام الوقود الأثقل (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.8)."},"19":{"q":"في ولاية نورث داكوتا، يُحدَّد وزن محور التوجيه وفق تصنيف المحور الذي تضعه الشركة المصنّعة، لكن لا يجوز أن يتجاوز كم رطلاً عند السير على شبكة الطرق بين الولايات (Interstate)؟","options":["12,000 رطل","18,000 رطل","20,000 رطل","24,000 رطل"],"explanation":"تحدد ولاية نورث داكوتا محور التوجيه وفق تصنيف المحور الذي تضعه الشركة المصنّعة، على ألا يتجاوز 20,000 رطل على شبكة الطرق بين الولايات (Interstate)، ولا يجوز أن يتجاوز أي إطار 550 رطلاً لكل بوصة من عرض الإطار (NDHP Legal Size and Weight Guide, Ref 9-1, Sec. E.3.a)."},"20":{"q":"في ولاية نورث داكوتا، أي فئة من رخصة القيادة التجارية CDL مطلوبة لتشغيل أي تركيبة من المركبات يبلغ تصنيف الوزن الإجمالي المجتمع لها (GCWR) 26,001 رطلاً أو أكثر، شريطة أن يكون تصنيف الوزن الإجمالي للمركبة (GVWR) المقطورة يتجاوز 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تغطي الفئة A من رخصة CDL في نورث داكوتا (مركبة مركّبة/تركيبة) أي تركيبة من المركبات يبلغ تصنيف الوزن الإجمالي المجتمع GCWR لها 26,001 رطلاً أو أكثر عندما يتجاوز تصنيف الوزن الإجمالي GVWR للوحدة المقطورة 10,000 رطل. المصدر: صفحة رخصة القيادة التجارية لدى NDDOT ودليل ND CDL؛ 49 CFR 383.91."},"21":{"q":"بموجب قواعد ولاية نورث داكوتا، أي مما يلي تخوّل رخصة CDL من الفئة B السائق بتشغيله؟","options":["أي مركبة مفردة يبلغ تصنيف وزنها الإجمالي GVWR 26,001 رطلاً أو أكثر، تقطر وحدة لا يتجاوز تصنيف وزنها الإجمالي GVWR 10,000 رطل","أي تركيبة من المركبات يزيد تصنيف الوزن الإجمالي المجتمع GCWR لها عن 26,001 رطل مع وحدة مقطورة يزيد وزنها عن 10,000 رطل","فقط المركبات المصممة لنقل 16 راكباً أو أكثر","فقط المركبات التي يقل تصنيف وزنها الإجمالي GVWR عن 26,001 رطل والتي تنقل مواد خطرة تستلزم لوحات تحذير"],"explanation":"تغطي الفئة B في نورث داكوتا (مركبة مستقيمة ثقيلة) أي مركبة مفردة يبلغ تصنيف وزنها الإجمالي GVWR 26,001 رطلاً أو أكثر، أو مثل هذه المركبة وهي تقطر وحدة لا يتجاوز تصنيف وزنها الإجمالي GVWR 10,000 رطل. المصدر: صفحة رخصة القيادة التجارية لدى NDDOT ودليل ND CDL؛ 49 CFR 383.91."},"22":{"q":"يقود سائق في ولاية نورث داكوتا مركبة مفردة يقل تصنيف وزنها الإجمالي GVWR عن 26,001 رطل وهي مصممة لنقل 16 راكباً أو أكثر (بما في ذلك السائق). أي فئة من رخصة CDL تنطبق؟","options":["الفئة C","الفئة A","الفئة B","لا يلزم رخصة CDL"],"explanation":"تنطبق الفئة C في نورث داكوتا (مركبة صغيرة) على المركبات المفردة التي يقل تصنيف وزنها الإجمالي GVWR عن 26,001 رطل والمصممة لنقل 16 راكباً أو أكثر (بما في ذلك السائق) أو التي تنقل مواد خطرة تستلزم لوحات تحذير. المصدر: صفحة رخصة القيادة التجارية لدى NDDOT ودليل ND CDL؛ 49 CFR 383.91."},"23":{"q":"أي تظهير في رخصة CDL في نورث داكوتا مطلوب لتشغيل مركبة صهريج تُستخدم لنقل سائل أو غاز في صهريج مثبّت بشكل دائم تتجاوز سعته المُصنّفة الفردية 119 غالوناً (وبإجمالي 1,000 غالون أو أكثر)؟","options":["N (مركبات الصهاريج)","H (المواد الخطرة)","T (المقطورات المزدوجة/الثلاثية)","P (الركاب)"],"explanation":"التظهير N مطلوب في نورث داكوتا لنقل السوائل أو الغازات في صهريج تتجاوز سعته المُصنّفة 119 غالوناً بشكل فردي أو 1,000 غالون أو أكثر بشكل إجمالي. المصدر: صفحة رخصة القيادة التجارية لدى NDDOT؛ 49 CFR 383.93."},"24":{"q":"في ولاية نورث داكوتا، أي تظهير يجب أن يحصل عليه حامل رخصة CDL لقطر مقطورات مزدوجة أو ثلاثية؟","options":["T (المقطورات المزدوجة/الثلاثية)","N (مركبات الصهاريج)","X (تركيبة الصهريج/المواد الخطرة)","P (الركاب)"],"explanation":"يخوّل التظهير T قطر المقطورات المزدوجة أو الثلاثية في ولاية نورث داكوتا، ويُحصَل عليه باجتياز اختبار المعرفة الخاص بالمقطورات المزدوجة/الثلاثية. المصدر: صفحة رخصة القيادة التجارية لدى NDDOT ودليل ND CDL؛ 49 CFR 383.93."},"25":{"q":"ما هو الحد الأدنى للسن للحصول على رخصة CDL في نورث داكوتا صالحة فقط للقيادة داخل الولاية (INTRASTATE) (ضمن نورث داكوتا)؟","options":["18 عاماً","16 عاماً","19 عاماً","21 عاماً"],"explanation":"تسمح ولاية نورث داكوتا برخصة CDL للقيادة داخل الولاية فقط عند سن 18 عاماً. يجب أن يبلغ السائقون 21 عاماً للعمل في التجارة بين الولايات. المصدر: متطلبات CDL لدى NDDOT؛ NDCC Title 39؛ 49 CFR 383."},"26":{"q":"يجب أن يبلغ متقدّم رخصة CDL في نورث داكوتا الذي يرغب في القيادة في التجارة بين الولايات، أو نقل مواد خطرة، أو نقل ركاب مقابل أجر، على الأقل أي سن؟","options":["21 عاماً","18 عاماً","19 عاماً","25 عاماً"],"explanation":"تشترط ولاية نورث داكوتا أن يبلغ السائق 21 عاماً على الأقل للعمل عبر حدود الولايات (بين الولايات)، أو لنقل مواد خطرة، أو لنقل ركاب مقابل أجر. المصدر: متطلبات CDL لدى NDDOT؛ 49 CFR 383."},"27":{"q":"بعد إصدار تصريح المتعلّم التجاري (CLP) في نورث داكوتا، كم يجب أن ينتظر المتقدّم قبل أن يصبح مؤهلاً لإجراء اختبار مهارات القيادة (الطريق) لرخصة CDL؟","options":["14 يوماً على الأقل","30 يوماً على الأقل","7 أيام على الأقل","60 يوماً على الأقل"],"explanation":"تتبع ولاية نورث داكوتا القاعدة الفيدرالية التي تشترط الاحتفاظ بتصريح CLP لمدة 14 يوماً على الأقل قبل أن يتمكن المتقدّم من إجراء اختبار مهارات CDL. المصدر: صفحة طلب CDL لدى NDDOT؛ 49 CFR 383.25."},"28":{"q":"قبل الحصول على تظهير المواد الخطرة (H) في نورث داكوتا، يجب على المتقدّم اجتياز أي فحص خلفية مطلوب فيدرالياً؟","options":["تقييم التهديد الأمني من TSA، بما في ذلك أخذ البصمات","فحص سجل جنائي من FBI فقط دون بصمات","اختبار كشف كذب تديره الولاية","فحص مراجع يجريه صاحب العمل فقط"],"explanation":"يجب على المتقدّمين لتظهير H في نورث داكوتا إكمال تقييم التهديد الأمني من TSA، والذي يشمل تقديم البصمات، قبل إمكانية إضافة التظهير. المصدر: صفحة متطلبات المواد الخطرة لدى NDDOT؛ 49 CFR 1572 / TSA."},"29":{"q":"أي خطوة من خطوات تدريب المستوى المبتدئ مطلوبة الآن قبل أن يتمكن المتقدّم في نورث داكوتا من إجراء اختبار المعرفة لتظهير جديد للمواد الخطرة (H)؟","options":["تدريب نظري فيدرالي ELDT للمواد الخطرة من مزوّد مدرَج في سجل مزوّدي التدريب التابع لـ FMCSA","تدريب مهني داخل المقصورة على ناقلات الصهاريج لمدة 40 ساعة","دورة في أكاديمية للمواد الخطرة تديرها ولاية نورث داكوتا","لا يلزم أي تدريب، فقط اختبار المعرفة"],"explanation":"يجب على المتقدّمين الأوليين لتظهير H في نورث داكوتا إكمال التدريب النظري للمواد الخطرة المطلوب فيدرالياً ضمن تدريب سائق المستوى المبتدئ (ELDT) من مزوّد مدرَج في سجل مزوّدي التدريب التابع لـ FMCSA قبل اختبار المعرفة. المصدر: صفحة متطلبات المواد الخطرة لدى NDDOT؛ 49 CFR 380."},"30":{"q":"يجب إكمال تدريب سائق المستوى المبتدئ (ELDT) المطلوب قبل الحصول على أول رخصة CDL من الفئة A في نورث داكوتا من خلال أي نظام؟","options":["مزوّد مدرَج في سجل مزوّدي التدريب التابع لـ FMCSA","أي كلية مجتمعية في نورث داكوتا، دون إدراج فيدرالي","أكاديمية السائقين الداخلية التابعة لـ NDDOT","أي صاحب عمل لشركة شحن من خارج الولاية يختاره السائق"],"explanation":"تشترط ولاية نورث داكوتا إكمال ELDT من خلال مدرسة أو جهة مدرَجة في سجل مزوّدي التدريب التابع لـ FMCSA قبل اختبار المهارات للحصول على أول رخصة CDL من الفئة A. المصدر: صفحة كيفية التقديم لرخصة CDL لدى NDDOT؛ 49 CFR 380 Subpart F."},"31":{"q":"أي تظهير يحتاجه السائق في نورث داكوتا لتشغيل مركبة (غير الحافلة المدرسية) مصممة لنقل 16 شخصاً أو أكثر بما في ذلك السائق؟","options":["P (الركاب)","S (الحافلة المدرسية)","N (الصهريج)","T (المقطورات المزدوجة/الثلاثية)"],"explanation":"التظهير P (الركاب) مطلوب لتشغيل حافلة أو مركبة أخرى مصممة لنقل 16 شخصاً أو أكثر بما في ذلك السائق. كما تتطلب الحافلة المدرسية تظهير S منفصلاً. المصدر: دليل ND CDL؛ 49 CFR 383.93."},"32":{"q":"لإضافة تظهير الحافلة المدرسية (S) إلى رخصة CDL في نورث داكوتا، أي تظهير يجب أن يحمله السائق أيضاً؟","options":["P (الركاب)","N (الصهريج)","H (المواد الخطرة)","T (المقطورات المزدوجة/الثلاثية)"],"explanation":"في ولاية نورث داكوتا، يتطلب تظهير S (الحافلة المدرسية) أن يحمل السائق أولاً تظهير P (الركاب)، بالإضافة إلى اجتياز اختباري المعرفة والمهارات الخاصين بالحافلة المدرسية. المصدر: دليل ND CDL؛ 49 CFR 383.93."},"33":{"q":"عند التقديم لرخصة CDL في نورث داكوتا، يجب على المتقدّم تقديم إثبات لرقم الضمان الاجتماعي. أي من هذه المستندات مقبول؟","options":["بطاقة الضمان الاجتماعي الأصلية","نسخة مصوّرة من بطاقة الضمان الاجتماعي","ملاحظة مكتوبة بخط اليد تتضمن رقم الضمان الاجتماعي","بطاقة مكتبة تُظهِر الرقم"],"explanation":"تشترط ولاية نورث داكوتا إثبات رقم الضمان الاجتماعي، مثل بطاقة الضمان الاجتماعي الأصلية؛ ولا تُقبَل النسخ المصوّرة، ويجب أن تكون المستندات أصلية أو موثّقة. المصدر: متطلبات رخصة القيادة لدى NDDOT / قائمة تحقّق REAL ID."},"34":{"q":"كم عدد مستندات إثبات الإقامة التي تشترط ولاية نورث داكوتا أن يقدّمها المتقدّم لإثبات عنوان إقامته في نورث داكوتا؟","options":["مستندان","مستند واحد","ثلاثة مستندات","لا يلزم إثبات إقامة"],"explanation":"تشترط ولاية نورث داكوتا تقديم مستندين يثبتان عنوان إقامة المتقدّم في نورث داكوتا (مثل كشوف خدمات المرافق/الكشوف المالية، السجلات الضريبية). المصدر: متطلبات رخصة القيادة لدى NDDOT / قائمة تحقّق REAL ID."},"35":{"q":"إلى جانب الهوية ورقم الضمان الاجتماعي والإقامة، ما هو الإثبات الإضافي الذي يجب أن يقدّمه متقدّم رخصة CDL في نورث داكوتا؟","options":["إثبات الجنسية الأمريكية، أو الإقامة الدائمة القانونية، أو الوجود القانوني/المؤقت","خطاب موثّق من صاحب عمل حالي","إثبات ملكية مركبة","شهادة ثانوية"],"explanation":"تشترط ولاية نورث داكوتا إثبات الجنسية، أو الإقامة الدائمة القانونية، أو الوجود القانوني في الولايات المتحدة بالإضافة إلى الهوية ورقم الضمان الاجتماعي والإقامة. المصدر: صفحة متطلبات رخصة القيادة لدى NDDOT."},"36":{"q":"متقدّم رخصة CDL في نورث داكوتا الذي يقود في التجارة بين الولايات ويجب أن يحمل شهادة الفاحص الطبي يُصرّح ذاتياً بأي فئة؟","options":["بين الولايات، غير مُستثنى (NI)","بين الولايات، مُستثنى (EI)","داخل الولاية، غير مُستثنى (NA)","داخل الولاية، مُستثنى (EA)"],"explanation":"يُصرّح السائقون في التجارة بين الولايات الذين يجب أن يستوفوا معايير التأهيل البدني الفيدرالية ذاتياً بأنهم بين الولايات وغير مُستثنين، ويجب أن يحتفظوا بشهادة فاحص طبي صالحة في ملفهم لدى نورث داكوتا. المصدر: التصريح الذاتي لـ CDL لدى NDDOT؛ 49 CFR 383.71 / 391."},"37":{"q":"كم عدد فئات التصريح الذاتي الطبي التي يجب أن يختار منها حامل رخصة CDL في نورث داكوتا عند التصريح بنوع التجارة التي يعمل فيها؟","options":["أربع (بين الولايات غير مُستثنى، بين الولايات مُستثنى، داخل الولاية غير مُستثنى، داخل الولاية مُستثنى)","اثنتان (بين الولايات وداخل الولاية فقط)","ثلاث (بين الولايات، داخل الولاية، ومُعفى)","خمس (واحدة لكل تظهير في CDL)"],"explanation":"تشترط القواعد الفيدرالية التي تبنّتها نورث داكوتا اختيار واحدة من أربع فئات للتصريح الذاتي: بين الولايات غير مُستثنى، أو بين الولايات مُستثنى، أو داخل الولاية غير مُستثنى، أو داخل الولاية مُستثنى. المصدر: التصريح الذاتي لـ CDL لدى NDDOT؛ 49 CFR 383.71."},"38":{"q":"بموجب المعيار الفيدرالي الذي تتبعه ولاية نورث داكوتا، ما هي المدة القصوى التي قد يكون فيها تصريح المتعلّم التجاري (CLP) صالحاً قبل أن يلزم تجديده (دون إعادة إجراء اختبارات المعرفة)؟","options":["180 يوماً","30 يوماً","12 شهراً","5 سنوات"],"explanation":"يكون تصريح CLP صالحاً لمدة تصل إلى 180 يوماً ويمكن تجديده مرة واحدة لمدة 180 يوماً إضافية ضمن نافذة سنة واحدة دون إعادة الاختبار؛ تصدر نورث داكوتا تصاريح CLP بموجب هذا المعيار الفيدرالي. المصدر: دليل ND CDL؛ 49 CFR 383.25."},"39":{"q":"يجب على متقدّم رخصة CDL في نورث داكوتا إجراء اختبار المهارات (الطريق) في أي نوع من المركبات؟","options":["مركبة ممثّلة للفئة والنوع الذي ينوي المتقدّم قيادته","أي سيارة ركاب يملكها المتقدّم","مركبة يوفّرها فاحص NDDOT","فقط تركيبة من الفئة A، بغض النظر عن الرخصة المطلوبة"],"explanation":"تشترط ولاية نورث داكوتا إجراء اختبار المهارات في مركبة ممثّلة للفئة والتكوين (بما في ذلك التظهيرات مثل الحافلة المدرسية أو الصهريج) الذي ينوي المتقدّم تشغيله. المصدر: صفحة طلب CDL لدى NDDOT؛ 49 CFR 383.71/383.113."},"40":{"q":"في ولاية نورث داكوتا، عند أي تركيز للكحول في الدم (BAC) يُعتبر السائق مشغّلاً لمركبة آلية تجارية (CMV) تحت تأثير الكحول وخاضعاً لإلغاء الأهلية؟","options":["0.04 أو أعلى","0.08 أو أعلى","0.02 أو أعلى","0.10 أو أعلى"],"explanation":"تتبع ولاية نورث داكوتا المعيار الفيدرالي: تشغيل مركبة CMV بتركيز كحول في الدم BAC قدره 0.04 أو أكثر هو مخالفة كحول تلغي أهلية حامل رخصة CDL. وهذا نصف حد 0.08 المطبَّق على القيادة غير التجارية. المصدر: دليل رخصة القيادة التجارية لدى NDDOT (إلغاء الأهلية)؛ NDCC 39-06.2-10.1."},"41":{"q":"بموجب قانون الموافقة الضمنية في نورث داكوتا، ماذا يحدث لحامل رخصة CDL الذي يرفض الخضوع لاختبار كيميائي للكحول أثناء تشغيل مركبة CMV؟","options":["يُعامَل بنفس معاملة إدانة القيادة تحت تأثير الكحول (DUI) ويلغي أهلية السائق","يؤدي فقط إلى تحذير عند الرفض الأول","يحمل عقوبة أصغر من إدانة DUI","يؤدي إلى تعليق لمدة 30 يوماً فقط"],"explanation":"يُعامَل رفض الخضوع للاختبار الكيميائي، لأغراض رخصة CDL، بنفس معاملة إدانة الكحول/القيادة تحت التأثير (DUI). يلغي الرفض الأول أهلية السائق لمدة سنة واحدة على الأقل، تماماً مثل أول مخالفة كبرى. المصدر: دليل ND CDL (إلغاء الأهلية)؛ NDCC 39-06.2-10.1."},"42":{"q":"ما هو الحد الأدنى لمدة إلغاء أهلية رخصة CDL في نورث داكوتا لأول مخالفة كبرى، مثل القيادة تحت تأثير الكحول (DUI) في مركبة CMV، عند عدم نقل مواد خطرة؟","options":["سنة واحدة","60 يوماً","6 أشهر","3 سنوات"],"explanation":"تلغي أول مخالفة كبرى (مثل تشغيل مركبة CMV بتركيز كحول في الدم BAC قدره 0.04 أو أكثر، أو القيادة تحت التأثير DUI، أو رفض الاختبار) أهلية السائق لمدة سنة واحدة على الأقل. المصدر: دليل ND CDL (إلغاء الأهلية)؛ NDCC 39-06.2-10؛ 49 CFR 383.51."},"43":{"q":"في ولاية نورث داكوتا، ما هو الحد الأدنى لإلغاء أهلية رخصة CDL لأول مخالفة كبرى تُرتكب أثناء نقل مركبة CMV لمواد خطرة تحمل لوحات تحذير؟","options":["3 سنوات","سنة واحدة","5 سنوات","120 يوماً"],"explanation":"إذا ارتُكبت أول مخالفة كبرى أثناء تشغيل مركبة CMV تحمل لوحات تحذير للمواد الخطرة، يزداد إلغاء الأهلية من سنة واحدة إلى ثلاث سنوات على الأقل. المصدر: دليل ND CDL (إلغاء الأهلية)؛ 49 CFR 383.51."},"44":{"q":"ما هي مدة إلغاء أهلية رخصة CDL في نورث داكوتا لثاني مخالفة كبرى (مثل ثاني قيادة تحت تأثير الكحول DUI في مركبة CMV)؟","options":["مدى الحياة","10 سنوات","3 سنوات","5 سنوات"],"explanation":"تؤدي ثاني إدانة بأي مخالفة كبرى، بأي تركيبة، إلى إلغاء أهلية رخصة CDL مدى الحياة. المصدر: دليل ND CDL (إلغاء الأهلية)؛ NDCC 39-06.2-10؛ 49 CFR 383.51."},"45":{"q":"يُدان حامل رخصة CDL في نورث داكوتا باستخدام مركبة لارتكاب جناية تتعلق بتصنيع أو توزيع مادة خاضعة للرقابة. ما هو إلغاء الأهلية المطبَّق؟","options":["إلغاء الأهلية مدى الحياة دون إعادة إصدار","إلغاء الأهلية لمدة سنة واحدة","إلغاء الأهلية لمدة 3 سنوات","إلغاء الأهلية لمدة 60 يوماً"],"explanation":"يؤدي استخدام مركبة CMV لارتكاب جناية تتعلق بتصنيع أو توزيع أو صرف مادة خاضعة للرقابة إلى إلغاء الأهلية مدى الحياة وهو غير خاضع لإعادة الإصدار. المصدر: دليل ND CDL (إلغاء الأهلية)؛ 49 CFR 383.51."},"46":{"q":"كم عدد مخالفات المرور الخطيرة خلال فترة 3 سنوات التي تستوجب إلغاء أهلية رخصة CDL لمدة 60 يوماً في نورث داكوتا؟","options":["2 (الثانية خلال 3 سنوات)","1 (المخالفة الأولى)","3 (الثالثة خلال 3 سنوات)","4 (الرابعة خلال 3 سنوات)"],"explanation":"تؤدي ثاني مخالفة مرور خطيرة خلال فترة 3 سنوات، ناشئة عن حوادث منفصلة، إلى إلغاء الأهلية لمدة 60 يوماً على الأقل. المصدر: دليل ND CDL (إلغاء الأهلية)؛ NDCC 39-06.2-10.5؛ 49 CFR 383.51."},"47":{"q":"في ولاية نورث داكوتا، تؤدي ثلاث مخالفات مرور خطيرة خلال فترة 3 سنوات إلى إلغاء أهلية رخصة CDL لمدة لا تقل عن كم؟","options":["120 يوماً","60 يوماً","سنة واحدة","180 يوماً"],"explanation":"تؤدي ثالث مخالفة مرور خطيرة خلال فترة 3 سنوات (من حوادث منفصلة) إلى إلغاء الأهلية لمدة 120 يوماً على الأقل. المصدر: دليل ND CDL (إلغاء الأهلية)؛ NDCC 39-06.2-10.5؛ 49 CFR 383.51."},"48":{"q":"أي مما يلي يُصنَّف كمخالفة مرور خطيرة لأغراض إلغاء أهلية رخصة CDL في نورث داكوتا؟","options":["تجاوز السرعة بمقدار 15 mph أو أكثر فوق حد السرعة المعلن","تشغيل مركبة CMV بتركيز كحول في الدم BAC قدره 0.04 أو أكثر","رفض اختبار كيميائي بموجب الموافقة الضمنية","مغادرة مكان الحادث"],"explanation":"تجاوز السرعة المفرط (15 mph أو أكثر فوق الحد) هو مخالفة مرور خطيرة. أما المخالفات الأخرى المذكورة فهي مخالفات كبرى تحمل فترات إلغاء أهلية أطول بكثير. المصدر: دليل ND CDL (إلغاء الأهلية)؛ NDCC 39-06.2-10.5؛ 49 CFR 383.51."},"49":{"q":"قيادة مركبة CMV أثناء إرسال الرسائل النصية، بما يخالف قانون الولاية أو القانون المحلي، تُصنَّف في نورث داكوتا كأي نوع من المخالفات المؤدية لإلغاء الأهلية؟","options":["مخالفة مرور خطيرة","مخالفة كبرى","مخالفة أمر إيقاف الخدمة","مخالفة معبر السكة الحديدية"],"explanation":"إرسال الرسائل النصية أثناء قيادة مركبة CMV هو مخالفة مرور خطيرة؛ مخالفتان خلال 3 سنوات تتسببان في إلغاء أهلية لمدة 60 يوماً، وثلاث خلال 3 سنوات في إلغاء أهلية لمدة 120 يوماً. المصدر: دليل ND CDL (إلغاء الأهلية)؛ 49 CFR 383.51؛ 49 CFR 392.80."},"50":{"q":"استخدام هاتف محمول يدوي أثناء قيادة مركبة CMV، بما يخالف القاعدة، يُعامَل في نورث داكوتا على أنه:","options":["مخالفة مرور خطيرة","مخالفة معدّات بسيطة","مخالفة كبرى تلغي الأهلية لمدة سنة واحدة","مخالفة أمر إيقاف الخدمة"],"explanation":"قيادة مركبة CMV أثناء استخدام هاتف محمول يدوي هي مخالفة مرور خطيرة. يؤدي تراكم مخالفتين أو ثلاث خلال 3 سنوات إلى إلغاء أهلية لمدة 60 أو 120 يوماً على التوالي. المصدر: دليل ND CDL (إلغاء الأهلية)؛ 49 CFR 383.51؛ 49 CFR 392.82."},"51":{"q":"بموجب القاعدة الفيدرالية المطبَّقة في نورث داكوتا، ما هي الغرامة المدنية القصوى التي قد يواجهها سائق مركبة CMV لإرساله رسائل نصية أو استخدامه هاتفاً يدوياً أثناء القيادة؟","options":["$2,750","$500","$1,000","$5,000"],"explanation":"قد يخضع السائق لغرامة مدنية تصل إلى $2,750 لإرساله رسائل نصية أو استخدامه هاتفاً محمولاً يدوياً أثناء قيادة مركبة CMV، بالإضافة إلى إلغاء الأهلية في حال تكرار المخالفات الخطيرة. المصدر: قاعدة القيادة المشتّتة لدى FMCSA (49 CFR 392.80/392.82)، المطبَّقة في نورث داكوتا."},"52":{"q":"ما هو الحد الأدنى لإلغاء أهلية رخصة CDL في نورث داكوتا لأول إدانة بمخالفة أمر إيقاف الخدمة (OOS) أثناء قيادة مركبة CMV لا تنقل مواد خطرة ولا ركاباً؟","options":["180 يوماً","60 يوماً","سنة واحدة","90 يوماً"],"explanation":"تؤدي أول مخالفة لأمر إيقاف الخدمة إلى إلغاء الأهلية لمدة 180 يوماً على الأقل. المصدر: دليل ND CDL (إلغاء الأهلية)؛ NDCC 39-06.2-10.9؛ 49 CFR 383.51."},"53":{"q":"في ولاية نورث داكوتا، تؤدي ثاني مخالفة لأمر إيقاف الخدمة خلال 10 سنوات (لا مواد خطرة ولا ركاب) إلى إلغاء أهلية لمدة لا تقل عن:","options":["سنتان","180 يوماً","سنة واحدة","3 سنوات"],"explanation":"تؤدي ثاني مخالفة لأمر إيقاف الخدمة خلال فترة 10 سنوات إلى إلغاء أهلية السائق لمدة سنتين على الأقل. المصدر: دليل ND CDL (إلغاء الأهلية)؛ NDCC 39-06.2-10.9؛ 49 CFR 383.51."},"54":{"q":"يرتكب حامل رخصة CDL في نورث داكوتا ثالث مخالفة لأمر إيقاف الخدمة خلال 10 سنوات. ما هو الحد الأدنى لإلغاء الأهلية؟","options":["3 سنوات","سنتان","سنة واحدة","5 سنوات"],"explanation":"تؤدي ثالث مخالفة لأمر إيقاف الخدمة أو ما يليها خلال فترة 10 سنوات إلى إلغاء الأهلية لمدة 3 سنوات على الأقل. المصدر: دليل ND CDL (إلغاء الأهلية)؛ NDCC 39-06.2-10.9؛ 49 CFR 383.51."},"55":{"q":"ما هو الحد الأدنى لإلغاء أهلية رخصة CDL لأول مخالفة لأمر إيقاف الخدمة أثناء نقل مواد خطرة تحمل لوحات تحذير أو أثناء قيادة مركبة مصممة لنقل 16 راكباً أو أكثر؟","options":["180 يوماً","90 يوماً","سنة واحدة","60 يوماً"],"explanation":"تحمل أول مخالفة لأمر إيقاف الخدمة أثناء نقل مواد خطرة تحمل لوحات تحذير أو تشغيل مركبة مصممة لـ 16 راكباً أو أكثر حداً أدنى لإلغاء الأهلية قدره 180 يوماً (نفس الحد الأدنى لأول مخالفة كما في مركبات CMV الأخرى، لكن المخالفتين الثانية والثالثة أطول). المصدر: دليل ND CDL (إلغاء الأهلية)؛ 49 CFR 383.51."},"56":{"q":"ما هو الحد الأدنى لإلغاء أهلية رخصة CDL في نورث داكوتا لأول مخالفة عند معبر تقاطع السكة الحديدية مع الطريق السريع؟","options":["60 يوماً","30 يوماً","120 يوماً","سنة واحدة"],"explanation":"تؤدي أول إدانة بمخالفة عند معبر تقاطع السكة الحديدية مع الطريق السريع إلى إلغاء الأهلية لمدة 60 يوماً على الأقل. المصدر: دليل ND CDL (إلغاء الأهلية)؛ NDCC 39-06.2-10.6؛ 49 CFR 383.51."},"57":{"q":"يرتكب حامل رخصة CDL في نورث داكوتا ثاني مخالفة عند معبر تقاطع السكة الحديدية مع الطريق السريع خلال 3 سنوات. ما هو الحد الأدنى لإلغاء الأهلية؟","options":["120 يوماً","60 يوماً","180 يوماً","سنة واحدة"],"explanation":"تؤدي ثاني مخالفة عند معبر تقاطع السكة الحديدية خلال فترة 3 سنوات إلى إلغاء الأهلية لمدة 120 يوماً على الأقل. المصدر: دليل ND CDL (إلغاء الأهلية)؛ NDCC 39-06.2-10.6؛ 49 CFR 383.51."},"58":{"q":"ما هو الحد الأدنى لإلغاء الأهلية لثالث مخالفة عند معبر تقاطع السكة الحديدية مع الطريق السريع خلال 3 سنوات في نورث داكوتا؟","options":["سنة واحدة","120 يوماً","180 يوماً","60 يوماً"],"explanation":"تؤدي ثالث مخالفة عند معبر تقاطع السكة الحديدية أو ما يليها خلال فترة 3 سنوات إلى إلغاء الأهلية لمدة سنة واحدة على الأقل (180 يوماً على الأقل حتى سنة واحدة بموجب القاعدة، مع تطبيق الحد الأقصى). المصدر: دليل ND CDL (إلغاء الأهلية)؛ NDCC 39-06.2-10.6؛ 49 CFR 383.51."},"59":{"q":"يُكتشَف أن سائق مركبة CMV في نورث داكوتا لديه كمية كحول قابلة للقياس أو الكشف دون 0.04 BAC. ما هي العاقبة الفورية؟","options":["يُوضَع خارج الخدمة لمدة 24 ساعة","تُلغى أهليته بشكل دائم","يُتهَم بمخالفة كبرى","يُمنَح إلغاء أهلية لمدة 60 يوماً"],"explanation":"يجب وضع السائق الذي لديه أي تركيز كحول قابل للقياس دون 0.04 خارج الخدمة لمدة 24 ساعة؛ أما تركيز الكحول في الدم BAC قدره 0.04 أو أكثر فهو مخالفة كبرى تلغي الأهلية. المصدر: دليل ND CDL (الكحول/إيقاف الخدمة)؛ 49 CFR 392.5."},"60":{"q":"على طريق سريع بين الولايات في داكوتا الشمالية خارج المدينة، تقترب من شاحنة قطر متوقفة على الكتف الأيمن مع تشغيل أضوائها الكهرمانية الوامضة. بموجب قانون \"التنحّي جانبًا\" (Move Over) في داكوتا الشمالية، ماذا يجب على سائق المركبة التجارية المقترِبة أن يفعل؟","options":["الاستمرار بالسرعة المحددة لأن مركبات الشرطة فقط هي المشمولة","التوقف توقفًا تامًّا والانتظار حتى تغادر المركبة","الانتقال إلى الكتف الأيسر والتوقف","الانتقال إلى مسار غير ملاصق للمركبة المتوقفة إذا أمكن فعل ذلك بأمان، وإلا فالتباطؤ والمرور بحذر"],"explanation":"يُلزم قانون داكوتا الشمالية NDCC 39-10-26 السائقين على الطريق السريع بين الولايات أو على طريق متعدد المسارات خارج المدينة بالانتقال إلى مسار غير ملاصق لمركبة طوارئ أو مركبة صيانة طرق متوقفة تعرض أضواء كهرمانية/زرقاء/بيضاء/حمراء إذا أمكن ذلك بأمان؛ وإن تعذّر، فعلى السائق التباطؤ والمتابعة بحذر بسرعة آمنة. وقد وسّع تعديل عام 2023 هذا الحكم ليشمل أي مركبة متوقفة تعرض أضواء الخطر الوامضة. المصدر: NDCC 39-10-26؛ قانون التنحّي جانبًا لدوريات طرق داكوتا الشمالية."},"61":{"q":"في عام 2023 وسّعت داكوتا الشمالية قانون \"التنحّي جانبًا\". إلى جانب مركبات الطوارئ المرخّصة ومركبات صيانة الطرق، فإن واجب التنحّي جانبًا أو التباطؤ ينطبق الآن أيضًا عند الاقتراب من أي مركبة متوقفة من النوع التالي؟","options":["أي مركبة تعرض إشارات تحذير الخطر الوامضة الخاصة بها","مركبات توصيل البريد فقط","المركبات التي تعرض ضوءًا أزرق فقط","أي مركبة متوقفة داخل حدود المدينة"],"explanation":"أضاف توسيع داكوتا الشمالية لقانون التنحّي جانبًا في عام 2023 (NDCC 39-10-26) أي مركبة آلية متوقفة تعرض إشارات تحذير الخطر الوامضة على الطريق السريع بين الولايات أو على طريق متعدد المسارات خارج المدينة. المصدر: NDCC 39-10-26؛ مواد قانون التنحّي جانبًا لدوريات طرق داكوتا الشمالية / NDDOT."},"62":{"q":"اعتبارًا من 1 أغسطس 2025، ما هو الحد الأقصى القانوني للسرعة على الطرق السريعة بين الولايات المعبّدة المقسّمة متعددة المسارات ذات الوصول المتحكَّم به في المناطق الريفية بداكوتا الشمالية (حيثما كان محددًا)، وهل يختلف بالنسبة للشاحنات؟","options":["75 mph للسيارات لكن 65 mph للشاحنات","80 mph، وينطبق على جميع المركبات بما في ذلك الشاحنات","70 mph لجميع المركبات","80 mph للسيارات لكن 70 mph للشاحنات"],"explanation":"بموجب NDCC 39-09-02 (بصيغته المعدّلة بالقانون HB 1298، الساري اعتبارًا من 1 أغسطس 2025)، يبلغ الحد الأقصى 80 mph على الطرق السريعة بين الولايات المقسّمة ذات الوصول المتحكَّم به في المناطق الريفية. ولا تضع داكوتا الشمالية حدًّا أدنى منفصلًا لسرعة الشاحنات بموجب القانون، لذا ينطبق الحد على جميع المركبات. المصدر: NDCC 39-09-02؛ إرشادات حد السرعة من NDDOT / دوريات طرق داكوتا الشمالية."},"63":{"q":"بموجب قانون داكوتا الشمالية، ما هو الحد الأقصى للسرعة على طريق معبّد ومقسّم متعدد المسارات لا يكون طريقًا سريعًا بين الولايات ذا وصول متحكَّم به؟","options":["55 mph","65 mph","70 mph","80 mph"],"explanation":"يحدد NDCC 39-09-02 سرعة 70 mph كالحد الأقصى القانوني المفترض على الطرق المعبّدة والمقسّمة متعددة المسارات (بخلاف الطرق السريعة بين الولايات، التي تبلغ 80 mph). المصدر: NDCC 39-09-02."},"64":{"q":"في داكوتا الشمالية، على الطرق المرصوفة بالحصى أو الترابية أو ذات السطح غير المتماسك (والطرق المعبّدة ذات المسارين التابعة للمقاطعات والبلدات) دون حد محدد، ما هو الحد الأقصى القانوني المفترض للسرعة؟","options":["45 mph","50 mph","55 mph","65 mph"],"explanation":"يحدد NDCC 39-09-02 سرعة 55 mph كالحد الأقصى القانوني المفترض على الطرق المرصوفة بالحصى أو الترابية أو ذات السطح غير المتماسك وعلى الطرق المعبّدة ذات المسارين التابعة للمقاطعات والبلدات حيث لا يكون هناك حد محدد. المصدر: NDCC 39-09-02."},"65":{"q":"سائق يشغّل مركبة تجارية تحمل لافتات مواد خطرة (HazMat) في داكوتا الشمالية يقترب من تقاطع سكة حديد مستوٍ يُلزَم بالتوقف عنده. أين يجب أن تتوقف المركبة؟","options":["ضمن 75 قدمًا لكن ليس أقل من 25 قدمًا من أقرب قضيب","ضمن 100 قدم لكن ليس أقل من 50 قدمًا من أقرب قضيب","ضمن 50 قدمًا لكن ليس أقل من 15 قدمًا من أقرب قضيب","في أي مكان ضمن 10 أقدام من أقرب قضيب"],"explanation":"يُلزم NDCC 39-10-43 سائق مركبة HazMat التي تحمل لافتات (وبعض مركبات الصهاريج/الكلور) بالتوقف ضمن 50 قدمًا لكن ليس أقل من 15 قدمًا من أقرب قضيب، ثم النظر والإصغاء قبل المتابعة. المصدر: NDCC 39-10-43؛ دليل CDL لداكوتا الشمالية."},"66":{"q":"في داكوتا الشمالية، أي مركبة يُلزمها القانون بالتوقف عند جميع تقاطعات سكك الحديد المستوية (وليس الخطرة منها فقط)؟","options":["أي مركبة تقطر مقطورة","حافلة تقلّ ركابًا أو حافلة مدرسية","أي شاحنة بيك أب تُستخدم في الزراعة","أي مركبة يزيد وزنها الإجمالي على 26,000 رطل"],"explanation":"يُلزم NDCC 39-10-43 سائق حافلة تقلّ ركابًا، وحافلة مدرسية، ومركبات HazMat التي تحمل لافتات/بعض مركبات الصهاريج بالتوقف عند جميع تقاطعات سكك الحديد المستوية ضمن 50 قدمًا لكن ليس أقل من 15 قدمًا من أقرب قضيب. المصدر: NDCC 39-10-43."},"67":{"q":"بعد التوقف عند تقاطع سكة حديد كما هو مطلوب في داكوتا الشمالية، ما القيد الإضافي الذي يضعه القانون على سائق الحافلة أو مركبة HazMat أثناء عبور القضبان؟","options":["يجب على السائق إطلاق البوق باستمرار أثناء العبور","يجب على السائق ألا يبدّل التروس يدويًّا أثناء عبور القضيب","يجب على السائق تشغيل الأضواء الوامضة الرباعية أثناء العبور","يجب على السائق العبور في أعلى ترس متاح"],"explanation":"يوجّه NDCC 39-10-43 السائق بالعبور فقط في ترس يتجنّب الحاجة إلى تبديل التروس أثناء وجوده على التقاطع، ولا يجوز للسائق تبديل التروس يدويًّا أثناء عبور القضيب. المصدر: NDCC 39-10-43؛ دليل CDL لداكوتا الشمالية."},"68":{"q":"بموجب قاعدة التوقف الإلزامي في داكوتا الشمالية للحافلات ومركبات HazMat عند تقاطعات سكك الحديد، متى لا يكون التوقف مطلوبًا؟","options":["عندما تكون المركبة فارغة","عندما تكون حركة المرور موجّهة من قِبل ضابط شرطة، أو عند تقاطع موسوم بعبارة 'Exempt' (مُعفى) أو 'Tracks out of service' (قضبان خارج الخدمة)","عندما يكون لدى السائق أكثر من سنة خبرة","عندما يكون التقاطع في منطقة تجارية"],"explanation":"يُسقط NDCC 39-10-43 التوقف عندما تكون حركة المرور موجّهة من قِبل ضابط شرطة، وعند التقاطعات التي حدّدها المدير ووسمها بوضوح بعبارة 'Exempt' (مُعفى) أو 'Tracks out of service' (قضبان خارج الخدمة). المصدر: NDCC 39-10-43."},"69":{"q":"حافلة مدرسية في داكوتا الشمالية متوقفة مع تشغيل أضوائها الحمراء الوامضة وذراع التوقف لتحميل الأطفال. سائق تجاري يقترب من الاتجاه المعاكس على طريق ذي مسارين. ماذا يجب على السائق أن يفعل؟","options":["التباطؤ إلى 20 mph والمرور بحذر","التجاوز من اليسار فقط بسرعة مخفّضة","المتابعة، لأن حركة المرور المقابلة لا يُطلب منها التوقف أبدًا","التوقف قبل بلوغ الحافلة وعدم المتابعة حتى لا تعود الأضواء وذراع التوقف مشغّلة"],"explanation":"يُلزم NDCC 39-10-46 السائق الذي يقابل حافلة مدرسية أو يتجاوزها من أي اتجاه بالتوقف قبل بلوغها عندما تكون الأضواء الحمراء الوامضة أو ذراع التوقف مشغّلة، وعدم المتابعة حتى تتحرك الحافلة، أو يُشار إلى السائق بالمتابعة، أو لا تعود الأضواء والذراع مشغّلة. المصدر: NDCC 39-10-46."},"70":{"q":"يحتوي قانون توقف الحافلات المدرسية في داكوتا الشمالية على استثناء خاص بالطرق المقسّمة. بموجب NDCC 39-10-46، لا يحتاج السائق إلى التوقف لحافلة مدرسية متوقفة إلا عندما:","options":["يكون هناك مساران أو أكثر في اتجاه السائق","تكون الحافلة على طريق مختلف من طريق ذي طرق منفصلة، أو يكون السائق على طريق ذي وصول متحكَّم به وتكون الحافلة في منطقة تحميل لا يجوز للمشاة العبور فيها","يكون هناك مسار وسطي للانعطاف يسارًا في الاتجاهين بين السائق والحافلة","يكون للطريق خط وسطي مدهون"],"explanation":"بموجب NDCC 39-10-46(5)، ينطبق الاستثناء فقط عندما تكون الحافلة على طريق مختلف من طريق ذي طرق منفصلة (مقسّمة ماديًّا)، أو على طريق ذي وصول متحكَّم به حيث تكون الحافلة في منطقة تحميل ولا يجوز للمشاة العبور. ووجود مسار انعطاف وسطي أو خط مدهون فقط لا يؤهّل للاستثناء. المصدر: NDCC 39-10-46."},"71":{"q":"على طريق غير مقسّم بأربعة مسارات في داكوتا الشمالية (مساران في كل اتجاه، مفصولان بخط وسطي مدهون فقط)، تتوقف حافلة مدرسية متجهة في الاتجاه المعاكس مع تشغيل أضوائها الحمراء الوامضة. هل يجب على حركة المرور القادمة التوقف؟","options":["لا، لأن هناك مسارات متعددة","لا، حركة المرور القادمة لا تتوقف أبدًا على طريق ذي أربعة مسارات","يجب أن يتوقف المسار الأقرب إلى الحافلة فقط","نعم، لأن الطريق غير مقسّم ماديًّا إلى طرق منفصلة"],"explanation":"ينطبق استثناء NDCC 39-10-46 فقط على الطرق ذات الطرق المنفصلة (المقسّمة ماديًّا). أما على طريق غير مقسّم متعدد المسارات بخط وسطي مدهون فقط، فيجب على حركة المرور القادمة التوقف للحافلة المدرسية التي تعرض أضواءها الحمراء الوامضة وذراع التوقف. المصدر: NDCC 39-10-46."},"72":{"q":"بموجب قانون داكوتا الشمالية، يجوز لسائق الحافلة المدرسية تشغيل الأضواء الكهرمانية التحذيرية (التنبيه) على أي مسافة قبل النقطة التي سيُستقبل عندها الأطفال أو يُنزَّلون؟","options":["ليس أقل من 100 قدم ولا أكثر من 300 قدم","ليس أقل من 200 قدم ولا أكثر من 400 قدم","ليس أقل من 300 قدم ولا أكثر من 500 قدم","250 قدمًا بالضبط"],"explanation":"يسمح NDCC 39-10-46(3) بتشغيل الأضواء الكهرمانية التحذيرية على مسافة ليست أقل من 300 قدم ولا أكثر من 500 قدم من النقطة التي يُستقبل عندها الأطفال أو يُنزَّلون. المصدر: NDCC 39-10-46."},"73":{"q":"يُلزم قانون داكوتا الشمالية كل حافلة مدرسية بحمل لافتة معينة على مؤخرتها تتعلق بتقاطعات سكك الحديد. ماذا تقول؟","options":["\"DO NOT PASS ON TRACKS\"","\"THIS SCHOOLBUS STOPS AT ALL RAILROAD CROSSINGS\"","\"CAUTION: RAILROAD AHEAD\"","\"SCHOOLBUS YIELDS AT CROSSINGS\""],"explanation":"يُلزم NDCC 39-10-46(6) كل حافلة مدرسية بحمل لافتة واضحة للعيان على مؤخرتها نصها \"THIS SCHOOLBUS STOPS AT ALL RAILROAD CROSSINGS.\" المصدر: NDCC 39-10-46."},"74":{"q":"بموجب قواعد الطريق في داكوتا الشمالية، فإن المركبة التجارية التي تسير بأقل من السرعة العادية لحركة المرور على طريق متعدد المسارات يجب أن:","options":["تستخدم المسار الأيسر للبقاء بعيدًا عن حركة المرور المندمجة","تبقى في أي مسار يفضّله السائق","تُقاد في المسار الأيمن أو أقرب ما يمكن عمليًّا إلى الحافة اليمنى، إلا عند التجاوز أو الاستعداد للانعطاف يسارًا","تستخدم المسار الأوسط على طريق ذي ثلاثة مسارات"],"explanation":"يُلزم NDCC 39-10-08(2) أي مركبة تسير أبطأ من السرعة العادية لحركة المرور بالبقاء في المسار الأيمن (أو أقرب ما يمكن عمليًّا إلى الحافة اليمنى)، إلا عند التجاوز أو الاستعداد للانعطاف يسارًا. المصدر: NDCC 39-10-08."},"75":{"q":"تتعطل شاحنة سائق CDL في داكوتا الشمالية على طريق ذي مسارين مستوٍ ومستقيم وغير مقسّم في وضح النهار. باتباع قواعد أجهزة التحذير التي تطبّقها داكوتا الشمالية، أين ينبغي وضع مثلثات التحذير الثلاثة؟","options":["الثلاثة جميعًا ضمن 10 أقدام من مؤخرة الشاحنة","نحو 50 قدمًا و150 قدمًا و250 قدمًا خلف المركبة","واحد على السقف واثنان على الكتف","نحو 10 أقدام خلف المركبة، و100 قدم خلفها، و100 قدم أمامها"],"explanation":"تتّبع داكوتا الشمالية معيار الوضع الفيدرالي (49 CFR 392.22): على طريق ذي مسارين، توضع المثلثات على نحو 10 أقدام خلف المركبة من جهة حركة المرور، ونحو 100 قدم خلفها، ونحو 100 قدم أمامها. المصدر: دليل CDL لداكوتا الشمالية؛ 49 CFR 392.22."},"76":{"q":"عندما يكون سائق CDL في داكوتا الشمالية متوقفًا على طريق باتجاه واحد أو طريق مقسّم، كيف ينبغي وضع مثلثات التحذير الثلاثة باتجاه حركة المرور المقترِبة؟","options":["على نحو 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور المقترِبة","على نحو 25 قدمًا و75 قدمًا و125 قدمًا باتجاه حركة المرور المقترِبة","الثلاثة جميعًا على 100 قدم باتجاه حركة المرور المقترِبة","على نحو 50 قدمًا و100 قدم و150 قدمًا باتجاه حركة المرور المقترِبة"],"explanation":"على طريق باتجاه واحد أو طريق مقسّم، يقتضي المعيار الفيدرالي الذي تطبّقه داكوتا الشمالية (49 CFR 392.22) وضع المثلثات على نحو 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور المقترِبة. المصدر: دليل CDL لداكوتا الشمالية؛ 49 CFR 392.22."},"77":{"q":"سائق CDL في داكوتا الشمالية ينقل حمولة تحمل لافتات من المتفجرات أو السائل القابل للاشتعال يجب أن يتوقف ويضع أجهزة التحذير. أي جهاز تحذير محظور على مثل هذه المركبة؟","options":["مثلثات التحذير العاكسة","ثلاثة عاكسات طوارئ حمراء محمولة","الشُّعَل أو الفيوزيات (أي إشارة تنتج لهبًا)","فوانيس كهربائية حمراء"],"explanation":"لا يجوز استخدام الشُّعَل أو الفيوزيات أو أي إشارة تنتج لهبًا على المركبات التي تنقل المتفجرات أو الغاز/السائل القابل للاشتعال أو التي تستخدم الغاز المضغوط كوقود؛ بل يجب استخدام المثلثات العاكسة أو العاكسات الحمراء أو الفوانيس الكهربائية الحمراء بدلًا منها. المصدر: دليل CDL لداكوتا الشمالية؛ 49 CFR 392.22 / 393.95."},"78":{"q":"خارج فترة ذوبان الجليد الربيعي، فإن موقف داكوتا الشمالية تجاه تصاريح الوزن الزائد للحمولات القابلة للتقسيم خلال قيود الحمل الربيعية المعلنة هو أن:","options":["لن تُصدَر تصاريح الوزن الزائد لأي حمولة قابلة للتقسيم خلال قيود الطرق الربيعية","يجوز للحمولات القابلة للتقسيم دائمًا تجاوز الحدود بتصريح قياسي على مدار السنة","تنطبق القيود الربيعية على نظام الطرق السريعة بين الولايات فقط","الحمولات القابلة للتقسيم معفاة من جميع حدود وزن المحاور في الربيع"],"explanation":"لا تصدر NDDOT ودوريات طرق داكوتا الشمالية تصاريح وزن زائد للحمولات القابلة للتقسيم خلال قيود الطرق الربيعية (ذوبان الجليد) المعلنة، التي تمتد عادةً من منتصف فبراير تقريبًا إلى مايو حسب الظروف. المصدر: قيود الحمل في داكوتا الشمالية من NDDOT؛ معلومات تصاريح الحجم الزائد/الوزن الزائد من دوريات طرق داكوتا الشمالية."},"79":{"q":"يضع قانون داكوتا الشمالية حدًّا أقصى منخفضًا خاصًّا للسرعة لنوع معدات محدد واحد. المركبة المجهّزة بإطارات مطاطية صلبة لا يجوز قيادتها بأسرع من:","options":["5 mph","10 mph","20 mph","25 mph"],"explanation":"يحظر NDCC 39-09-04.1 قيادة أي مركبة مجهّزة بإطارات مطاطية صلبة بأكثر من 10 mph. المصدر: NDCC 39-09-04.1."},"80":{"q":"أي جهة تُصدِر رخص القيادة التجارية (CDL) في داكوتا الشمالية؟","options":["شعبة رخص القيادة بوزارة النقل في داكوتا الشمالية (NDDOT)","الإدارة الفيدرالية لسلامة الناقلين بالشاحنات (FMCSA)","دوريات طرق داكوتا الشمالية","مكتب عمدة المقاطعة التي يقيم فيها السائق"],"explanation":"في داكوتا الشمالية، تُصدَر رخص CDL من قِبل وزارة النقل في داكوتا الشمالية (NDDOT) عبر شعبة رخص القيادة التابعة لها؛ وتضع FMCSA المعايير الفيدرالية لكنها لا تصدر رخص الولايات. المصدر: صفحات رخصة القيادة التجارية لدى NDDOT."},"81":{"q":"بموجب التصديق الذاتي الطبي في داكوتا الشمالية، من كم فئة تصديق ذاتي يجب على مقدّم طلب CDL أن يختار؟","options":["أربع","اثنتان","ثلاث","ست"],"explanation":"تستخدم داكوتا الشمالية فئات التصديق الذاتي الفيدرالية الأربع: غير المُعفى بين الولايات، والمُعفى بين الولايات، وغير المُعفى داخل الولاية، والمُعفى داخل الولاية. المصدر: متطلبات التصديق الطبي لـ CDL من NDDOT."},"82":{"q":"سائق في داكوتا الشمالية يصدّق ذاتيًّا أنه 'غير مُعفى بين الولايات'. ما الذي يتطلبه ذلك فيما يخص التأهيل الطبي؟","options":["يجب على السائق الحصول على شهادة فاحص طبي معتمد من DOT والحفاظ على سريانها","السائق معفى من جميع متطلبات التصديق الطبي","يحتاج السائق فقط إلى إعفاء بصري","يجب على السائق اجتياز اختبار لياقة بدنية تابع للولاية بدلًا من فحص DOT"],"explanation":"يخضع السائقون غير المُعفين بين الولايات لـ 49 CFR Part 391 ويجب عليهم الحصول على شهادة فاحص طبي معتمدة من DOT والحفاظ على سريانها. المصدر: متطلبات التصديق الطبي لـ CDL من NDDOT؛ 49 CFR 391.45."},"83":{"q":"أي فئة من فئات التصديق الذاتي في داكوتا الشمالية لا تتطلب شهادة فاحص طبي معتمدة من DOT؟","options":["المُعفى بين الولايات","غير المُعفى بين الولايات","غير المُعفى داخل الولاية","ناقل المواد الخطرة بين الولايات"],"explanation":"السائقون الذين يصدّقون أنهم 'مُعفون' (بين الولايات أو داخل الولاية) يعملون حصريًّا في عمليات مُعفاة وليسوا مطالَبين بحمل شهادة فاحص طبي؛ أما السائقون غير المُعفين فيجب عليهم ذلك. المصدر: متطلبات التصديق الطبي لـ CDL من NDDOT."},"84":{"q":"اعتبارًا من 21 أبريل 2025، كيف تُقدَّم شهادة الفاحص الطبي المعتمدة من DOT لحامل CDL في داكوتا الشمالية إلى الولاية؟","options":["يرفعها الفاحص الطبي المعتمد إلكترونيًّا؛ ولم تعد NDDOT تقبل الشهادات الورقية","يرسل السائق نسخة ورقية بالبريد إلى NDDOT","يرسل السائق نسخة بالفاكس إلى شعبة رخص القيادة","يقدّمها صاحب العمل لدى كاتب المقاطعة"],"explanation":"اعتبارًا من 21 أبريل 2025، لم تعد داكوتا الشمالية تقبل الشهادات الطبية مباشرةً؛ ويجب على الفاحصين الطبيين المعتمدين وطنيًّا رفع الشهادة إلكترونيًّا إلى السجل/الولاية. المصدر: إشعار NDDOT بشأن الشهادة الطبية لـ CDL."},"85":{"q":"قبل إجراء اختبار مهارات CDL في داكوتا الشمالية لأول رخصة من الفئة A أو B، ما التدريب الذي يجب على مقدّم الطلب الجديد إكماله؟","options":["تدريب السائق المبتدئ (ELDT) من مزوّد مدرَج في سجل مزوّدي التدريب","دورة قيادة دفاعية في قاعة دراسية بالمقاطعة","تدرّب مهني لمدة أربع سنوات لدى ناقل مرخّص","توجيه يقتصر على صاحب العمل دون اشتراط السجل"],"explanation":"منذ 7 فبراير 2022، تقتضي قواعد ELDT الفيدرالية التي اعتمدتها داكوتا الشمالية أن يكمل مقدّمو طلبات CDL الجدد التدريب من مزوّد مدرَج في سجل مزوّدي التدريب لدى FMCSA قبل اختبار المهارات. المصدر: 'كيفية التقديم' من NDDOT؛ ELDT من FMCSA."},"86":{"q":"يتألف اختبار مهارات CDL في داكوتا الشمالية من أي ثلاثة أجزاء، بالترتيب؟","options":["الفحص قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","اختبار المعرفة التحريري، وفحص العين، والقيادة على الطريق","الركن الموازي، واختبار المواد الخطرة التحريري، واختبار الفرامل الهوائية","الفحص قبل الرحلة، واختبار اعتماد المواد الخطرة، والقيادة الليلية"],"explanation":"يتّبع اختبار مهارات CDL في داكوتا الشمالية الصيغة الفيدرالية ذات الأجزاء الثلاثة: الفحص قبل الرحلة للمركبة، ومهارات التحكم الأساسي بالمركبة، والقيادة على الطريق. المصدر: دليل CDL لداكوتا الشمالية؛ صفحات CDL لدى NDDOT."},"87":{"q":"في داكوتا الشمالية، ما الذي يجب على مقدّم الطلب الحصول عليه قبل السماح له بإجراء اختبار مهارات CDL (اختبار الطريق)؟","options":["تصريح متعلّم القيادة التجارية (CLP) بعد اجتياز اختبار(ات) المعرفة المطلوبة","رخصة CDL كاملة تُصدَر بشكل مؤقت","اعتماد المواد الخطرة","رقم صلاحية تشغيل فيدرالي"],"explanation":"يجب على مقدّمي الطلبات أولًا اجتياز اختبار(ات) المعرفة والحصول على تصريح متعلّم القيادة التجارية (CLP) قبل تحديد موعد اختبار المهارات. المصدر: 'كيفية التقديم للحصول على رخصة قيادة تجارية' من NDDOT."},"88":{"q":"كم يجب أن يُحتفظ بتصريح CLP في داكوتا الشمالية قبل أن يتمكن حامله من إجراء اختبار مهارات CDL؟","options":["14 يومًا على الأقل","30 يومًا على الأقل","7 أيام على الأقل","60 يومًا على الأقل"],"explanation":"تطبّق داكوتا الشمالية فترة الاحتفاظ الفيدرالية البالغة 14 يومًا: يجب الاحتفاظ بتصريح CLP لمدة 14 يومًا على الأقل قبل أن يتمكن مقدّم الطلب من إجراء اختبار مهارات CDL. المصدر: صفحات CDL لدى NDDOT؛ 49 CFR 383.25."},"89":{"q":"في داكوتا الشمالية، تصريح متعلّم القيادة التجارية صالح لمدة تصل إلى كم يومًا متتاليًا من تاريخ إصداره؟","options":["180 يومًا","90 يومًا","365 يومًا","60 يومًا"],"explanation":"تصريح CLP في داكوتا الشمالية صالح لمدة تصل إلى 180 يومًا متتاليًا من تاريخ الإصدار؛ وإذا لم يُجتَز اختبار الطريق في الوقت المناسب، فيجب تجديد التصريح. المصدر: صفحات CDL لدى NDDOT."},"90":{"q":"عند التدرّب بتصريح CLP في داكوتا الشمالية، من يجب أن يكون في المركبة مع حامل التصريح؟","options":["حامل CDL من الفئة/الاعتمادات نفسها أو أعلى، يجلس بجوار السائق","أي سائق مرخّص يبلغ من العمر 21 عامًا أو أكثر","ضابط من دوريات طرق داكوتا الشمالية","لا يلزم أحد إذا كان التدرّب خارج الطرق العامة"],"explanation":"لا يجوز لحامل CLP قيادة مركبة تجارية إلا بصحبة حامل CDL مؤهّل (يحمل الفئة والاعتمادات المناسبة) يجلس بجواره. المصدر: صفحات CDL لدى NDDOT؛ 49 CFR 383.25."},"91":{"q":"ما هي دورة التجديد القياسية لرخصة CDL في داكوتا الشمالية؟","options":["أربع سنوات","خمس سنوات","سنتان","ثماني سنوات"],"explanation":"تُصدَر رخص CDL في داكوتا الشمالية لمدة أربع سنوات وتنتهي صلاحيتها عند منتصف ليل عيد ميلاد السائق في نهاية تلك الدورة. المصدر: 'كيفية تجديد رخصة القيادة التجارية' من NDDOT."},"92":{"q":"تنتهي صلاحية رخصة CDL في داكوتا الشمالية عند منتصف ليل أي تاريخ من سنة التجديد؟","options":["عيد ميلاد السائق","31 ديسمبر","الذكرى السنوية لتاريخ الإصدار الأصلي","آخر يوم من شهر الإصدار"],"explanation":"تنتهي صلاحية رخص CDL في داكوتا الشمالية عند منتصف ليل عيد ميلاد السائق في سنة التجديد. المصدر: معلومات التجديد من NDDOT."},"93":{"q":"ما المستندات التي يجب على مقدّم طلب CDL في داكوتا الشمالية تقديمها عادةً عند التقديم؟","options":["رخصة قيادة سارية، وإثبات الوجود القانوني، وإثبات عنوان الإقامة","بطاقة الضمان الاجتماعي فقط","جواز سفر وتسجيل مركبة فقط","شهادة ميلاد ورخصة صيد"],"explanation":"تتطلب NDDOT من مقدّمي الطلبات تقديم رخصة قيادة سارية، وإثبات الوجود القانوني/الهوية، وإثبات عنوان الإقامة في داكوتا الشمالية. المصدر: 'كيفية التقديم للحصول على رخصة قيادة تجارية' من NDDOT."},"94":{"q":"ما الحد الأدنى للسن للحصول على رخصة CDL داخل الولاية فقط (ضمن داكوتا الشمالية)؟","options":["18 عامًا","16 عامًا","21 عامًا","19 عامًا"],"explanation":"تسمح داكوتا الشمالية برخصة CDL داخل الولاية في سن 18 عامًا؛ أما التشغيل بين الولايات (والمواد الخطرة) فيتطلب عمومًا سن 21 عامًا. المصدر: 'كيفية التقديم' من NDDOT؛ 49 CFR 383/391."},"95":{"q":"ما الحد الأدنى للسن للحصول على رخصة CDL صالحة للقيادة بين الولايات (أو لاعتماد المواد الخطرة) في داكوتا الشمالية؟","options":["21 عامًا","18 عامًا","19 عامًا","25 عامًا"],"explanation":"يتطلب تشغيل CDL بين الولايات، واعتماد المواد الخطرة، أن يكون عمر السائق 21 عامًا على الأقل. المصدر: متطلبات CDL من NDDOT؛ قواعد CDL الفيدرالية."},"96":{"q":"للحصول على تصريح CLP في داكوتا الشمالية، بالإضافة إلى اجتياز اختبار المعرفة، ما الفحص المطلوب؟","options":["فحص البصر (العين)","اختبار سمع تجريه NDDOT","فحص للكشف عن المخدرات والكحول في مكتب DOT","تقييم نفسي"],"explanation":"تتطلب داكوتا الشمالية فحص البصر/العين لإصدار تصريح CLP، إلى جانب اجتياز اختبار(ات) المعرفة المطلوبة. المصدر: 'كيفية التقديم للحصول على رخصة قيادة تجارية' من NDDOT."},"97":{"q":"إذا رسب مقدّم طلب CDL في داكوتا الشمالية في اختبار المعرفة، ما سياسة NDDOT بشأن إعادة إجرائه؟","options":["يُسمح عمومًا بمحاولة واحدة في اليوم؛ ويعود مقدّم الطلب في يوم آخر لإعادة الاختبار","يجب على مقدّم الطلب الانتظار 30 يومًا قبل أي إعادة","يُمنع مقدّم الطلب نهائيًّا بعد رسوب واحد","يُسمح بإعادات غير محدودة في اليوم نفسه"],"explanation":"تقصر NDDOT عمومًا اختبار المعرفة على محاولة واحدة في اليوم، لذا يجب على مقدّم الطلب الراسب العودة في يوم لاحق لإعادة الاختبار. المصدر: معلومات اختبار/رسوم CDL من NDDOT. (قد تتغير الرسوم الدقيقة.)"},"98":{"q":"يريد سائق إضافة اعتماد حافلة مدرسية (S) إلى رخصة CDL في داكوتا الشمالية لأول مرة. ما خطوة الإجراء المطلوبة قبل اختبار المهارات/الاعتماد؟","options":["إكمال تدريب السائق المبتدئ (ELDT) المطلوب لاعتماد S","اجتياز فحص بصر فقط","الاحتفاظ برخصة CDL الأساسية لمدة خمس سنوات على الأقل","الحصول على تصريح منفصل داخل الولاية فقط"],"explanation":"إضافة اعتماد الركاب (P)، أو الحافلة المدرسية (S)، أو المواد الخطرة (H) لأول مرة يستوجب متطلب ELDT، الذي يجب إكماله قبل الاختبار. المصدر: صفحات CDL لدى NDDOT؛ قاعدة ELDT من FMCSA السارية في 7 فبراير 2022."},"99":{"q":"في اختبار مهارات CDL في داكوتا الشمالية، يختبر جزء التحكم الأساسي بالمركبة بشكل أساسي أيًّا من القدرات التالية؟","options":["مناورات مثل الرجوع في خط مستقيم، والركن/الرسوّ، والانعطاف المتحكَّم به","قراءة لافتات الطريق من الذاكرة","حساب حدود وزن الجسور","الإجابة عن أسئلة شفهية حول المواد الخطرة"],"explanation":"يختبر جزء التحكم الأساسي بالمركبة مناورات التحكم بالسرعة المنخفضة مثل الرجوع في خط مستقيم، والرسوّ في الزقاق، والركن الموازي، والانعطاف الدقيق. المصدر: دليل CDL لداكوتا الشمالية؛ صيغة اختبار المهارات من NDDOT."}}};
